-- Poems batch 285
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('e3564762-9805-4197-b473-2847f63ce39f','淳祐祭海神十六首 迎神用《延安》。 其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔宮一曲〕堪輿之間，最鉅惟瀛。',45,'全唐诗/poet.song.250000.json','["〔宮一曲〕堪輿之間，最鉅惟瀛。", "包乾括坤，吐日滔星。", "祀典載新，禮樂孔明。", "鑒吾嘉頼，來燕來寧。"]'),
('0e984b17-1520-4cbc-b379-6184bfc21b63','淳祐祭海神十六首 迎神用《延安》。 其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔角一曲〕四溟廣矣，八紘是紀。',45,'全唐诗/poet.song.250000.json','["〔角一曲〕四溟廣矣，八紘是紀。", "我宅東南，迴復萬里。", "洪濤飄風，安危所倚。", "祀事特隆，神其戾止。"]'),
('76fff451-b4fd-424a-b708-6f63c5ea6ae2','淳祐祭海神十六首 迎神用《延安》。 其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔徵一曲〕若稽有唐，克致崇極。',45,'全唐诗/poet.song.250000.json','["〔徵一曲〕若稽有唐，克致崇極。", "祝號既升，爰增祭式。", "從享于郊，神斯受職。", "我祀肇新，式祈陰騭。"]'),
('2920340e-fd78-496c-a43e-13626a5c60d8','淳祐祭海神十六首 迎神用《延安》。 其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔羽一曲〕猗與祀禮，四海會同。',45,'全唐诗/poet.song.250000.json','["〔羽一曲〕猗與祀禮，四海會同。", "靈之來沛，鞭霆馭風。", "肸蠁彷彿，在位肅雍。", "佑我烝民，式徼神功。"]'),
('e1349446-4e79-4241-9b3e-b8c1d55e5a45','淳祐祭海神十六首 升降用《欽安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','靈之來至，垂慶陰陰。',40,'全唐诗/poet.song.250000.json','["靈之來至，垂慶陰陰。", "靈之已坐，飭茲五音。", "壇殿聿嚴，陟降孔欽。", "靈宜安留，鑒我德心。"]'),
('ad21728c-29e9-42b9-b9bc-9a1f094591b7','淳祐祭海神十六首 東海位奠玉幣用《德安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','百川所歸，天地之左。',40,'全唐诗/poet.song.250000.json','["百川所歸，天地之左。", "澒洞鴻濛，功高善下。", "行都攸依，百祿是荷。", "制幣嘉玉，以侑以妥。"]'),
('de212b21-2dd9-4bed-b077-ebcfb8973d64','淳祐祭海神十六首 南海位奠玉幣用《瀛安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','祝融之位，貴乎三神。',40,'全唐诗/poet.song.250000.json','["祝融之位，貴乎三神。", "吞納江漢，廣大無垠。", "長爲委輸，祐我黎民。", "敬陳明享，允鑒恭勤。"]'),
('f4a5c6c5-58a7-4b8f-8253-67e966b53765','淳祐祭海神十六首 西海位奠玉幣用《潤安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','蒲昌之澤，派引天潢。',40,'全唐诗/poet.song.250000.json','["蒲昌之澤，派引天潢。", "羲娥出入，浩渺微茫。", "蓋高斯覆，猶隔封疆。", "我思六合，肇正吉昌。"]'),
('f3b1b646-5510-4d67-85db-5592c4d27fb0','淳祐祭海神十六首 北海位奠玉幣用《瀚安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','瀚海重潤，地紀亦歸。',40,'全唐诗/poet.song.250000.json','["瀚海重潤，地紀亦歸。", "吞受百瀆，限制北陲。", "一視同仁，我心則怡。", "嘉薦玉幣，神其格思。"]'),
('739049fd-f68a-45c2-adc3-21c9f5dee0c2','淳祐祭海神十六首 捧俎用《豐安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','昭格靈貺，祀典肇升。',40,'全唐诗/poet.song.250000.json','["昭格靈貺，祀典肇升。", "牲牷告充，雕俎是承。", "薦虔效物，省德惟馨。", "靈其有喜，萬宇肅澄。"]'),
('c62a32b1-f019-49bd-864b-920b394cffdc','淳祐祭海神十六首 東海位酌獻用《熙安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','滄溟之德，東南具依。',40,'全唐诗/poet.song.250000.json','["滄溟之德，東南具依。", "熬波出素，國計攸資。", "石臼却敵，濟我王師。", "神其享錫，益畀燕綏。"]'),
('ce26f7a5-0cce-46b8-ad61-81b51fcac317','淳祐祭海神十六首 南海位酌獻用《貴安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','南溟浮天，旁通百蠻。',40,'全唐诗/poet.song.250000.json','["南溟浮天，旁通百蠻。", "風檣迅疾，琛舶來還。", "民商永頼，坐消寇姦。", "薦茲嘉觴，弭矣驚瀾。"]'),
('fc09487a-7584-4ddb-ba9d-5287b07b9f6f','淳祐祭海神十六首 西海位酌獻用《類安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','積流疏派，被于流沙。',40,'全唐诗/poet.song.250000.json','["積流疏派，被于流沙。", "布潤施澤，功均邇遐。", "我秩祀典，四海一家。", "祗薦令芳，靈其享嘉。"]'),
('a766312f-9921-4532-b520-68fb877eed58','淳祐祭海神十六首 北海位酌獻用《溥安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','儵忽會同，裴回安留。',40,'全唐诗/poet.song.250000.json','["儵忽會同，裴回安留。", "牲肥酒香，晨事聿修。", "惟德之凉，曷奄九州。", "帝命是祗，多福自求。"]'),
('19e285ae-18f2-471a-8bd2-05efb4ece176','淳祐祭海神十六首 亞、終獻用《饗安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','籩豆有楚，貳觴斯旅。',40,'全唐诗/poet.song.250000.json','["籩豆有楚，貳觴斯旅。", "神其醉飽，式燕以序。", "百靈祕怪，蜿蜒飛舞。", "錫我祺祥，有永終古。"]'),
('a9f4271c-2c8a-473b-978b-4c1ed9c4e170','淳祐祭海神十六首 送神用《成安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','告靈饗矣，錫我嘉祚。',40,'全唐诗/poet.song.250000.json','["告靈饗矣，錫我嘉祚。", "乾端坤倪，開豁呈露。", "玄雲聿收，羣龍咸騖。", "滅除凶災，六幕清豫。"]'),
('f80fa1bb-82ba-4ec6-92b4-4b15a8d75724','紹興祀大火十二首 降神用《高安》。 其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔圜鍾爲宮〕五緯相天，各率其職。',46,'全唐诗/poet.song.250000.json','["〔圜鍾爲宮〕五緯相天，各率其職。", "司禮與視，則維熒惑。", "至陽之精，屆我長嬴。", "于以求之，祀事孔明。"]'),
('4b617c62-e6fb-4a3a-8005-975cab87706c','紹興祀大火十二首 降神用《高安》。 其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔黄鍾爲角〕有出有藏，伏見靡常。',46,'全唐诗/poet.song.250000.json','["〔黄鍾爲角〕有出有藏，伏見靡常。", "相我國家，鑒觀四方。", "視罔不正，終然允臧。", "神其來格，明德馨香。"]'),
('3b3d8607-7c6e-4d07-8049-0a1ec048aa14','紹興祀大火十二首 降神用《高安》。 其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔太簇爲徵〕小大率禮，不愆于儀。',46,'全唐诗/poet.song.250000.json','["〔太簇爲徵〕小大率禮，不愆于儀。", "展采錯事，秩祀孔時。", "維今之故，閲我數度。", "修厥典常，神其來顧。"]'),
('ea945430-faa8-4309-8648-6e3a2959c4cb','紹興祀大火十二首 降神用《高安》。 其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔姑洗爲羽〕於赫我宋，以火德王。',46,'全唐诗/poet.song.250000.json','["〔姑洗爲羽〕於赫我宋，以火德王。", "永永丕圖，繄神之相。", "神之來矣，維其時矣。", "禮備樂奏，神其知矣。"]'),
('054d0622-e5e4-44f2-b13a-bec2d4226daf','紹興祀大火十二首 升殿用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','有儼其容，有潔其衷。',40,'全唐诗/poet.song.250000.json','["有儼其容，有潔其衷。", "屹屹崇壇，伊神與通。", "神肯降格，嘉神之休。", "虔恭降登，神乎安留。"]'),
('e33ae14c-f1f3-4ca7-895d-055b84d8a227','紹興祀大火十二首 熒惑位奠玉幣用《嘉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','馨香接神，肸蠁恍惚。',40,'全唐诗/poet.song.250000.json','["馨香接神，肸蠁恍惚。", "求神以誠，薦誠以物。", "有藉斯玉，有篚斯幣。", "是用薦陳，昭茲精意。"]'),
('f331b667-38f4-4840-8805-cec3af545045','紹興祀大火十二首 商丘宣明王位奠幣用《嘉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','熒惑在天，惟火與合。',40,'全唐诗/poet.song.250000.json','["熒惑在天，惟火與合。", "繄神主火，純一不雜。", "作配熒惑，祀功則然。", "不腆之幣，于以告虔。"]'),
('8c72b35f-7ea7-4f16-b423-cf3dc7add67b','紹興祀大火十二首 捧俎用《豐安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','火遵其令，無物不長。',40,'全唐诗/poet.song.250000.json','["火遵其令，無物不長。", "視此牲牢，務得其養。", "豢以祀神，有腯其肥。", "非神之宜，其將曷歸。"]'),
('e581b62d-a3fc-4016-aec2-1ab31e24ac8a','紹興祀大火十二首 熒惑位酌獻用《祐安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','皇念有神，介我戩穀。',40,'全唐诗/poet.song.250000.json','["皇念有神，介我戩穀。", "登時休明，有此美祿。", "酌言獻之，有飶其香。", "神兮燕娭，醉此嘉觴。"]'),
('aacd10ff-b103-42ca-9d52-b2a092448c59','紹興祀大火十二首 宣明王位酌獻用《祐安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','誰其祀神，知神嗜好。',40,'全唐诗/poet.song.250000.json','["誰其祀神，知神嗜好。", "閼伯祀火，爲神所勞。", "睠言配食，既與火俱。", "於樂旨酒，承神嘉虞。"]'),
('4340e6e6-4baa-4194-9cb4-29761e904ccb','紹興祀大火十二首 亞、終獻用《文安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','神既貺施，嗜我飲食。',40,'全唐诗/poet.song.250000.json','["神既貺施，嗜我飲食。", "申以累獻，以承靈億。", "神方常羊，咸畢我觴。", "于再于三，于誠之將。"]'),
('ba173c98-a445-4d15-926f-16cd4a4bfc06','紹興祀大火十二首 送神用《理安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','登降上下，奠璧獻斝。',40,'全唐诗/poet.song.250000.json','["登降上下，奠璧獻斝。", "音送粥粥，禮無違者。", "已虞至旦，神其將歸。", "顧我國家，遺以繁釐。"]'),
('6c6dcc9b-b2a4-411b-ade8-fd4fbd512191','出火祀大辰十二首 降神用《高安》。 其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔圜鍾爲宮〕燁燁我宋，火德所畀。',46,'全唐诗/poet.song.250000.json','["〔圜鍾爲宮〕燁燁我宋，火德所畀。", "用火紀時，允惟象類。", "神以類歆，誠繇類至。", "有感斯通，孚我陽燧。"]'),
('3b787b01-291b-4757-aa9b-feb015cbbaf4','出火祀大辰十二首 降神用《高安》。 其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔黄鍾爲角〕樂音上達，粵惟出虛。',46,'全唐诗/poet.song.250000.json','["〔黄鍾爲角〕樂音上達，粵惟出虛。", "火性炎上，亦生於無。", "我鏞我磬，我笙我竽。", "氣同聲應，昭哉合符。"]'),
('aa1b95c3-13bf-4d52-92f7-6deebca8c057','出火祀大辰十二首 降神用《高安》。 其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔太簇爲徵〕火在六氣，獨處其兩。',46,'全唐诗/poet.song.250000.json','["〔太簇爲徵〕火在六氣，獨處其兩。", "感生維君，繄辰克相。", "何以驗之，占茲垂象。", "騰駕蒼虯，歘其來饗。"]'),
('80d8090a-2234-467b-8bf3-2c2380b7b80c','出火祀大辰十二首 降神用《高安》。 其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔姑洗爲羽〕星入於戌，與火俱詘。',46,'全唐诗/poet.song.250000.json','["〔姑洗爲羽〕星入於戌，與火俱詘。", "火出於辰，與星俱伸。", "一伸一詘，孰操縱之。", "利用出入，民咸用之。"]'),
('41b5fd3b-2b60-413f-ad21-80f470f9afe9','出火祀大辰十二首 升殿用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','屹彼嘉壇，赤伏始屆。',40,'全唐诗/poet.song.250000.json','["屹彼嘉壇，赤伏始屆。", "掞光耀明，洋乎如在。", "俛仰重離，默與精會。", "隨我降升，肅聽環珮。"]'),
('8779ff41-0c9e-47c9-ab8d-d51a7a67bc71','出火祀大辰十二首 大辰位奠玉幣用《嘉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','維莫之春，五陽發舒。',40,'全唐诗/poet.song.250000.json','["維莫之春，五陽發舒。", "日之夕矣，三星在隅。", "莫量匪幣，莫嘉匪玉。", "明薦孔時，神光下矚。"]'),
('7759650c-15af-41f5-95a8-c23eeb15c560','出火祀大辰十二首 商丘宣明王位奠幣用《嘉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','二七儲神，與天地並。',40,'全唐诗/poet.song.250000.json','["二七儲神，與天地並。", "孰儷厥德，聿惟南正。", "功楙陶唐，澤流億姓。", "作配嚴禋，贄列惟稱。"]'),
('b633eb64-8c03-459c-bb14-9c5c57084259','出火祀大辰十二首 捧俎用《豐安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','有嚴在滌，陳彼牲牢。',40,'全唐诗/poet.song.250000.json','["有嚴在滌，陳彼牲牢。", "孔碩其俎，薦此血毛。", "厥初生民，飲茹則然。", "以燔以炙，伊誰云先。"]'),
('0eb4cc3c-22a5-4d6c-a276-5ddd2712f7be','出火祀大辰十二首 大辰位酌獻用《祐安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','孰爲大辰，維北有斗。',40,'全唐诗/poet.song.250000.json','["孰爲大辰，維北有斗。", "曾是彗星，斯名孔有。", "幽榮報功，潔齊敢後。", "容與嘉觴，式歆旨酒。"]'),
('8e914b31-ef7c-4e3a-9362-5587d277595a','出火祀大辰十二首 宣明王位酌獻用《祐安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','周設司爟，雖列夏官。',40,'全唐诗/poet.song.250000.json','["周設司爟，雖列夏官。", "仍襲孔易，闓端實難。", "相彼商丘，永懷初造。", "不腆桂椒，匪以爲報。"]'),
('996e2fe3-ed79-4489-9ecd-375981716322','出火祀大辰十二首 亞、終獻用《文安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','潜之伏矣，柞槱既休。',40,'全唐诗/poet.song.250000.json','["潜之伏矣，柞槱既休。", "有俶其來，榆柳是求。", "靈駕紛羽，尚其安留。", "飲我三爵，言言油油。"]'),
('fd90abbe-93ec-46cc-87ad-ebbde9b24378','出火祀大辰十二首 送神用《理安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','五運惟火，寔宗衆陽。',40,'全唐诗/poet.song.250000.json','["五運惟火，寔宗衆陽。", "宿壯用明，千載愈光。", "神保聿歸，安處火房。", "鬰攸不作，炎圖永昌。"]'),
('3bb1bb52-f66a-4aad-87d9-ef817439b9f1','納火祀大辰十二首 降神用《高安》。 其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔圜鍾爲宮〕赫赫皇圖，炎炎火德。',46,'全唐诗/poet.song.250000.json','["〔圜鍾爲宮〕赫赫皇圖，炎炎火德。", "侈神之賜，奄有方國。", "粢盛既豐，俎豆有飶。", "於萬斯年，報祀無斁。"]'),
('ed910fb2-3bf4-486f-b9ba-32a8ca8b063e','納火祀大辰十二首 降神用《高安》。 其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔黄鍾爲角〕火星之躔，有燁其光。',46,'全唐诗/poet.song.250000.json','["〔黄鍾爲角〕火星之躔，有燁其光。", "表于辰位，伏于戌方。", "時和歲稔，仁顯用藏。", "告爾萬民，出納有常。"]'),
('ec10a09b-fa82-41b6-96ac-2f3224f75b6e','納火祀大辰十二首 降神用《高安》。 其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔太簇爲徵〕季秋之月，律中無射。',46,'全唐诗/poet.song.250000.json','["〔太簇爲徵〕季秋之月，律中無射。", "農事備收，火功告畢。", "克禋克祀，有嚴有翼。", "風馬雲車，尚其來格。"]'),
('4c8f3ae3-18ef-450d-bdd5-e5ef6db1b3c4','納火祀大辰十二首 降神用《高安》。 其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔姑洗爲羽〕明明我后，重祭欽祠。',46,'全唐诗/poet.song.250000.json','["〔姑洗爲羽〕明明我后，重祭欽祠。", "有司肅事，式薦晨儀。", "禮惟其稱，物惟其時。", "神之聽之，福祿來爲。"]'),
('982a29f2-8e02-4475-bb62-b9024528ae57','納火祀大辰十二首 升殿用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','猗與明壇，右平左墄。',40,'全唐诗/poet.song.250000.json','["猗與明壇，右平左墄。", "冕服斯皇，玉珮有節。", "陟降惟寅，匪徐匪疾。", "式崇大祀，禮文咸秩。"]'),
('f70cb9a9-d0c0-42b0-8401-b67ca2d1f6ae','納火祀大辰十二首 大辰位奠玉幣用《嘉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','金行序晚，玉露晨清。',40,'全唐诗/poet.song.250000.json','["金行序晚，玉露晨清。", "齊戒豐潔，肅恭神明。", "嘉幣惟量，嘉玉惟精。", "于以奠之，庶幾來聽。"]'),
('59eeeba6-49b6-4eb6-b749-984e4622c169','納火祀大辰十二首 商丘宣明王位奠幣用《嘉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','恭惟火正，自陶唐氏。',40,'全唐诗/poet.song.250000.json','["恭惟火正，自陶唐氏。", "邑于商丘，配食辰祀。", "有功在民，有德在位。", "敢替典常，惟恭奉幣。"]'),
('af6b1f7d-295c-4c8c-9430-213de19f488f','納火祀大辰十二首 捧俎用《豐安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','萬彙攸成，四方寧謐。',40,'全唐诗/poet.song.250000.json','["萬彙攸成，四方寧謐。", "工祝致告，普存民力。", "迺薦斯牲，爲俎孔碩。", "介以繁祉，式和民則。"]'),
('08f44769-ddbe-4c45-945c-96af26e7ff7d','納火祀大辰十二首 大辰位酌獻用《祐安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','庶功備矣，休德昭明。',40,'全唐诗/poet.song.250000.json','["庶功備矣，休德昭明。", "天地釀和，鬰鬯斯清。", "玉瓚以酌，瑶觴載盈。", "周流常羊，來燕來寧。"]'),
('6e37852f-c5d3-4d61-aaaa-c9ba55239def','納火祀大辰十二首 宣明王位酌獻用《祐安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','廣大建祀，式崇其配。',40,'全唐诗/poet.song.250000.json','["廣大建祀，式崇其配。", "馨香在茲，清酒既載。", "穆穆有暉，洋洋如在。", "聿懷嘉慶，繄神之賚。"]'),
('b7db4e43-18da-4ae9-855a-f23fa80ca64c','納火祀大辰十二首 亞、終獻用《文安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','幣玉肅陳，笙簧具舉。',40,'全唐诗/poet.song.250000.json','["幣玉肅陳，笙簧具舉。", "桂醑浮觴，瓊羞溢俎。", "禮有三獻，式和且序。", "神具醉止，慶流寰宇。"]'),
('1d416f65-c883-4e84-a2ae-44e97d4ce49c','納火祀大辰十二首 送神用《理安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','神靈降鑒，天地回旋。',40,'全唐诗/poet.song.250000.json','["神靈降鑒，天地回旋。", "惟馨薦矣，既醉歆焉。", "諸宰斯徹，式禮莫愆。", "隤祉降祥，天子萬年。"]'),
('4db99112-6db2-4540-99e2-3050852e78d0','景德祭社稷三首 降神用《靜安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','百穀蕃滋，麗乎下土。',40,'全唐诗/poet.song.250000.json','["百穀蕃滋，麗乎下土。", "聿崇明祀，垂之千古。", "育物惟茂，粒民斯普。", "報本攸宜，國章咸臯。"]'),
('19ebe761-bf6c-4bab-83d1-f69bba497b44','景德祭社稷三首 奠玉幣、酌獻用《嘉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於穆大祀，功利相宣。',40,'全唐诗/poet.song.250000.json','["於穆大祀，功利相宣。", "靈壇美報，歷代昭然。", "介以蕃祉，祚以豐年。", "土爰稼穡，允協民天。"]'),
('3173ad92-be72-4033-b6dd-265f8bf40b63','景德祭社稷三首 送神用《靜安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','制幣犧齊，正辭無愧。',20,'全唐诗/poet.song.250000.json','["制幣犧齊，正辭無愧。", "樂以送之，畢其精意。"]'),
('1da1ffeb-6c8f-496a-a4b6-63f695c498b0','景祐祀社稷三首 迎神用《寧安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','五祀之本，百貨何極。',40,'全唐诗/poet.song.250000.json','["五祀之本，百貨何極。", "道著開闢，惠周動植。", "國崇美穀，民資力穡。", "奠獻惟寅，神靈來格。"]'),
('f64d5a6e-5631-4fbb-a8ad-7df54059b965','景祐祀社稷三首 亞、終獻用《文安》，送神用《寧安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','神之來兮，降茲下土。',40,'全唐诗/poet.song.250000.json','["神之來兮，降茲下土。", "神之去兮，杳無處所。", "壇壝肅然，瘞幣徹俎。", "乃粒之功，冠于萬古。"]'),
('7f068798-5663-4a1c-ae38-ca2b55444bb0','景祐祀社稷三首 奉俎用《豐安》。神州地祇、皇地祇與社稷通用。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','禮崇明禋，維馨斯酒。',40,'全唐诗/poet.song.250000.json','["禮崇明禋，維馨斯酒。", "潔粢豐盛，殺時犉牡。", "齊莊嚴祗，升燎于槱。", "其報伊何，如山如阜。"]'),
('8d6956b7-e4db-4427-b777-42fd3a0e843b','大觀祀社稷九首 迎神用《寧安》。 其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔黄鐘二奏〕惟土之尊，民食資焉。',46,'全唐诗/poet.song.250000.json','["〔黄鐘二奏〕惟土之尊，民食資焉。", "陰祀昭格，牲牢腥羶。", "有功于民，告其吉蠲。", "神之來享，雲車翩翩。"]'),
('c410f043-a976-46fd-9f55-de0ba6153a5a','大觀祀社稷九首 迎神用《寧安》。 其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔太簇角二奏〕惟穀之神，函育無窮。',47,'全唐诗/poet.song.250000.json','["〔太簇角二奏〕惟穀之神，函育無窮。", "百嘉蕃殖，民依厥功。", "嚴飭壇壝，威儀肅雍。", "神之來享，祈于登豐。"]'),
('8043fe2d-d4d8-4d07-b42e-949316340bef','大觀祀社稷九首 迎神用《寧安》。 其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔姑洗徵二奏〕猗歟那歟，生養斯民。',47,'全唐诗/poet.song.250000.json','["〔姑洗徵二奏〕猗歟那歟，生養斯民。", "家給人足，時底熙純。", "祗嚴明禋，於薦苾芬。", "粢盛豐潔，神乃有聞。"]'),
('22b30abd-a49f-4efd-aaac-0d8321ece4f9','大觀祀社稷九首 迎神用《寧安》。 其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔南呂羽二奏〕籩豆斯陳，三牲告幽。',47,'全唐诗/poet.song.250000.json','["〔南呂羽二奏〕籩豆斯陳，三牲告幽。", "報本之禮，答神之休。", "來歆芬香，豐登於秋。", "倉箱千萬，治符成周。"]'),
('d0c4f9ea-0e76-4d0c-9922-bec4058e7c4f','大觀祀社稷九首 初獻升降用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','崇崇廣壇，嚴恭祀事。',40,'全唐诗/poet.song.250000.json','["崇崇廣壇，嚴恭祀事。", "威儀孔時，周旋進止。", "鏘若環佩，誠通于幽。", "相于農植，邦其咸休。"]'),
('546f6e8b-677d-4c81-9f7e-698aab088a26','大觀祀社稷九首 奠幣用《嘉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於嘻陰祀，封土惟崇。',40,'全唐诗/poet.song.250000.json','["於嘻陰祀，封土惟崇。", "于時之吉，歆予鼓鍾。", "柔靜化光，人頼其功。", "陳茲量幣，百貨是隆。"]'),
('31f08d9d-0516-4b69-98f9-07783e8a350b','大觀祀社稷九首 酌獻用《嘉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','坤元生物，功利相宣。',40,'全唐诗/poet.song.250000.json','["坤元生物，功利相宣。", "蠲茲祀事，美報致虔。", "清酤芬如，靈壇巋然。", "酌尊奠觴，神其格焉。"]'),
('3965f947-f313-456c-bfdd-04ed851b65d4','大觀祀社稷九首 亞、終獻用《文安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','薦嘉亶時，洋洋來格。',40,'全唐诗/poet.song.250000.json','["薦嘉亶時，洋洋來格。", "載登茲壇，齊明維敕。", "神用居歆，順成農穡。", "其崇若墉，其比如櫛。"]'),
('cef084f1-e114-48d9-8077-21f27990e2ab','大觀祀社稷九首 送神用《寧安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','尊罍芬香，威儀肅雍。',40,'全唐诗/poet.song.250000.json','["尊罍芬香，威儀肅雍。", "靈心嘉止，洋洋交通。", "神歸降禧，年斯屢豐。", "倉箱千萬，慰予三農。"]'),
('1229011e-08c9-4731-8bbb-2dbb9b50c831','紹興祀太社太稷十七首 迎神用 其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔函鍾爲宮〕五祀之本，社稷有嚴。',46,'全唐诗/poet.song.250000.json','["〔函鍾爲宮〕五祀之本，社稷有嚴。", "芟柞伊始，夫敢不虔。", "吉日惟戊，式薦豆籩。", "神其來格，用介有年。"]'),
('7a3abb6b-f5e3-49b0-ad48-7f1eae9359c0','紹興祀太社太稷十七首 迎神用 其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔函鍾爲宮〕功烈在民，誕受露雨。',46,'全唐诗/poet.song.250000.json','["〔函鍾爲宮〕功烈在民，誕受露雨。", "良耜既歌，乃揚帗舞。", "是奉是尊，厚禮斯舉。", "相其豐年，多稌多黍。"]'),
('e49dc90d-2120-4c5d-9a85-c2bc20a9ed2a','紹興祀太社太稷十七首 迎神用 其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔太簇爲角〕是尊是奉，茲率舊章。',46,'全唐诗/poet.song.250000.json','["〔太簇爲角〕是尊是奉，茲率舊章。", "樂音純繹，薦溢圓方。", "情文備矣，神其迪嘗。", "永觀錫羨，多穡穰穰。"]'),
('d7046fd7-2e1c-49ac-8a11-5d7bf87dcf69','紹興祀太社太稷十七首 迎神用 其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔姑洗爲徵〕穀資土養，民頼穀生。',46,'全唐诗/poet.song.250000.json','["〔姑洗爲徵〕穀資土養，民頼穀生。", "功利之博，莫之與京。", "式嚴祠壇，因物薦誠。", "禮具樂奏，惟神顧歆。"]'),
('6e9a065e-2ee2-4ff8-b320-79fb644bf421','紹興祀太社太稷十七首 迎神用 其五','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔南呂爲羽〕國主社稷，時祀有常。',46,'全唐诗/poet.song.250000.json','["〔南呂爲羽〕國主社稷，時祀有常。", "肅若舊典，報本不忘。", "粢盛豐潔，歌吟青黄。", "尊神倏來，百物賓將。"]'),
('60eb9034-1429-48bd-9a78-9d7e0a4dfb5c','紹興祀太社太稷十七首 盥洗用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','祭重齊肅，神格專精。',40,'全唐诗/poet.song.250000.json','["祭重齊肅，神格專精。", "沃洗于阼，涓潔著誠。", "清明鬯矣，熙事備成。", "以似以續，如坻如京。"]'),
('e25d1ecb-bd35-41b2-8a32-976f826dceb8','紹興祀太社太稷十七首 升壇用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','神地之道，粒食有先。',40,'全唐诗/poet.song.250000.json','["神地之道，粒食有先。", "歲謹祈報，禮嚴豆籩。", "降登祼薦，罔或不虔。", "以似以續，宜屢豐年。"]'),
('2ceb5473-b157-4060-8347-b258ab975083','紹興祀太社太稷十七首 太社位奠玉幣用《嘉安》。春社太稷、土正、后稷通用。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','土發而祭，農祥是祈。',40,'全唐诗/poet.song.250000.json','["土發而祭，農祥是祈。", "籩豆加篚，典禮有彝。", "惟茲珪幣，用告肅祗。", "神靈降鑒，錫我繁釐。"]'),
('bde4a1c6-910b-40f5-884a-9fbfbe5797a4','紹興祀太社太稷十七首 太社位奠玉幣用《嘉安》。秋臘太稷、土正、后稷通用。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','赫赫媼神，稼穡是司。',40,'全唐诗/poet.song.250000.json','["赫赫媼神，稼穡是司。", "方是藉斂，報本攸宜。", "嘉壇建祀，玉帛陳儀。", "明靈昭格，以介蕃釐。"]'),
('cdd65068-9498-492d-9491-59008cec9769','紹興祀太社太稷十七首 還位用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','國主太祀，地道聿神。',40,'全唐诗/poet.song.250000.json','["國主太祀，地道聿神。", "稷司百穀，利毓惟均。", "練日新吉，粢盛飶芬。", "神燕娭矣，福此下民。"]'),
('eb84a24f-529b-47f1-bedc-7a8ebafe9ff7','紹興祀太社太稷十七首 捧俎用《豐安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','嘉承天和，黍稷翼翼。',40,'全唐诗/poet.song.250000.json','["嘉承天和，黍稷翼翼。", "默相農功，繄神之德。", "俎實犧牲，舊章是式。", "嗣有豐年，我庾維億。"]'),
('9f4ca300-d0a5-4cfc-87d1-f66c8450acb3','紹興祀太社太稷十七首 太社位酌獻用《嘉安》。春社太稷、土正、后稷通用。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','封土崇祀，有烈在民。',40,'全唐诗/poet.song.250000.json','["封土崇祀，有烈在民。", "千載不昧，福此人羣。", "洗爵奠斝，有酒其芬。", "神具醉止，愷樂欣欣。"]'),
('6c230c14-a1c8-4e14-a88c-86e4ff283804','紹興祀太社太稷十七首 太社位酌獻用《嘉安》。秋社、臘太稷、土正、后稷通用。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','叶氣嘉生，年穀順成。',40,'全唐诗/poet.song.250000.json','["叶氣嘉生，年穀順成。", "萬億及秭，如坻如京。", "奉時犉牡，告於神明。", "歌此良耜，於昭德馨。"]'),
('d563c15c-86f3-413b-858a-0e42aefcecc7','紹興祀太社太稷十七首 亞、終獻用《文安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','風雨時若，自天降康。',40,'全唐诗/poet.song.250000.json','["風雨時若，自天降康。", "稼穡滋殖，自神發祥。", "穀我婦子，豐年穰穰。", "報本嚴祀，齊明允臧。"]'),
('5c837ed7-f8bc-49ab-94bf-1011594a336f','紹興祀太社太稷十七首 徹豆用《娭安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','報本之禮，載于甲令。',40,'全唐诗/poet.song.250000.json','["報本之禮，載于甲令。", "靈壇昭告，神既來聽。", "徹彼豆籩，精誠斯罄。", "實惟豐年，農夫之慶。"]'),
('465008be-0196-4b3d-973e-74a97a89ecaf','紹興祀太社太稷十七首 送神用《寧安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','乃粒烝民，功昭萬古。',40,'全唐诗/poet.song.250000.json','["乃粒烝民，功昭萬古。", "國有常祀，薦獻式敘。", "肅肅雍雍，舊章咸舉。", "神保聿歸，介我稷黍。"]'),
('8e826aaf-c0fd-4577-ae71-a16e15af42f4','紹興祀太社太稷十七首 望瘞用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','地載萬物，民資迺功。',40,'全唐诗/poet.song.250000.json','["地載萬物，民資迺功。", "報本稱祀，太稷攸同。", "禮樂既備，訖埋愈恭。", "神其降嘏，時和歲豐。"]'),
('0786dbe6-3661-41b5-8794-ce1af65976c4','熙寧祭風師五首 迎神用《欣安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','飄颻而來，淅瀝而下。',40,'全唐诗/poet.song.250000.json','["飄颻而來，淅瀝而下。", "爰張其旂，爰整其駕。", "有豆有登，有兆有壇。", "弭旌柅輈，降止且安。"]'),
('1a76a739-2ccf-44e4-af53-7c6beec7eb1c','熙寧祭風師五首 升降用《欽安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','盥帨于下，有盤有匜。',40,'全唐诗/poet.song.250000.json','["盥帨于下，有盤有匜。", "饋酌于上，有登有彝。", "服容柔止，進退優止。", "即事寅恭，神其休止。"]'),
('7264e9a7-4782-477e-843d-046dcceec52c','熙寧祭風師五首 奠幣用《容安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','育我嘉生，神惠是仰。',40,'全唐诗/poet.song.250000.json','["育我嘉生，神惠是仰。", "載致斯幣，庶幾用享。", "鼓之舞之，式繄爾神。", "錫福無疆，佑此下民。"]'),
('b58b9814-441e-4368-9ff1-2767fe4e04e8','熙寧祭風師五首 亞、終獻，酌獻用《雍安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','栗栗壇坫，載是豆觴。',40,'全唐诗/poet.song.250000.json','["栗栗壇坫，載是豆觴。", "醇烈氤氳，普薦芬芳。", "酌之維宜，獻之維時。", "民有報侑，靈用安之。"]'),
('1772b3c7-31bc-43af-8437-410aa7bf8641','熙寧祭風師五首 送神用《欣安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','奠獻紛紛，靈心欣欣。',40,'全唐诗/poet.song.250000.json','["奠獻紛紛，靈心欣欣。", "超然而返，衆御如雲。", "其施伊何，多黍多稌。", "其祥伊何，不愆厥敘。"]'),
('7fc0c487-4af7-4f01-b4ac-ba9d23d946bd','大觀祭風師六首 降神用《欣安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','羽旗雲車，飄颻自天。',40,'全唐诗/poet.song.250000.json','["羽旗雲車，飄颻自天。", "猗歟南箕，歆嘉升煙。", "牲餼粢盛，俎簋鉶籩。", "維神戾止，從空泠然。"]'),
('5dc33b9b-7f49-4677-9568-60dcde1b6dbe','大觀祭風師六首 初獻升降用《欽安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','明昭惟馨，威儀孔時。',40,'全唐诗/poet.song.250000.json','["明昭惟馨，威儀孔時。", "鏘鏘鳴佩，欽薦牲犧。", "惟恭惟祗，無愆無違。", "周旋中禮，肅恭委蛇。"]'),
('9e08a488-9419-4b98-8985-b3c6689f3e2b','大觀祭風師六首 奠幣用《容安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','吹噓于喁，披拂氤氳。',40,'全唐诗/poet.song.250000.json','["吹噓于喁，披拂氤氳。", "衆竅咸作，潜運化鈞。", "恩大功豐，酬神維恭。", "嘉贈盈箱，于物有容。"]'),
('ca757bf0-12ff-44a4-8f9f-ba107e6a3fc7','大觀祭風師六首 酌獻用《雍安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','犧尊斯陳，清酤盈中。',40,'全唐诗/poet.song.250000.json','["犧尊斯陳，清酤盈中。", "芬芬苾苾，馨香交通。", "明靈來思，歆我精衷。", "維千萬祀，品物芃芃。"]'),
('253c743b-96da-4418-99ea-6cdda8eaeacc','大觀祭風師六首 亞、終獻用《雍安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','清酤洋洋，虔恭注茲。',40,'全唐诗/poet.song.250000.json','["清酤洋洋，虔恭注茲。", "條鬯敷宣，神用歆之。", "尊罍靜嘉，金奏諧熙。", "於皇肆祀，休我羣黎。"]'),
('71f10d58-fa55-403d-a202-29cbc571812f','大觀祭風師六首 送神用《欣安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','窈冥無窮，肸蠁斯融。',40,'全唐诗/poet.song.250000.json','["窈冥無窮，肸蠁斯融。", "來終嘉薦，歸返遥空。", "惟神之歸，欣安導和。", "惟神之澤，于彼滂沱。"]'),
('5c377580-f1a2-438e-8688-ea52b48b262f','雨師五首 迎神用《欣安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','神之無象，亦可思索。',40,'全唐诗/poet.song.250000.json','["神之無象，亦可思索。", "維雲陰陰，維風莫莫。", "降止壇宇，來顧芳馨。", "侑以鼓歌，薦此明誠。"]'),
('3e322d4f-c0de-4965-ac28-30b188bb72ff','雨師五首 升降用《欽安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','佩玉璆如，黼黻襜如。',40,'全唐诗/poet.song.250000.json','["佩玉璆如，黼黻襜如。", "承神不懈，訖獲嘉虞。", "聖皇命祀，臣敢弗恭。", "凡爾在位，翼翼雍雍。"]'),
('06a955ab-22ae-4666-b775-a20ba09083d3','雨師五首 奠幣用《容安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','崇崇壇階，靈既降止。',40,'全唐诗/poet.song.250000.json','["崇崇壇階，靈既降止。", "有嚴執奠，承祀茲始。", "明靈在天，式顧庶察。", "澤潤以時，永拂荒札。"]'),
('801c7785-e12f-4eb8-8db5-0a32a3d1eaed','雨師五首 酌獻，亞、終獻用《雍安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','寅恭我神，惟上之使。',40,'全唐诗/poet.song.250000.json','["寅恭我神，惟上之使。", "俾成康年，民徯休祉。", "折俎既登，𣂏酒既盈。", "匪薦是專，配以明誠。"]'),
('a142de44-1474-4b94-affd-73af9b4675bc','雨師五首 送神用《欣安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','牲俎告徹，嘉樂休成。',40,'全唐诗/poet.song.250000.json','["牲俎告徹，嘉樂休成。", "卒事有嚴，燕虞高靈。", "蕃我民人，育我稷黍。", "萬有千祀，承神之祜。"]'),
('dbd5552c-fe5b-4cfc-87f2-12c4ac05dde1','紹興祭風師六首 迎神用《欣安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','夫物絪縕，神氣撓之。',40,'全唐诗/poet.song.250000.json','["夫物絪縕，神氣撓之。", "誰歟其司，維南之箕。", "俶哉明庶，我祀維時。", "我心孔勞，神其下來。"]'),
('12f841c1-3ce6-481a-955d-1ff00ef2c4a5','紹興祭風師六首 初獻升降、盥洗用《欽安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','神哉沛矣，厥靈載揚。',40,'全唐诗/poet.song.250000.json','["神哉沛矣，厥靈載揚。", "揚靈如何，剡剡皇皇。", "我其承之，繩繩齊莊。", "往從鬰人，爰俠斯芳。"]'),
('2e0e2699-2e47-4f34-b92a-a49e15d40daa','紹興祭風師六首 奠幣用《容安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','物之流形，甚畏瘥癘。',40,'全唐诗/poet.song.250000.json','["物之流形，甚畏瘥癘。", "八風平矣，嘉生以遂。", "絲縷之積，有量斯幣。", "惟本之報，匪物之貴。"]'),
('a721d198-fe54-41fd-a062-f626e82a0370','紹興祭風師六首 酌獻用《雍安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','我求於神，無臭無聲。',40,'全唐诗/poet.song.250000.json','["我求於神，無臭無聲。", "神之燕饗，惟時專精。", "大磬在列，槱燎在庭。", "侑我桂酒，娭其以聽。"]'),
('2d7d6e9e-5894-4f61-bade-e9d04283cf09','紹興祭風師六首 亞、終獻。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','禮有三祀，儀物視帝。',40,'全唐诗/poet.song.250000.json','["禮有三祀，儀物視帝。", "神臨消摇，疇敢跛倚。", "重觴載申，百味孔旨。", "神兮樂康，答我以祉。"]'),
('3b21da04-4f6b-446c-826a-633788a111c2','紹興祭風師六首 送神。曲同迎神。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','荃其止乎，禗禗其容。',40,'全唐诗/poet.song.250000.json','["荃其止乎，禗禗其容。", "奄橫四海，蹇莫之窮。", "時不驟得，禮焉有終。", "荃其行乎，余心𢥞𢥞。"]'),
('23aa264e-bde5-4b9a-b30b-f3f837661956','雨師雷神七首 迎神用《欣安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','衆萬之託，動之潤之。',40,'全唐诗/poet.song.250000.json','["衆萬之託，動之潤之。", "昭格孔時，維神之依。", "泠然後先，肆我肯顧。", "是耶非耶，紛其來下。"]'),
('2df78ba3-1764-43d8-bedb-d8083e0555ce','雨師雷神七首 初獻盥洗、升降用《欽安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','言言祠宮，爰考我禮。',40,'全唐诗/poet.song.250000.json','["言言祠宮，爰考我禮。", "維西有罍，維東有洗。", "爰潔爰滌，載薦其醴。", "神在何斯，匪遠具邇。"]'),
('fcc78a79-1a92-48ef-9c85-8559c8d8be22','雨師雷神七首 奠幣用《容安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','霈兮隠兮，蹶其陰威。',40,'全唐诗/poet.song.250000.json','["霈兮隠兮，蹶其陰威。", "相我有終，胡寧不知。", "我幣有陳，我邸斯珪。", "豈維有陳，于以奠之。"]'),
('81a1a5d0-3f3f-4823-b92e-889be50810df','雨師雷神七首 雨師位酌獻用《雍安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','山川出雲，裔裔而縷。',40,'全唐诗/poet.song.250000.json','["山川出雲，裔裔而縷。", "載霪載濛，其德迺溥。", "自古有年，胡然莫祖。", "無簡我觴，無怠我俎。"]'),
('5204391a-ba46-42fe-841e-3c311a5fadf6','雨師雷神七首 雷神位酌獻。曲同雨師。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','瞻彼南山，有虺其出。',40,'全唐诗/poet.song.250000.json','["瞻彼南山，有虺其出。", "維蟄之奮，維癘之息。", "眷焉顧饗，在夏之日。", "觴豆匪報，皇忍忘德。"]'),
('f22da5c0-3989-4d2d-895a-66636d8ac42f','雨師雷神七首 亞、終獻。曲同初獻。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','作解之德，形聲一兮。',40,'全唐诗/poet.song.250000.json','["作解之德，形聲一兮。", "爰展獻侑，酌則三兮。", "我興有假，云胡有私。", "下土是冒，庶其遠而。"]'),
('65ed47d7-73ca-4869-be7f-ada7812bed62','雨師雷神七首 送神。曲同迎神。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','陰旄載旋，鼓車其鞭。',40,'全唐诗/poet.song.250000.json','["陰旄載旋，鼓車其鞭。", "問神安歸，冥然而天。", "皇有正命，祀事孔蠲。", "其臨其歸，億萬斯年。"]'),
('e33458fe-1c84-4f7d-8581-337c13bc63e8','雍熙享先農六首餘同祈穀','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','先農播種，九穀務滋。',40,'全唐诗/poet.song.250000.json','["先農播種，九穀務滋。", "靈壇致享，良耜陳儀。", "吉日惟亥，運屬純熙。", "樂之作矣，神其格思。"]'),
('45d84e2c-1ca8-45a6-9194-0fc43e73c140','雍熙享先農六首餘同祈穀 奠玉幣用《敷安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','親耕展祀，明靈來格。',40,'全唐诗/poet.song.250000.json','["親耕展祀，明靈來格。", "九有駿奔，百司庇職。", "獻奠肅肅，登降翼翼。", "祈彼豐穰，福流萬國。"]'),
('f8b758e1-6074-41cb-ab88-0ea90d353524','雍熙享先農六首餘同祈穀 奉俎用《豐安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','肅陳韶舞，祗薦犧牲。',20,'全唐诗/poet.song.250000.json','["肅陳韶舞，祗薦犧牲。", "乃逆黄俎，以率躬耕。"]'),
('c7bb0eed-c4f0-4376-8a73-509d2d3b35f3','雍熙享先農六首餘同祈穀 亞獻用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','祀惟古典，食乃民天。',20,'全唐诗/poet.song.250000.json','["祀惟古典，食乃民天。", "歆茲潔祀，以應祈年。"]'),
('40c35dea-0f68-429d-a5dc-9610ee4adbe3','雍熙享先農六首餘同祈穀 終獻用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','式陳芳薦，爰致虔誠。',20,'全唐诗/poet.song.250000.json','["式陳芳薦，爰致虔誠。", "神其降鑒，永福黎甿。"]'),
('a9e32bc4-8f1b-499a-9111-7caa7833604a','雍熙享先農六首餘同祈穀 送神用《靜安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','明禋紺壇，靈風肅然。',40,'全唐诗/poet.song.250000.json','["明禋紺壇，靈風肅然。", "登歌已闋，神馭將旋。", "道光帝籍，禮備公田。", "鑒茲躬稼，永賜豐年。"]'),
('849bf1c5-2731-42f5-95da-3ee9817b0628','明道親享先農十首 迎神用《靜安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','稼政之本，民食惟天。',40,'全唐诗/poet.song.250000.json','["稼政之本，民食惟天。", "甫田兆歲，后稷其先。", "靈壇既祀，黛耜攸虔。", "乃聖能享，億萬斯年。"]'),
('50217543-26d6-4308-857f-9ee570ede1a8','明道親享先農十首 皇帝升降用《隆安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','冕服在御，壇壝有儀。',20,'全唐诗/poet.song.250000.json','["冕服在御，壇壝有儀。", "陟降左右，天惟顯思。"]'),
('a8b65833-1082-4b33-98d7-745914733b20','明道親享先農十首 奠玉幣用《嘉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','將躬黛耜，先陟靈壇。',40,'全唐诗/poet.song.250000.json','["將躬黛耜，先陟靈壇。", "嘉玉量幣，樂舉禮殫。", "神既至止，福亦和安。", "千斯積詠，萬國多歡。"]'),
('db82d110-6323-4a59-a408-4e7d18e5c481','明道親享先農十首 奉俎用《豐安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','將迎景福，乃薦嘉牲。',20,'全唐诗/poet.song.250000.json','["將迎景福，乃薦嘉牲。", "籍于千畝，用此精誠。"]'),
('f8249872-4653-4486-82ee-2fc16e253233','明道親享先農十首 皇帝初獻用《禧安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','雲罍已實，玉爵有舟。',20,'全唐诗/poet.song.250000.json','["雲罍已實，玉爵有舟。", "薦于靈籍，佇乃神休。"]'),
('a1300185-bd82-4b36-91d8-c834d88c7aab','明道親享先農十首 飲福用《禧安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','神既至饗，福亦來酬。',40,'全唐诗/poet.song.250000.json','["神既至饗，福亦來酬。", "申錫純嘏，旨酒惟柔。", "思文后稷，貽我來牟。", "子孫千億，丕荷天休。"]'),
('91fead6c-8ab7-4436-b898-c179190d9fac','明道親享先農十首 退文舞、進武舞用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','羽葆有奕，文武交相。',20,'全唐诗/poet.song.250000.json','["羽葆有奕，文武交相。", "周旋合度，福祿無疆。"]'),
('c26bdef6-df4f-4cfb-a74a-46facbdfd06c','明道親享先農十首 亞獻用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','豆籩雖薦，黍稷非馨。',20,'全唐诗/poet.song.250000.json','["豆籩雖薦，黍稷非馨。", "惠我豐歲，歆茲至誠。"]'),
('07ba7c68-6d0b-43f3-80b5-6903d6dad167','明道親享先農十首 終獻用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','歆我嘉薦，錫我蕃禧。',20,'全唐诗/poet.song.250000.json','["歆我嘉薦，錫我蕃禧。", "多黍多稌，如京如坻。"]'),
('08e8646f-8fe6-4dcf-bf06-770d2ab02674','明道親享先農十首 送神用《靜安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','獻終豆徹，禮備樂成。',40,'全唐诗/poet.song.250000.json','["獻終豆徹，禮備樂成。", "祠容肅肅，風馭冥冥。", "三時務本，一墢躬耕。", "人祇胥悅，祉福是膺。"]'),
('9c9dd049-3df8-4fe6-8e91-210e776124b1','景祐饗先農五首 迎神用《凝安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','在昔神農，首茲播殖。',40,'全唐诗/poet.song.250000.json','["在昔神農，首茲播殖。", "無有污萊，盡爲稼穡。", "乃粒斯民，實惟帝力。", "嘉薦令芳，佇瞻來格。"]'),
('a18011c3-0e59-46b0-b0cd-3f989a22f99f','景祐饗先農五首 升降用《同安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','居德之厚，厥祀攸陳。',40,'全唐诗/poet.song.250000.json','["居德之厚，厥祀攸陳。", "土膏初脈，農事先春。", "鏗然金奏，儼若華紳。", "陟降于阼，福祿惟神。"]'),
('52a4dace-a1d8-455a-8ce5-251664f3e025','景祐饗先農五首 奠幣用《明安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','農爲政本，食乃民天。',40,'全唐诗/poet.song.250000.json','["農爲政本，食乃民天。", "苾芬明祀，蔗蔉良田。", "陳茲量幣，望彼豐年。", "茂介福祉，來欽吉蠲。"]'),
('f2cde72f-6d1d-4dd2-9aad-82a63d48ee03','景祐饗先農五首 酌獻用《成安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','農祥晨正，平秩東作。',40,'全唐诗/poet.song.250000.json','["農祥晨正，平秩東作。", "倬彼大田，庤乃錢鎛。", "酒醴盈尊，金璆合樂。", "期茲萬年，充于六幕。"]'),
('6d26b3b2-8abe-4b24-a731-75c5798c05a5','景祐饗先農五首 送神用《凝安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','務嗇之本，恤祀惟馨。',40,'全唐诗/poet.song.250000.json','["務嗇之本，恤祀惟馨。", "神斯至止，降福攸寧。", "崇茲稼政，合于禮經。", "俎徹樂闋，邈仰迴靈。"]'),
('7b80d241-5cc6-44bd-88c8-d76758612770','先蠶六首 迎神用《明安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','生民之朔，衣皮而羣。',40,'全唐诗/poet.song.250000.json','["生民之朔，衣皮而羣。", "惟聖有作，被冒以文。", "禮樂以成，貴賤以分。", "欲報之德，金石諧均。"]'),
('86cee217-282b-421d-89f3-5bc308ce35c2','先蠶六首 升降用《翊安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','掩抑笙簫，鏗谹金石。',40,'全唐诗/poet.song.250000.json','["掩抑笙簫，鏗谹金石。", "神來宴娭，嘉我休德。", "奉祀之臣，洗心翊翊。", "錫茲福禧，以惠四國。"]'),
('bbc9c7c8-c2fc-4c21-bc4e-e989c414c9fc','先蠶六首 奠幣用《娭安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','皇天降物，屢化若神。',40,'全唐诗/poet.song.250000.json','["皇天降物，屢化若神。", "聖實先識，躬以教民。", "功被天下，爲萬世文。", "幣以達志，庶幾徹聞。"]'),
('0d1df81c-0052-4639-9967-91b669329dcf','先蠶六首 酌獻用《美安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','夐哉聖神，成功微妙。',40,'全唐诗/poet.song.250000.json','["夐哉聖神，成功微妙。", "迺兗迺裳，以供郊廟。", "百末旨酒，嘉觴自炤。", "靈徠宴饗，不嚬以笑。"]'),
('f5f86c3f-b32f-4c01-9d81-4f1fb042fee9','先蠶六首 亞、終獻用《惠安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','神之徠，駕蹌蹌。',40,'全唐诗/poet.song.250000.json','["神之徠，駕蹌蹌。", "紫壇熙，燭夜光。", "會竽瑟，鳴球琅。", "薦旨酒，雜蘭芳。", "佑明德，錫百祥。"]'),
('8f5eb7f2-cf6f-4281-a2b9-9d51ada4976b','先蠶六首 送神用《祥安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','神之功兮，四海所宗。',40,'全唐诗/poet.song.250000.json','["神之功兮，四海所宗。", "占五帝兮，莫與比崇。", "倏往來兮，旌騎容容。", "恭明祀兮，萬世無窮。"]'),
('640c1522-b562-4765-a01c-663c801408ba','紹興享先農十一首 皇帝入內壝盥洗用《隆安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','大事在祀，齊潔爲先。',40,'全唐诗/poet.song.250000.json','["大事在祀，齊潔爲先。", "既盥而升，奉以周旋。", "下觀而化，無敢不蠲。", "惟神降格，監厥精虔。"]'),
('3b2f1f4d-759d-4340-992f-51631d1ac09b','紹興享先農十一首 迎神用《靜安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','猗歟田祖，粒食之宗。',40,'全唐诗/poet.song.250000.json','["猗歟田祖，粒食之宗。", "世世仰德，青壇載崇。", "時惟后稷，躬稼同功。", "作配並祀，以詔無窮。"]'),
('163d69c1-47af-4b63-a317-8300791a815f','紹興享先農十一首 神農、后稷位奠幣用《嘉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','制爲量幣，厚意是將。',40,'全唐诗/poet.song.250000.json','["制爲量幣，厚意是將。", "求之以類，各因其方。", "于以奠之，精誠允彰。", "神其享止，惠我無疆。"]'),
('99b88743-dd87-4670-813c-8e5f2c269673','紹興享先農十一首 尚書奉俎用《豐安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','柔毛剛鬣，或剝或烹。',20,'全唐诗/poet.song.250000.json','["柔毛剛鬣，或剝或烹。", "爲俎孔碩，登薦厥誠。"]'),
('039a5364-f9bb-4fbd-89ee-a91b6274935a','紹興享先農十一首 酌獻用《禧安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','蠲滌醆斝，巾帨而升。',40,'全唐诗/poet.song.250000.json','["蠲滌醆斝，巾帨而升。", "挹彼注茲，酒醴維清。", "洋洋在上，享于克誠。", "神其孚佑，以厚民生。"]'),
('4ea7b25f-f030-47ea-be68-1ec724fa97aa','紹興享先農十一首 文舞退、武舞進用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','羽毛干戚，張弛則殊。',20,'全唐诗/poet.song.250000.json','["羽毛干戚，張弛則殊。", "進旅退旅，匪棘匪舒。"]'),
('51654127-dc0d-4250-9146-9f63dfb699d8','紹興享先農十一首 亞獻用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','顯相祀事，濟濟鏘鏘。',20,'全唐诗/poet.song.250000.json','["顯相祀事，濟濟鏘鏘。", "舉斝酌醴，神其允臧。"]'),
('a2983ce6-e392-4f50-b0e1-a4d84096ae67','紹興享先農十一首 終獻用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','殽核維旅，酒醴維馨。',20,'全唐诗/poet.song.250000.json','["殽核維旅，酒醴維馨。", "于再于三，禮則有成。"]'),
('51878b47-855d-4e50-8048-ef394b0b5d0b','紹興享先農十一首 飲福用《禧安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','幽明位異，施報理同。',40,'全唐诗/poet.song.250000.json','["幽明位異，施報理同。", "克恭明神，降福乃豐。", "我膺受之，來燕來崇。", "豈伊專饗，于彼三農。"]'),
('678c3490-a373-47c8-9c08-22ca9f92b3e4','紹興享先農十一首 徹豆用《歆安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','莫重於祭，非禮不成。',40,'全唐诗/poet.song.250000.json','["莫重於祭，非禮不成。", "籩豆有踐，爾殽既馨。", "神具醉止，薦以齊明。", "贊徹孔時，釐事斯成。"]'),
('697a416c-43dc-47d5-aa69-06e51bb469b4','紹興享先農十一首 送神用《靜安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','神之來止，風駛雲翔。',40,'全唐诗/poet.song.250000.json','["神之來止，風駛雲翔。", "神之旋歸，有迎有將。", "歌以送之，磬筦鏘鏘。", "何以惠民，豐年穰穰。"]'),
('ce9a3d0a-4a30-46cc-b920-32264d06c534','親耕藉田七首 皇帝出大次用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','勤勞稼穡，必躬必親。',40,'全唐诗/poet.song.250000.json','["勤勞稼穡，必躬必親。", "爲藉千畝，以教導民。", "帝出乎震，時惟上春。", "天顔咫尺，望之如雲。"]'),
('4c932887-f035-468a-b17b-d8caea6aff4c','親耕藉田七首 親耕。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','元辰既擇，禮備樂成。',40,'全唐诗/poet.song.250000.json','["元辰既擇，禮備樂成。", "洪縻在手，祗飾專精。", "三推一墢，端冕朱紘。", "靡辭染屨，以示黎甿。"]'),
('7cf26faf-f779-4f6a-ac88-e6ff138a2004','親耕藉田七首 升壇。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','方壇屹立，陛級而登。',40,'全唐诗/poet.song.250000.json','["方壇屹立，陛級而登。", "玉色下照，臨觀耦耕。", "萬目咸臯，如日之升。", "成規成矩，百祿是膺。"]'),
('34ef2efd-2c57-44fd-891a-eff6e0214f48','親耕藉田七首 公卿耕藉。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','羣公顯相，奉事齋莊。',40,'全唐诗/poet.song.250000.json','["羣公顯相，奉事齋莊。", "率時農夫，舉耜載揚。", "播厥百穀，以佑我皇。", "多黍多稌，丕應農祥。"]'),
('c534fe32-9e55-470e-85f9-7edf11b2b041','親耕藉田七首 群官耕藉。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','畟畟良耜，我田既臧。',40,'全唐诗/poet.song.250000.json','["畟畟良耜，我田既臧。", "土膏其動，春日載陽。", "執事有恪，于此中邦。", "農夫之慶，棲畝餘糧。"]'),
('b7566980-930a-45af-b6a1-0ce5c99c1af4','親耕藉田七首 降壇。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','肇新帝藉，率我農人。',40,'全唐诗/poet.song.250000.json','["肇新帝藉，率我農人。", "三推終畝，祗事咸均。", "陟降孔時，粲然有文。", "受天之祜，多稼如雲。"]'),
('33c8ec2c-5189-4e24-b4a7-314b821cd9c6','親耕藉田七首 歸大次。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','教民稼穡，不令而行。',40,'全唐诗/poet.song.250000.json','["教民稼穡，不令而行。", "進退有度，琚瑀鏘鳴。", "言還熉幄，禮則告成。", "帝命率育，明德惟馨。"]'),
('13660a76-8275-4987-abfe-0a01d3c2a4ea','紹興祀先農攝事七首 迎神用《凝安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','青陽開動，土膏脈起。',40,'全唐诗/poet.song.250000.json','["青陽開動，土膏脈起。", "日練吉亥，爲農祈祉。", "典秩增峻，儀物具美。", "幄光熉黄，庶幾戾止。"]'),
('b3de7ad7-0df4-4ead-9da3-eac81443a9e6','紹興祀先農攝事七首 初獻升殿用《同安》。盥洗同。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','率職咸涖，禮容睟然。',40,'全唐诗/poet.song.250000.json','["率職咸涖，禮容睟然。", "澡身端意，陟降靡愆。", "神心嘉虞，饗茲潔蠲。", "敷錫純佑，屢登豐年。"]'),
('065b63f0-416c-4679-80c6-b7dcee7acedb','紹興祀先農攝事七首 奠幣用《明安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','靈斿載臨，見先陳贄。',40,'全唐诗/poet.song.250000.json','["靈斿載臨，見先陳贄。", "有嚴篚實，式將純意。", "肸蠁既接，禮行有次。", "神兮安留，歆我禋祀。"]'),
('35cc6062-d47c-4c37-8421-6c8801b12eda','紹興祀先農攝事七首 神農位酌獻用《成安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','耒耜之教，帝實開先。',40,'全唐诗/poet.song.250000.json','["耒耜之教，帝實開先。", "致養垂利，古今民天。", "嘉薦報本，于以祈年。", "誠格和應，神娭福延。"]'),
('1fe98537-36e7-40ca-8406-5f6736dd4100','紹興祀先農攝事七首 后稷位酌獻用《成安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','有周膺曆，實起后稷。',40,'全唐诗/poet.song.250000.json','["有周膺曆，實起后稷。", "相時豐功，率由稼穡。", "振古稱祀，先農並食。", "阜我昌我，時萬時億。"]'),
('a7a064e3-1499-49b9-86e2-2c3da67f5edd','紹興祀先農攝事七首 亞、終獻用《同安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','旨具百味，酌備三疇。',40,'全唐诗/poet.song.250000.json','["旨具百味，酌備三疇。", "貳觴既畢，禮洽意周。", "庶幾嘉饗，格神之幽。", "相我穡事，錫以有秋。"]'),
('8b1809a4-a6ca-4cd5-998c-e025701dcd09','紹興祀先農攝事七首 送神用《凝安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','熙事成兮，始終潔齊。',40,'全唐诗/poet.song.250000.json','["熙事成兮，始終潔齊。", "籩豆徹兮，撙節靡垂。", "靈有嘉兮，降福孔皆。", "票然逝兮，我心孔懷。"]'),
('d27c17d7-ffa1-45e9-bc82-49436b76e6c5','祀先蠶六首 迎神用《明安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','功被寰宇，㒩蟲之靈。',40,'全唐诗/poet.song.250000.json','["功被寰宇，㒩蟲之靈。", "有神司之，以生以成。", "典禮有初，祀事講明。", "孔蓋翠旌，降集于庭。"]'),
('93f2992a-87ef-4250-a1cf-8da8240ac3d0','祀先蠶六首 初獻盥洗、升殿用《翊安》。降同。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','靈修戾止，詔以毛血。',40,'全唐诗/poet.song.250000.json','["靈修戾止，詔以毛血。", "既盥而帨，尊爵蠲潔。", "金石諧宛，登降有節。", "宜顧宜饗，情文不越。"]'),
('3c452988-2485-4583-ae0b-103b06158a11','祀先蠶六首 奠幣用《娛安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','化日初長，時當暮春。',40,'全唐诗/poet.song.250000.json','["化日初長，時當暮春。", "蠶事方興，惟后惟嬪。", "絲纊御冬，殘生濟人。", "敢忘報本，篚幣是陳。"]'),
('28c32623-cc35-4a9a-adad-4d35bfe03917','祀先蠶六首 酌獻用《美安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','盛服承祀，出自公桑。',40,'全唐诗/poet.song.250000.json','["盛服承祀，出自公桑。", "衣不羽皮，利及萬方。", "百味旨酒，有飶其香。", "神其歆止，洋洋在傍。"]'),
('a301bbad-853e-416a-a435-52855673cf2e','祀先蠶六首 亞、終獻用《惠安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','日吉辰良，禮備樂作。',40,'全唐诗/poet.song.250000.json','["日吉辰良，禮備樂作。", "精誠內孚，俎豆交錯。", "升歌清越，侑此三爵。", "黎民不寒，幽顯同樂。"]'),
('cb2a6387-3019-4153-9136-d4058df1bb66','祀先蠶六首 送神用《祥安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','神之來矣，靈風肅然。',40,'全唐诗/poet.song.250000.json','["神之來矣，靈風肅然。", "云胡不留，歸旐有翩。", "乃舉舊典，歲以告虔。", "降福我邦，於萬斯年。"]'),
('8c44de67-f9a6-4861-8322-e6314888feda','景德蜡祭百神三首 降神用《高安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','百物蕃阜，四方順成。',40,'全唐诗/poet.song.250000.json','["百物蕃阜，四方順成。", "通其八蜡，合乃嘉平。", "旨酒斯醇，大庖孔盈。", "萬靈來格，威儀以成。"]'),
('bd3bbe6b-c1b0-490f-92d4-ae1ed57cb922','景德蜡祭百神三首 奠玉幣、酌獻用《嘉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','肅肅靈壇，昭昭上天。',40,'全唐诗/poet.song.250000.json','["肅肅靈壇，昭昭上天。", "潔粢豐盛，以享以虔。", "百神咸萃，六樂斯縣。", "介茲景福，期於有年。"]'),
('952f0e43-86e7-432c-83e8-9eedd1acdad8','景德蜡祭百神三首 送神用《高安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','來顧來享，禮成樂備。',20,'全唐诗/poet.song.250000.json','["來顧來享，禮成樂備。", "靈馭翩翩，雲行雨施。"]'),
('06486a30-fe06-40ce-9c3a-26fcb81c6c59','熙寧蜡祭十三首 東西郊降神用《高安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','天錫康年，四方順成。',40,'全唐诗/poet.song.250000.json','["天錫康年，四方順成。", "乃通蜡祭，索享于明。", "金石四作，羽旄翠旌。", "神來宴娭，澤被羣生。"]'),
('17203c21-5e9d-4954-842a-4cb8fc34ced8','熙寧蜡祭十三首 升降用《肅安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','惟蜡有祭，報神之功。',40,'全唐诗/poet.song.250000.json','["惟蜡有祭，報神之功。", "合聚萬物，來享來宗。", "承詔攝事，不忘肅雍。", "靈之格思，福祿來崇。"]'),
('b1ebd44b-dfc0-49ca-81c5-f760247805e8','熙寧蜡祭十三首 奠幣用《欽安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','穰穰豐年，繄侯休德。',40,'全唐诗/poet.song.250000.json','["穰穰豐年，繄侯休德。", "帥承天和，欽象古則。", "嘉玉量幣，奠容翼翼。", "靈施暨民，罔有終極。"]'),
('74b0a085-41aa-4892-a7ab-ce8aa9824043','熙寧蜡祭十三首 奉俎用《承安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','禮崇明祀，必先成民。',40,'全唐诗/poet.song.250000.json','["禮崇明祀，必先成民。", "奉牲以告，備腯其均。", "炮炙芬芬，俎豆莘莘。", "錫之純嘏，以佑斯人。"]'),
('cfbe10c1-2a4d-40ee-bd6d-ef3617d717eb','熙寧蜡祭十三首 酌獻用《懌安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','秩秩禮文，爲壇四方。',40,'全唐诗/poet.song.250000.json','["秩秩禮文，爲壇四方。", "嘉栗旨酒，百神迪嘗。", "敷與萬物，既阜既昌。", "伊樂厥福，傳世無疆。"]'),
('fd33d116-56f2-48e6-b5f5-8f688519ad64','熙寧蜡祭十三首 亞、終獻用《慶安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','禮文備矣，肅肅無譁。',40,'全唐诗/poet.song.250000.json','["禮文備矣，肅肅無譁。", "金石諧節，圭璧光華。", "粢以告豐，醴以告嘉。", "錫茲福祉，以澤幽遐。"]'),
('73522d19-7bbc-4707-bdf3-ee8fbdfce896','熙寧蜡祭十三首 送神用《宣安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','靈之來下，擴景乘光。',40,'全唐诗/poet.song.250000.json','["靈之來下，擴景乘光。", "靈之迴御，景龍以驤。", "鑒我休德，降嘏産祥。", "大田多稼，以惠無疆。"]'),
('874924c8-d293-4f3d-8217-78a1856d992f','熙寧蜡祭十三首 南北方迎神用《簡安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','美若休德，民和歲豐。',40,'全唐诗/poet.song.250000.json','["美若休德，民和歲豐。", "稼穡雲施，其積如墉。", "惠我四國，先嗇之功。", "祭之百種，來享來宗。"]'),
('bc67e681-80d5-430f-85e5-12237c0f8ccf','熙寧蜡祭十三首 升降用《穆安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','皇皇靈德，經緯萬方。',40,'全唐诗/poet.song.250000.json','["皇皇靈德，經緯萬方。", "承詔攝事，陟降以莊。", "高冠岌峨，長佩鏘洋。", "嘉承神貺，令聞不忘。"]'),
('d840e658-4c65-4b89-b967-d674655a35a1','熙寧蜡祭十三首 奠幣用《吉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於穆明祀，莫如報功。',40,'全唐诗/poet.song.250000.json','["於穆明祀，莫如報功。", "靈之利澤，惠我無窮。", "齋以滌志，幣以達衷。", "撫寧四極，永錫登豐。"]'),
('b44f0586-2b65-481c-83c1-53572c9612f7','熙寧蜡祭十三首 酌獻用《禔安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','英英禮文，既備而全。',40,'全唐诗/poet.song.250000.json','["英英禮文，既備而全。", "嚴嚴四郊，屹屹紫壇。", "百末旨酒，其敷若蘭。", "何以畀民，既壽而安。"]'),
('f7191270-e190-4c02-be42-5097a24543e5','熙寧蜡祭十三首 亞、終獻用《曼安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','林林生民，含哺而嬉。',40,'全唐诗/poet.song.250000.json','["林林生民，含哺而嬉。", "教之稼穡，實神之爲。", "圖報厚德，萬祀無期。", "以假以享，錫我繁禧。"]'),
('301ac2f6-6312-4c0a-94ce-2c18713ad09a','熙寧蜡祭十三首 送神用《成安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','嘉薦芳美，靈來宴娭。',40,'全唐诗/poet.song.250000.json','["嘉薦芳美，靈來宴娭。", "斿車結雲，若風馬馳。", "既至而喜，錫我蕃禧。", "嘉承天貺，曼壽無期。"]'),
('946b6827-c259-45ad-af12-17eb6a8c9526','大觀蜡祭二首 東郊亞、終獻用《慶安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','震乘春陽，仁司生殖。',40,'全唐诗/poet.song.250000.json','["震乘春陽，仁司生殖。", "錫我歲豐，襄我民力。", "誰其尸之，宗子先嗇。", "億萬斯年，懷神罔極。"]'),
('bc5009bc-76cf-4b0b-8614-3efe326f1a67','大觀蜡祭二首 南郊升降用《穆安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','穆如薰風，敷舒文藻。',40,'全唐诗/poet.song.250000.json','["穆如薰風，敷舒文藻。", "氣蒸消除，豐予黍稻。", "神之聽之，鍾鼓咸考。", "於萬斯年，惟皇之報。"]'),
('d80b8081-f960-41e8-a440-0833f03f5b55','紹興以後蜡祭四十二首 東方百神降神用《熙安》。 其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔圜鍾爲宮〕玄冥凌厲，歲聿其周。',46,'全唐诗/poet.song.250000.json','["〔圜鍾爲宮〕玄冥凌厲，歲聿其周。", "天地閉藏，農且息休。", "古大蜡禮，伊耆肇修。", "爰薦飶馨，以迓飈游。"]'),
('7e646775-3211-4fdc-b2ee-8d96aa0b8b27','紹興以後蜡祭四十二首 東方百神降神用《熙安》。 其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔黄鍾爲角〕惟大明尊，實首三辰。',46,'全唐诗/poet.song.250000.json','["〔黄鍾爲角〕惟大明尊，實首三辰。", "功赫庶物，光被廣輪。", "歲方索饗，咸秩羣神。", "靈斿來下，尸此明禋。"]'),
('a9b87a8a-9784-4aad-80af-da18de3bc88d','紹興以後蜡祭四十二首 東方百神降神用《熙安》。 其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔太簇爲徵〕三時不害，四方順成。',46,'全唐诗/poet.song.250000.json','["〔太簇爲徵〕三時不害，四方順成。", "酬功報始，以我齊明。", "豳頌土鼓，樂此嘉平。", "降祥幅員，惠于函生。"]'),
('112ebb93-65a2-4c49-9521-27e957decf16','紹興以後蜡祭四十二首 東方百神降神用《熙安》。 其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔姑洗爲羽〕日昱乎晝，容光必照。',46,'全唐诗/poet.song.250000.json','["〔姑洗爲羽〕日昱乎晝，容光必照。", "肸蠁之交，惟人所召。", "有監在下，視茲升燎。", "肅若其承，雲駢星曜。"]'),
('749ed3a8-d590-493c-a3d9-27be85008495','紹興以後蜡祭四十二首 初獻升降用《肅安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','禮儀告具，心儼容莊。',40,'全唐诗/poet.song.250000.json','["禮儀告具，心儼容莊。", "工歌屢奏，聲和義章。", "崇壇陟降，濟濟蹌蹌。", "靈光共仰，嘉薦芬芳。"]'),
('865b5990-3a44-4c06-bd40-81573a86185e','紹興以後蜡祭四十二首 大明位奠玉幣用《欽安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','晨曦未融，天宇澄穆。',40,'全唐诗/poet.song.250000.json','["晨曦未融，天宇澄穆。", "有虔秉誠，將以幣玉。", "如在左右，罔不祗肅。", "神兮安留，錫以祉福。"]'),
('d3f2ced4-58ac-46a1-a744-a8bde86fc907','紹興以後蜡祭四十二首 帝神農位奠幣。曲同大明。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','農爲政本，食乃民天。',40,'全唐诗/poet.song.250000.json','["農爲政本，食乃民天。", "神農氏作，民始力田。", "先嗇之配，禮報則然。", "有幣將之，維以告虔。"]'),
('e809dcdb-de90-4e66-92f8-325f7d1cdb56','紹興以後蜡祭四十二首 后稷氏位奠幣。曲同大明。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','播種之功，時惟后稷。',40,'全唐诗/poet.song.250000.json','["播種之功，時惟后稷。", "推以配天，莫匪爾極。", "崇侑清祀，是爲司嗇。", "陳幣奠將，永祚王國。"]'),
('e42234c8-d06f-4c58-81b7-20ad12bf9abd','紹興以後蜡祭四十二首 奉俎用《承安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','享以精禋，馨非稷黍。',40,'全唐诗/poet.song.250000.json','["享以精禋，馨非稷黍。", "工祝致告，孔碩爲俎。", "執事駿奔，繩繩具舉。", "神之嘉虞，介福是與。"]'),
('df0ea62d-a5a9-4253-a973-95cb9b6a0bc7','紹興以後蜡祭四十二首 大明位酌獻用《擇安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','肇禋備祀，教民美報。',40,'全唐诗/poet.song.250000.json','["肇禋備祀，教民美報。", "時和歲豐，奉醴以告。", "惟照臨功，等於載燾。", "酌獻云初，明神所勞。"]'),
('6397867c-c085-4862-bd61-a4d0d8d28453','紹興以後蜡祭四十二首 神農位酌獻。曲同大明。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','惟酒欣欣，惟神冥冥。',40,'全唐诗/poet.song.250000.json','["惟酒欣欣，惟神冥冥。", "是顧是饗，來燕來寧。", "耒耜之利，神所肇興。", "萬世永頼，無斁其承。"]'),
('bb2ffc12-7b86-41c2-af35-4874e43caaa4','紹興以後蜡祭四十二首 后稷位酌獻。曲同大明。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','釋之蒸之，爲酒爲醴。',40,'全唐诗/poet.song.250000.json','["釋之蒸之，爲酒爲醴。", "推本所由，於焉洽禮。", "周邦開基，邰家是啟。", "獻茲嘉觴，拜下首稽。"]'),
('f1bf2748-f5d5-4faf-a479-5b75ddd5999b','紹興以後蜡祭四十二首 亞、終獻用《慶安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','申以貳觴，百味且旨。',40,'全唐诗/poet.song.250000.json','["申以貳觴，百味且旨。", "禮告三終，神具醉止。", "旌容騎沓，揚光紛委。", "降福穰穰，被大豐美。"]'),
('79f92e61-77d4-4301-8e03-a433b8ffc9b8','紹興以後蜡祭四十二首 送神用《宣安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','禮樂既成，神保聿歸。',40,'全唐诗/poet.song.250000.json','["禮樂既成，神保聿歸。", "言歸何所，地紀天維。", "豈惟屢豐，嗣歲所祈。", "億萬斯年，神來燕娭。"]'),
('33cb7a2b-5e27-4ce8-bbd8-43bc31e997b9','紹興以後蜡祭四十二首 西方百神降神用《熙安》。 其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔圜鍾爲宮〕玄冬肇祀，始于伊耆。',46,'全唐诗/poet.song.250000.json','["〔圜鍾爲宮〕玄冬肇祀，始于伊耆。", "歲事聿成，庸答蕃釐。", "眷言西顧，匪神司之。", "歸功爾神，翩其下來。"]'),
('9ddf9b5f-7b90-4042-801c-f9085eabb284','紹興以後蜡祭四十二首 西方百神降神用《熙安》。 其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔黄鍾爲角〕魄生自西，照望太陽。',46,'全唐诗/poet.song.250000.json','["〔黄鍾爲角〕魄生自西，照望太陽。", "下暨諸神，貺施萬方。", "節適風雨，富我囷箱。", "共承嘉祀，惟以迪嘗。"]'),
('1fb430ea-8f95-4115-8dce-6d98611f37cb','紹興以後蜡祭四十二首 西方百神降神用《熙安》。 其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔太簇爲徵〕神罔小大，奠方茲土。',46,'全唐诗/poet.song.250000.json','["〔太簇爲徵〕神罔小大，奠方茲土。", "祭列坊庸，禮迨貓虎。", "有功斯民，祀乃其所。", "非稷馨香，厥福周溥。"]'),
('f45a561b-7f5b-4cc1-872d-facacb8c329c','紹興以後蜡祭四十二首 西方百神降神用《熙安》。 其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔姑洗爲羽〕豐年穰穰，美芳職職。',46,'全唐诗/poet.song.250000.json','["〔姑洗爲羽〕豐年穰穰，美芳職職。", "籩豆方圓，其儀孔碩。", "風馬在御，雲車載飭。", "來顧來饗，維俟休德。"]'),
('a9bb6ba6-90fd-4a9e-ba43-dca8b82fec22','紹興以後蜡祭四十二首 初獻升降用《肅安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','盥獻恭莊，燎煙芬酷。',40,'全唐诗/poet.song.250000.json','["盥獻恭莊，燎煙芬酷。", "載陟載降，禮容可度。", "欽惟爾神，上下肅肅。", "成我稷黍，鑒此牲玉。"]'),
('0a422ea4-85c0-4f68-a10d-7e2b2f57583a','紹興以後蜡祭四十二首 夜明位奠玉幣用《欽安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','穆穆太陰，禮嚴姊事。',40,'全唐诗/poet.song.250000.json','["穆穆太陰，禮嚴姊事。", "璧玉華光，推以裒對。", "十二周天，歲乃有終。", "盡我備物，莫報元功。"]'),
('7f85e5d1-016e-42f4-9a8a-caba2748902d','紹興以後蜡祭四十二首 神農位奠幣。曲同夜明。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','耒耜肇興，自神農氏。',40,'全唐诗/poet.song.250000.json','["耒耜肇興，自神農氏。", "稼穡滋殖，爲農者始。", "作配明祀，奠以告虔。", "萬世佃漁，帝功卓然。"]'),
('f6af0b05-e8a4-445e-a42b-9aef256924c4','紹興以後蜡祭四十二首 后稷位奠幣。曲同夜明。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','明明周祖，惟民之恤。',40,'全唐诗/poet.song.250000.json','["明明周祖，惟民之恤。", "播種爲教，下民迺粒。", "曾是索饗，而匪先公。", "萬物難報，阡陌之功。"]'),
('78879d0e-3831-45c8-8997-da65bd3c9b73','紹興以後蜡祭四十二首 奉俎用《承安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','時和歲登，物亡疾瘯。',40,'全唐诗/poet.song.250000.json','["時和歲登，物亡疾瘯。", "實俎間膏，報神之福。", "匪神福之，曷成且豐。", "肥腯咸有，惟神之功。"]'),
('316b735a-7160-4537-ad3f-05d031662146','紹興以後蜡祭四十二首 夜明位酌獻用《擇安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','除壇西郊，坎其擊鼓。',40,'全唐诗/poet.song.250000.json','["除壇西郊，坎其擊鼓。", "百靈至止，結璘作主。", "秬鬯湛淡，玉斝觩䚧。", "是謂嘉德，神其安留。"]'),
('4329d4d9-dec6-4c0b-9443-59782a123ffb','紹興以後蜡祭四十二首 神農位酌獻。曲同夜明。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','蕩蕩鴻明，稱秩羣祀。',40,'全唐诗/poet.song.250000.json','["蕩蕩鴻明，稱秩羣祀。", "配以昔帝，式重農事。", "潔我圭瓚，黄流在中。", "靈其監茲，肸蠁豐融。"]'),
('54d53d29-04d9-49bb-abf0-e43f3a12eddb','紹興以後蜡祭四十二首 后稷位酌獻。曲同夜明。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','歲十二月，祀有常典。',40,'全唐诗/poet.song.250000.json','["歲十二月，祀有常典。", "祭列司嗇，言反其本。", "酌彼泰尊，百末蘭生。", "承神嘉虞，繄此德馨。"]'),
('6fad3e5e-a0e0-4236-9b90-3a08666447d3','紹興以後蜡祭四十二首 亞、終獻用《慶安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','歌磬臚驩，膋蕭激香。',40,'全唐诗/poet.song.250000.json','["歌磬臚驩，膋蕭激香。", "飈御奄留，申以貳觴。", "相與震澹，告靈其醉。", "庶幾聽之，成我熙事。"]'),
('3f9c3737-014c-4083-9d66-c6462d9f599b','紹興以後蜡祭四十二首 送神用《宣安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','禮備樂成，澹然將歸。',40,'全唐诗/poet.song.250000.json','["禮備樂成，澹然將歸。", "其留消摇，象輿已轙。", "偃蹇欲驤，羽毛紛委。", "忽乘杳冥，遺此福祉。"]'),
('03998a96-ead4-4837-8926-606c50f77f1f','紹興以後蜡祭四十二首 南方百神迎神用《簡安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','維物之精，散乎太空。',40,'全唐诗/poet.song.250000.json','["維物之精，散乎太空。", "維索之饗，合聚而同。", "迺擊土鼓，于歲之終。", "格彼幽矣，肸蠁其通。"]'),
('79ab5528-5445-4074-bd99-4c687756d877','紹興以後蜡祭四十二首 初獻盥洗、升降用《穆安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','有帨其新，有匜其潔。',40,'全唐诗/poet.song.250000.json','["有帨其新，有匜其潔。", "言念清祀，弗簡弗褻。", "誠意既交，品物斯列。", "是用告虔，靡神不說。"]'),
('515f59b3-384c-4d00-82d2-2bfd2e03c1ad','紹興以後蜡祭四十二首 奠幣用《吉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','百室機杼，衣褐具宜。',40,'全唐诗/poet.song.250000.json','["百室機杼，衣褐具宜。", "民以卒歲，神實惠之。", "言舉祀典，答神之釐。", "有篚斯陳，振古如茲。"]'),
('3ae16a20-3ef1-4275-9523-f02668ae786f','紹興以後蜡祭四十二首 神農位酌獻用《穆安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','肇降生民，有不粒食。',40,'全唐诗/poet.song.250000.json','["肇降生民，有不粒食。", "維時神農，迺爲先嗇。", "爾耒爾耨，云誰之因。", "酌以汙尊，我思古人。"]'),
('32eb69a5-0c89-47f4-bb21-4ccb9bcd7539','紹興以後蜡祭四十二首 后稷位酌獻用《穆安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','維后之功，配天其大。',40,'全唐诗/poet.song.250000.json','["維后之功，配天其大。", "祀而稷之，萬世如在。", "黄冠野服，駿奔皇皇。", "自古有年，神其降康。"]'),
('bb80acc3-4516-4e46-bf31-d28ab2a0abd2','紹興以後蜡祭四十二首 亞、終獻用《曼安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','豐年孔多，百禮以洽。',40,'全唐诗/poet.song.250000.json','["豐年孔多，百禮以洽。", "匪極神歡，何以昭答。", "載酌之酒，用申其勤。", "神具醉止，與物交欣。"]'),
('0405e416-15b0-471f-a72d-b138d0b47712','紹興以後蜡祭四十二首 送神用《成安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','卒爵樂闋，禮儀告備。',40,'全唐诗/poet.song.250000.json','["卒爵樂闋，禮儀告備。", "神保聿歸，敢以辭致。", "順成之方，其蜡乃通。", "自今以始，八方攸同。"]'),
('c364039b-cff5-46a1-a122-067dd0f2d721','紹興以後蜡祭四十二首 北方百神迎神用《簡安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','蕩蕩閫决，氣清泬寥。',40,'全唐诗/poet.song.250000.json','["蕩蕩閫决，氣清泬寥。", "彷彿象輿，麗于穹霄。", "蹇其來下，肅然風票。", "神乎安留，於焉消摇。"]'),
('0323b480-86ff-4b5d-b3e7-c6a15526fb9f','紹興以後蜡祭四十二首 初獻盥洗、升降用《穆安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','齊誠揭虔，敬恭祀事。',40,'全唐诗/poet.song.250000.json','["齊誠揭虔，敬恭祀事。", "維儼之容，維潔之器。", "雍雍樂成，肅肅禮備。", "神其燕娭，錫祉庶類。"]'),
('a01f36ed-3e42-48d3-9c5b-c9c9ff086c0f','紹興以後蜡祭四十二首 奠幣用《吉安》。配位同。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','神宅于幽，𣅺𣅺沈沈。',40,'全唐诗/poet.song.250000.json','["神宅于幽，𣅺𣅺沈沈。", "至和塞明，考我德音。", "神聽靜嘉，儼乎若臨。", "幣以薦誠，敢有弗欽。"]'),
('3fe52d93-d7dd-46ef-ba1b-edab21502b97','紹興以後蜡祭四十二首 神農氏位酌獻用《禔安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','先嗇之功，神實稱首。',40,'全唐诗/poet.song.250000.json','["先嗇之功，神實稱首。", "以耜以耒，俶載南畝。", "列籍皇墳，億世是守。", "何以爲報，爰潔茲酒。"]'),
('24b08b9f-f5ce-4ad9-b7d6-a6fcaf7b7242','紹興以後蜡祭四十二首 后稷氏位酌獻用《禔安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','煌煌后稷，實配于天。',40,'全唐诗/poet.song.250000.json','["煌煌后稷，實配于天。", "司嗇作稼，民以有年。", "匪神之私，歲以醴告。", "酌彼泰尊，于德之報。"]'),
('873be8e7-0459-46e5-8ff6-c60dd5f8b455','紹興以後蜡祭四十二首 亞、終獻用《曼安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','蘭生百末，申以貳觴。',40,'全唐诗/poet.song.250000.json','["蘭生百末，申以貳觴。", "神具醉止，爛其容光。", "遺我豐年，萬億及秭。", "俾民驩康，以洽百禮。"]'),
('157afc8a-8650-4cd3-8fec-4521dd229ce7','紹興以後蜡祭四十二首 送神用《成安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','靈之來兮，虯龍沓沓。',40,'全唐诗/poet.song.250000.json','["靈之來兮，虯龍沓沓。", "下土光景，憑陵閶闔。", "靈之旋兮，羽衛委蛇。", "偃蹇高驤，遺此蕃釐。"]'),
('e471b061-0895-4a30-bd9b-4252ef6607cf','景祐祭文宣王廟六首 迎神用《凝安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','大哉至聖，文教之宗。',40,'全唐诗/poet.song.250000.json','["大哉至聖，文教之宗。", "紀綱王化，丕變民風。", "常祀有秩，備物有容。", "神其格思，是仰是崇。"]'),
('7f208388-94df-475e-9444-59925d8002aa','景祐祭文宣王廟六首 初獻升降用《同安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','右文興化，憲古師今。',40,'全唐诗/poet.song.250000.json','["右文興化，憲古師今。", "明祀有典，吉日惟丁。", "豐犧在俎，雅奏來庭。", "周旋陟降，福祉是膺。"]'),
('fd763d97-b54c-420a-9ed1-18b682be20fd','景祐祭文宣王廟六首 奠幣用《明安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','一王垂法，千古作程。',40,'全唐诗/poet.song.250000.json','["一王垂法，千古作程。", "有儀可仰，無德而名。", "齊以滌志，幣以達誠。", "禮容合度，黍稷非馨。"]'),
('87380ab7-246b-4cef-93c5-42b6a3c96292','景祐祭文宣王廟六首 酌獻用《成安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','自天生聖，垂範百王。',40,'全唐诗/poet.song.250000.json','["自天生聖，垂範百王。", "恪恭明祀，陟降上庠。", "酌彼醇旨，薦此令芳。", "三獻成禮，率由舊章。"]'),
('7576e64a-99a2-43e7-8812-4da3cc019d5b','景祐祭文宣王廟六首 飲福用《綏安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','犧象在前，豆籩在列。',40,'全唐诗/poet.song.250000.json','["犧象在前，豆籩在列。", "以享以薦，既芬既潔。", "禮成樂備，人和神悅。", "祭則受福，率遵無越。"]'),
('fb73536d-5851-4ad4-8b31-90b644adcf70','景祐祭文宣王廟六首 兖國公配位酌獻用《成安》。哲宗朝增此一曲。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','無疆之祀，配侑可宗。',40,'全唐诗/poet.song.250000.json','["無疆之祀，配侑可宗。", "事舉以類，與享其從。", "嘉栗旨酒，登薦惟恭。", "降此遐福，令儀肅雍。"]'),
('5b9927d2-acad-41e4-a191-05fe3ad449bc','景祐祭文宣王廟六首 送神用《凝安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','肅肅庠序，祀事惟明。',40,'全唐诗/poet.song.250000.json','["肅肅庠序，祀事惟明。", "大哉宣父，將聖多能。", "歆馨肸蠁，迴馭凌兢。", "祭容斯畢，百福是膺。"]'),
('b10e7d7e-f7b4-47f2-b282-eefaeeb4868e','大觀三年釋奠六首 迎神用《凝安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','仰之彌高，鑽之彌堅。',40,'全唐诗/poet.song.250000.json','["仰之彌高，鑽之彌堅。", "於昭斯文，被于萬年。", "峨峨膠庠，神其來止。", "思款無窮，敢忘于始。"]'),
('bde75c9e-f5cb-4815-98c3-e8ac5c873fae','大觀三年釋奠六首 升降用《同安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','生民以來，道莫與京。',40,'全唐诗/poet.song.250000.json','["生民以來，道莫與京。", "溫良恭儉，惟神惟明。", "我潔尊罍，陳茲芹藻。", "言升言旋，式崇斯教。"]'),
('b4f04c50-4b8f-4dae-bac0-61f1e39d3879','大觀三年釋奠六首 奠幣用《明安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於論鼓鍾，于茲西雍。',40,'全唐诗/poet.song.250000.json','["於論鼓鍾，于茲西雍。", "粢盛肥碩，有顯其容。", "其容洋洋，咸瞻像設。", "幣以達誠，歆我明潔。"]'),
('67161a3e-05ae-4dff-86ef-b42b17f09a97','大觀三年釋奠六首 酌獻用《成安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','道德淵源，斯文之宗。',40,'全唐诗/poet.song.250000.json','["道德淵源，斯文之宗。", "功名糠粃，素王之風。", "碩兮斯牲，芬兮斯酒。", "綏我無疆，與天爲久。"]'),
('0032dacb-866f-43f2-9dff-0e1a0cf34b6c','大觀三年釋奠六首 配位酌獻用《成安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','儼然冠纓，崇然廟庭。',40,'全唐诗/poet.song.250000.json','["儼然冠纓，崇然廟庭。", "百王承祀，涓辰惟丁。", "于牲于醑，其從予享。", "與聖爲徒，其德不爽。"]'),
('16083a6a-4a61-4242-9df1-4158ad0c7c30','大觀三年釋奠六首 送神用《凝安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','肅莊紳緌，吉蠲牲犧。',40,'全唐诗/poet.song.250000.json','["肅莊紳緌，吉蠲牲犧。", "於皇明祀，薦登惟時。", "神之來兮，肸蠁之隨。", "神之去兮，休嘉之貽。"]'),
('04b0a4d0-bf18-41aa-a2eb-b00a5f223956','大晟府擬撰釋奠十四首 迎神用《凝安》。 其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔黄鍾爲宮〕大哉宣聖，道德尊崇。',46,'全唐诗/poet.song.250000.json','["〔黄鍾爲宮〕大哉宣聖，道德尊崇。", "維持王化，斯民是宗。", "典祀有常，精純並隆。", "神其來格，於昭盛容。"]'),
('b7011a50-87d1-498d-abfe-4ec9f169cc5b','大晟府擬撰釋奠十四首 迎神用《凝安》。 其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔大呂爲角〕生而知之，有教無私。',46,'全唐诗/poet.song.250000.json','["〔大呂爲角〕生而知之，有教無私。", "成均之祀，威儀孔時。", "維茲初丁，潔我盛粢。", "永適其道，萬世之師。"]'),
('2bc36475-91df-476b-9c24-667b3b6f968d','大晟府擬撰釋奠十四首 迎神用《凝安》。 其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔太簇爲徵〕巍巍堂堂，其道如天。',46,'全唐诗/poet.song.250000.json','["〔太簇爲徵〕巍巍堂堂，其道如天。", "清明之象，應物而然。", "時維上丁，備物薦誠。", "維新禮典，樂諧中聲。"]'),
('bcbf13e8-6aab-487f-b90a-8a11e00c99fb','大晟府擬撰釋奠十四首 迎神用《凝安》。 其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','〔應鍾爲羽〕聖王生知，闡迺儒規。',46,'全唐诗/poet.song.250000.json','["〔應鍾爲羽〕聖王生知，闡迺儒規。", "詩書文教，萬世昭垂。", "良日惟丁，靈承不爽。", "揭此精虔，神其來饗。"]'),
('b311eae9-efe3-4b1f-a6fe-41c9af5adf14','大晟府擬撰釋奠十四首 初獻盥洗用《同安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','右文興化，憲古師經。',40,'全唐诗/poet.song.250000.json','["右文興化，憲古師經。", "明祀有典，吉日惟丁。", "豐犧在俎，雅奏在庭。", "周旋陟降，福祉是膺。"]'),
('f39266eb-8d93-4b48-b727-150d8b666c9d','大晟府擬撰釋奠十四首 升殿用《同安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','誕興斯文，經天緯地。',40,'全唐诗/poet.song.250000.json','["誕興斯文，經天緯地。", "功加于民，實千萬世。", "笙鏞和鳴，粢盛豐備。", "肅肅降登，歆茲秩祀。"]'),
('d385034f-d78f-490c-ae35-9255292b36e5','大晟府擬撰釋奠十四首 奠幣用《明安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','自生民來，誰底其盛。',40,'全唐诗/poet.song.250000.json','["自生民來，誰底其盛。", "惟王神明，度越前聖。", "粢幣具成，禮容斯稱。", "黍稷非馨，惟神之聽。"]'),
('66db098e-b22f-4580-b013-7c4ba3391924','大晟府擬撰釋奠十四首 奉俎用《豐安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','道同乎天，人倫之至。',40,'全唐诗/poet.song.250000.json','["道同乎天，人倫之至。", "有饗無窮，其興萬世。", "既潔斯牲，粢明醑旨。", "不懈以忱，神之來暨。"]'),
('8ff8b012-fcce-4995-b5f2-35c18151e85f','大晟府擬撰釋奠十四首 文宣王位酌獻用《成安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','大哉聖王，實天生德。',40,'全唐诗/poet.song.250000.json','["大哉聖王，實天生德。", "作樂以崇，時祀無斁。", "清酤惟馨，嘉牲孔碩。", "薦羞神明，庶幾昭格。"]'),
('82e2039f-cb68-467b-b30c-19553872d33b','大晟府擬撰釋奠十四首 兖國公位酌獻用《成安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','庶幾屢空，淵源深矣。',40,'全唐诗/poet.song.250000.json','["庶幾屢空，淵源深矣。", "亞聖宣猷，百世宜祀。", "吉蠲斯辰，昭陳尊簋。", "旨酒欣欣，神其來止。"]'),
('daa68aba-f007-4d6c-b04e-06750e83d5a5','大晟府擬撰釋奠十四首 鄒國公位酌獻用《成安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','道之由興，於皇宣聖。',40,'全唐诗/poet.song.250000.json','["道之由興，於皇宣聖。", "惟公之傳，人知趨正。", "與饗在堂，情文實稱。", "萬年承休，假哉天命。"]'),
('c2bfd390-43fb-4f1b-affc-f536985c0ffa','大晟府擬撰釋奠十四首 亞、終獻用《文安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','百王宗師，生民物軌。',40,'全唐诗/poet.song.250000.json','["百王宗師，生民物軌。", "瞻之洋洋，神其寧止。", "酌彼金罍，惟清且旨。", "登獻惟三，於嘻成禮。"]'),
('1489fba6-c0f1-4129-9ff2-2a1d057f09c6','大晟府擬撰釋奠十四首 徹豆用《娛安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','犧象在前，豆籩在列。',40,'全唐诗/poet.song.250000.json','["犧象在前，豆籩在列。", "以饗以薦，既芬既潔。", "禮成樂備，人和神悅。", "祭則受福，率遵無越。"]'),
('81fc4733-1c29-4486-9c77-78f10078a5c7','大晟府擬撰釋奠十四首 送神用《凝安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','有嚴學宮，四方來宗。',40,'全唐诗/poet.song.250000.json','["有嚴學宮，四方來宗。", "恪恭祀事，威儀雍雍。", "歆茲惟馨，飈馭旋復。", "明禋斯畢，咸膺百福。"]'),
('93b7f81f-76e0-4882-813c-71f3ff17d7b1','景祐釋奠武成王六首 迎神用《凝安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','維師尚父，四履分封。',40,'全唐诗/poet.song.250000.json','["維師尚父，四履分封。", "靈神峻密，祀事寅恭。", "蕭薌祗薦，飈馭排空。", "如幾如式，福祿來崇。"]'),
('b49ad064-e929-4fa3-a29f-6bf5f156f064','景祐釋奠武成王六首 太尉升降用《同安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','上公攝事，衮服斯皇。',40,'全唐诗/poet.song.250000.json','["上公攝事，衮服斯皇。", "禮容濟濟，佩響鏘鏘。", "靈斿惚怳，嘉薦令芳。", "神具醉止，降福穰穰。"]'),
('c8a82925-248e-4e3c-8b31-574ce1175f6c','景祐釋奠武成王六首 奠幣用《明安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','四嶽之裔，凉彼武王。',40,'全唐诗/poet.song.250000.json','["四嶽之裔，凉彼武王。", "發揚蹈厲，周室用昌。", "追封廟食，簡冊增芳。", "升幣以奠，磬筦鏘鏘。"]'),
('2e71076b-c169-4fa3-a6f8-8a00007e9784','景祐釋奠武成王六首 酌獻用《成安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','獵渭之陽，理冥嘉應。',40,'全唐诗/poet.song.250000.json','["獵渭之陽，理冥嘉應。", "非龍非彪，聿求元聖。", "平易近民，五月報政。", "祀典之崇，於斯爲盛。"]'),
('64de5549-9afb-4f9b-ab53-2168f97cd51a','景祐釋奠武成王六首 飲福用《綏安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','神機經武，隆周之宇。',40,'全唐诗/poet.song.250000.json','["神機經武，隆周之宇。", "表海分封，邁燕超魯。", "耽耽廟貌，俎豆有序。", "薦福邦家，維師尚父。"]'),
('0bda7f47-c052-401b-a107-2559129b8fe4','景祐釋奠武成王六首 送神用《凝安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','聖朝稽古，崇茲武經。',40,'全唐诗/poet.song.250000.json','["聖朝稽古，崇茲武經。", "禮交樂舉，于神之庭。", "嘉栗旨酒，既饗芳馨。", "永嚴列象，劍舄簪纓。"]'),
('77d2ef7a-5c22-47f2-8f85-b7dec76ce2cb','熙寧祀武成王一首 初獻升降用《同安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','武德洸洸，日靖四方。',40,'全唐诗/poet.song.250000.json','["武德洸洸，日靖四方。", "百王所祀，休有烈光。", "命官攝事，佩玉鏘鏘。", "思皇多祜，以惠無疆。"]'),
('374bdded-36d7-4895-b034-a66df94f4606','大觀祀武成王一首 酌獻用《成安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','凉彼周王，君臣相遇。',40,'全唐诗/poet.song.250000.json','["凉彼周王，君臣相遇。", "終謀其成，諸侯來許。", "洋洋神靈，尊載酒醑。", "新聲爲侑，笙簫備舉。"]'),
('2f4b5088-eb51-4d63-9301-59336ba255a2','紹興釋奠武成王七首 迎神用《凝安》，姑洗爲宮。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於赫烈武，光昭古今。',40,'全唐诗/poet.song.250000.json','["於赫烈武，光昭古今。", "載嚴祀事，敕備惟欽。", "既潔其牲，既諧其音。", "神之格思，來顧來歆。"]'),
('3b47d31d-39a5-46e7-8f03-46a6f4bfb6c3','紹興釋奠武成王七首 初獻升殿用《同安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','肅肅廟中，有嚴階墄。',40,'全唐诗/poet.song.250000.json','["肅肅廟中，有嚴階墄。", "匪棘匪徐，進退可則。", "冕服是儀，環珮有節。", "神之鑒觀，率履不越。"]'),
('a7770d45-0698-46e1-8a11-31d667350b7d','紹興釋奠武成王七首 奠幣用《明安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','祀率舊典，禮崇駿功。',40,'全唐诗/poet.song.250000.json','["祀率舊典，禮崇駿功。", "齊明衷正，肸蠁豐融。", "量幣肅備，周旋鞠躬。", "神其昭受，幽贊無窮。"]'),
('5132dbe8-4c28-4046-852e-c172aceacded','紹興釋奠武成王七首 正位酌獻用《成安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','赫赫尚父，時維鷹揚。',40,'全唐诗/poet.song.250000.json','["赫赫尚父，時維鷹揚。", "神潜韜略，襟抱帝王。", "談笑致主，竹帛流芳。", "國有嚴祀，載稽典常。"]'),
('d36b3058-497c-46c8-acc2-ed50175d852e','紹興釋奠武成王七首 留侯位酌獻。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','眷彼留侯，奇籌贊漢。',40,'全唐诗/poet.song.250000.json','["眷彼留侯，奇籌贊漢。", "依乘風雲，勒成功旦。", "克配明禋，儀刑有煥。", "英氣如生，來格來衎。"]'),
('f17ac23d-e1a0-46b3-9b7c-d860151dd13a','紹興釋奠武成王七首 亞、終獻用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','道助文德，言爲世師。',40,'全唐诗/poet.song.250000.json','["道助文德，言爲世師。", "功名不泯，祀事無遺。", "旨酒惟馨，具醉在茲。", "有嘉累獻，神其燕娭。"]'),
('2bea083b-ef2f-4a3e-8de3-4dbdc547397f','紹興釋奠武成王七首 送神。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','日惟上戊，神顧精純。',40,'全唐诗/poet.song.250000.json','["日惟上戊，神顧精純。", "禮備三獻，樂成七均。", "奄留洋洋，流福無垠。", "言還恍惚，空想如存。"]'),
('b2219cc1-09b4-41ef-97bb-398d2619164d','紹興祀祚德廟八首 迎神用《凝安》，姑洗爲宮。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','匿孤立後，惟義惟忠。',40,'全唐诗/poet.song.250000.json','["匿孤立後，惟義惟忠。", "昔者神考，追錄乃功。", "祀典載加，進爵錫公。", "神兮降格，尚鑒褒崇。"]'),
('5571c836-b370-42d3-ace8-ce73f06835f5','紹興祀祚德廟八首 初獻升降用《同安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','廟宇更新，輪奐豐敞。',40,'全唐诗/poet.song.250000.json','["廟宇更新，輪奐豐敞。", "神靈如在，英姿颯爽。", "執事進趨，降升俯仰。", "威儀翼翼，虔祈歆饗。"]'),
('a7c62aec-cc5c-47b6-8ccc-9306b3019b38','紹興祀祚德廟八首 奠幣用《明安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','牲薦碩大，幣致精純。',40,'全唐诗/poet.song.250000.json','["牲薦碩大，幣致精純。", "聿升祀事，茲用兼陳。", "箱篚既實，奠獻惟寅。", "饗我至意，福祿來成。"]'),
('120caffd-55ce-4f91-866f-68f3ec9822b0','紹興祀祚德廟八首 彊濟公位酌獻用《成安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','以身託孤，實惟死友。',40,'全唐诗/poet.song.250000.json','["以身託孤，實惟死友。", "撫嫗長之，若父若母。", "潜授于韓，克興厥後。", "崇廟以獻，德侈報厚。"]'),
('8212fb8f-eacd-4bf8-8ff4-f3dd0757a52b','紹興祀祚德廟八首 英略公位酌獻用《成安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','立孤固難，死亦匪易。',40,'全唐诗/poet.song.250000.json','["立孤固難，死亦匪易。", "義輕一身，開先趙嗣。", "肅穆廟貌，烈有餘氣。", "式旋嘉薦，昭哉祀事。"]'),
('f771bcdd-dfee-48fb-8cc4-2666889d85f5','紹興祀祚德廟八首 啟佑公位酌獻用《成安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於皇時宋，永祚有基。',40,'全唐诗/poet.song.250000.json','["於皇時宋，永祚有基。", "始繄覆護，扶而立之。", "敢忘昭答，牲分酒釃。", "靈其燕饗，益相本支。"]'),
('41bc1508-cc25-40f1-896c-5e5d871c1ee2','紹興祀祚德廟八首 亞、終獻用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','𣅺𣅺靈宇，神安且翔。',40,'全唐诗/poet.song.250000.json','["𣅺𣅺靈宇，神安且翔。", "三哲鼎峙，中薦嘉觴。", "凜若義氣，千載彌光。", "猗其祐之，錫羨無疆。"]'),
('1af941d2-fe8d-40cd-b22b-f09eede014f0','紹興祀祚德廟八首 送神用《凝安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','禮樂云備，畢觴爾神。',40,'全唐诗/poet.song.250000.json','["禮樂云備，畢觴爾神。", "翊翊音送，轙輿若聞。", "駕言歸兮，靈斿結雲。", "祚我千億，介福來臻。"]'),
('dafd9e8b-8040-43a9-a7fe-07a003c0191b','司中司命五首 迎神用《欣安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','冠峨峨兮，服章蕤蕤。',40,'全唐诗/poet.song.250000.json','["冠峨峨兮，服章蕤蕤。", "靈來下兮，進止委蛇。", "我涓我壇，我潔我俎。", "降輿却旌，於茲享御。"]'),
('741f5312-036e-40bd-b8e9-ad4a4b9bd02a','司中司命五首 升降用《欽安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','紳緌舒舒，佩環鏗鏗。',40,'全唐诗/poet.song.250000.json','["紳緌舒舒，佩環鏗鏗。", "陟降上下，壇燎光明。", "有盥于罍，有帨于巾。", "不吳不敖，庶以安神。"]'),
('08a43ee6-2e31-4363-8130-d5f3b0b4193b','司中司命五首 奠幣用《容安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','我誠既潔，我豆既豐。',40,'全唐诗/poet.song.250000.json','["我誠既潔，我豆既豐。", "神來降斯，有儼其容。", "薦此嘉幣，肅肅雍雍。", "何以侑之，於樂鼓鍾。"]'),
('65910d45-7eba-4139-a0bc-36e9efc3035f','司中司命五首 酌獻用《雍安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','酌茲旨酒，既盈且芬。',40,'全唐诗/poet.song.250000.json','["酌茲旨酒，既盈且芬。", "式用來歆，衎衎熏熏。", "何以寧神，薦有嘉籩。", "何以錫民，曰惟豐年。"]'),
('9a42eb2e-0ea8-49d6-8da9-0aa7216621c8','司中司命五首 送神用《欣安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','雲兮飄飄，風兮稜稜。',40,'全唐诗/poet.song.250000.json','["雲兮飄飄，風兮稜稜。", "飈馭返空，杲日來昇。", "歸旆揚揚，衆樂鏘鏘。", "我神式懽，惠我嘉祥。"]'),
('19fcf0cb-8813-4de6-b6f1-4b59b3c9b5d3','五龍六首 迎神用《禧安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','靈之智兮，躍漢潜幽。',40,'全唐诗/poet.song.250000.json','["靈之智兮，躍漢潜幽。", "欲豢擾兮，無董與劉。", "陳金石兮，佐侑牢羞。", "庶燕享兮，澤應民求。"]'),
('dcad2d0a-b855-4077-a4bb-30f53292b0f4','五龍六首 升降用《雅安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','靈之至兮，逸駕騰驤。',40,'全唐诗/poet.song.250000.json','["靈之至兮，逸駕騰驤。", "噓雲吸氣，承祀日光。", "展詩鳴律，肅莊琳琅。", "何以膺神，貺惠無疆。"]'),
('6a1824c7-ad17-4f0f-b7f4-f017c50625a7','五龍六首 奠幣用《文安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','維靈德兮，變化不常。',40,'全唐诗/poet.song.250000.json','["維靈德兮，變化不常。", "沛天澤兮，周流八荒。", "奠嘉幣兮，肅雍不忘。", "永佑民兮，錫以豐穰。"]'),
('88239b7d-3c40-4411-a969-d7f8d222f5ed','五龍六首 酌獻用《愷安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','練吉日兮，進神之堂。',40,'全唐诗/poet.song.250000.json','["練吉日兮，進神之堂。", "牲既陳兮，粢盛既香。", "奠桂酒兮，容與嘉觴。", "靈安留兮，錫我福祥。"]'),
('9b3f901a-752d-48ca-b3ae-fbc9d7066823','五龍六首 亞、終獻用《嘉安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','明明天子，禮文咸秩。',40,'全唐诗/poet.song.250000.json','["明明天子，禮文咸秩。", "矧神之功，橫被九域。", "雲施稱民，物産滋殖。", "嘉承惠和，罔有終極。"]'),
('be4488a6-a8dc-4885-b458-3b66e061eb89','五龍六首 送神用《登安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','靈之來下，以雨先驅。',40,'全唐诗/poet.song.250000.json','["靈之來下，以雨先驅。", "靈之旋馭，五雲結車。", "操環應夏，發匣瑞虞。", "真人在御，來獻珍符。"]'),
('ace8bb47-1196-424a-b189-6e8bd8c47714','建隆乾德朝會樂章二十八首 皇帝升座用《隆安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','天臨有赫，上法乾元。',40,'全唐诗/poet.song.250000.json','["天臨有赫，上法乾元。", "鏗鏘六樂，儼恪千官。", "皇儀允肅，玉坐居尊。", "文明在御，禮備誠存。"]'),
('c8cc5dc7-4a5c-4f9f-8373-6655214d87ea','建隆乾德朝會樂章二十八首 公卿入門用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','堯天協紀，舜日揚光。',40,'全唐诗/poet.song.250000.json','["堯天協紀，舜日揚光。", "淑慎爾止，率由舊章。", "佩環濟濟，金石鏘鏘。", "威儀炳煥，至德昭彰。"]'),
('740672cb-daa9-4a70-9197-49f9f4e3428a','建隆乾德朝會樂章二十八首 上壽用《禧安》。 其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','乾健爲君，坤柔曰臣。',40,'全唐诗/poet.song.250000.json','["乾健爲君，坤柔曰臣。", "惟其臣子，克奉君親。", "永御皇極，以綏兆民。", "稱觴獻壽，山岳嶙峋。"]'),
('d1e1e9bd-f8bb-48b8-9c28-368193de52fb','建隆乾德朝會樂章二十八首 上壽用《禧安》。 其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','舜韶更奏，堯酒浮觴。',40,'全唐诗/poet.song.250000.json','["舜韶更奏，堯酒浮觴。", "皇情載懌，洪算無疆。", "基隆郟鄏，德茂陶唐。", "山巍日煥，地久天長。"]'),
('ace7acd9-b14f-4ce8-bab7-30be9815a561','建隆乾德朝會樂章二十八首 皇帝舉酒第一盞用《白龜》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','聖德昭宣，神龜出焉。',40,'全唐诗/poet.song.250000.json','["聖德昭宣，神龜出焉。", "載白其色，或游于川。", "名符在沼，瑞應巢蓮。", "登歌丹陛，紀異靈篇。"]'),
('9a79db5a-a781-4ec2-85e8-696b5c0211c9','建隆乾德朝會樂章二十八首 第二盞用《甘露》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','天德冥應，仁澤載濡。',40,'全唐诗/poet.song.250000.json','["天德冥應，仁澤載濡。", "其甘如醴，其凝若珠。", "雲表潜結，顥英允敷。", "降于竹柏，永昭瑞圖。"]'),
('7ff17658-c315-44a0-9fdc-019736354b2d','建隆乾德朝會樂章二十八首 第三盞用《紫芝》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','煌煌茂英，不根而生。',40,'全唐诗/poet.song.250000.json','["煌煌茂英，不根而生。", "蒲茸奪色，銅池著名。", "晨敷表異，三秀分榮。", "書于瑞典，光我文明。"]'),
('bb06867f-66c0-42c7-9db8-64d55a3c7515','建隆乾德朝會樂章二十八首 第四盞用《嘉禾》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','嘉彼合穎，致貢升平。',40,'全唐诗/poet.song.250000.json','["嘉彼合穎，致貢升平。", "異標南畝，瑞應西成。", "德至于地，皇祇效靈。", "和同之象，煥發祥經。"]'),
('bd8db035-f6e8-4609-bded-ba0a637b736d','建隆乾德朝會樂章二十八首 第五盞用《玉兔》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','盛德好生，網開三面。',40,'全唐诗/poet.song.250000.json','["盛德好生，網開三面。", "明視標奇，昌辰乃見。", "育質雪園，淪精月殿。", "著於樂章，色含江練。"]'),
('4f3c8cb7-fdd1-4bb1-987f-b250304ba12f','建隆乾德朝會樂章二十八首 羣臣舉酒用《正安》。 其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','戶牖嚴丹扆，鵷鸞簉紫庭。',48,'全唐诗/poet.song.250000.json','["戶牖嚴丹扆，鵷鸞簉紫庭。", "懇祈南岳壽，勢拱北辰星。", "得士於茲盛，基邦固以寧。", "誠明一何至，金石與丹青。"]'),
('2bbade9c-7076-47cb-a0a0-d61d44f9de34','建隆乾德朝會樂章二十八首 羣臣舉酒用《正安》。 其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','簪紱若雲屯，晨趨閶闔門。',48,'全唐诗/poet.song.250000.json','["簪紱若雲屯，晨趨閶闔門。", "侁侁羅禹會，濟濟奉堯罇。", "周禮觀明備，天儀仰睟溫。", "高卑陳表著，同拱帝王尊。"]'),
('b17c1489-1c19-40d3-a313-310cacde086f','建隆乾德朝會樂章二十八首 羣臣舉酒用《正安》。 其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','待漏造王庭，威儀盛莫京。',48,'全唐诗/poet.song.250000.json','["待漏造王庭，威儀盛莫京。", "紛綸簪組列，清越佩環聲。", "禮飲終三爵，韶音畢九成。", "永同鳬藻樂，千載奉升平。"]'),
('35fa1d1b-a8ba-43cd-9fa7-d34acbcf3e5f','建隆乾德朝會樂章二十八首 羣臣第一盞畢作《玄德升聞》。 其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','治定資神武，功成顯睿文。',48,'全唐诗/poet.song.250000.json','["治定資神武，功成顯睿文。", "貢輸庭實旅，朝會羽儀分。", "偃革千年運，垂衣萬乘君。", "孰知堯舜力，明德自升聞。"]'),
('779ebc05-4985-4e5b-b833-de4eb7095692','建隆乾德朝會樂章二十八首 羣臣第一盞畢作《玄德升聞》。 其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','約法皇綱正，崇文寶曆昌。',48,'全唐诗/poet.song.250000.json','["約法皇綱正，崇文寶曆昌。", "遒人振木鐸，農器鑄干將。", "瑞日含王宇，卿雲藹帝鄉。", "萬邦成一統，鴻祚與天長。"]'),
('e4480b4d-9489-4307-b983-5101b9cc0cc9','建隆乾德朝會樂章二十八首 又六變。 其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','宸扆威容盛，聲明禮樂宣。',48,'全唐诗/poet.song.250000.json','["宸扆威容盛，聲明禮樂宣。", "九州臻禹會，萬國戴堯天。", "貢職輸琛賮，皇猷煥簡編。", "含和均暢茂，鴻慶結非煙。"]'),
('73e6af44-df14-4166-8eb3-5360fe0c1460','建隆乾德朝會樂章二十八首 又六變。 其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','朝會儼威儀，司常建九旗。',48,'全唐诗/poet.song.250000.json','["朝會儼威儀，司常建九旗。", "舞容分綴兆，文物辨威蕤。", "運格桃林牧，祥開洛水龜。", "帝功潜日用，化俗自登熙。"]'),
('a3f3848a-2593-4c1b-9e74-1eea3807c738','建隆乾德朝會樂章二十八首 又六變。 其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','螭階聊載筆，紀瑞軼唐虞。',48,'全唐诗/poet.song.250000.json','["螭階聊載筆，紀瑞軼唐虞。", "丹鳳儀金奏，黄龍負寶圖。", "羣材薪棫樸，仁政煦蒲盧。", "蕩蕩巍巍德，豚魚信自孚。"]'),
('314409b3-9b35-4045-955d-5690011cf21f','建隆乾德朝會樂章二十八首 又六變。 其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','接聖宅神都，方來五達區。',48,'全唐诗/poet.song.250000.json','["接聖宅神都，方來五達區。", "國賢熙帝載，靈命握乾符。", "至化當純被，斯文益誕敷。", "車書今混一，聖治奉三無。"]'),
('2026072f-098d-4992-ba0b-5193d0c5ff35','建隆乾德朝會樂章二十八首 又六變。 其五','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','聖皇臨大寶，八表湊才賢。',48,'全唐诗/poet.song.250000.json','["聖皇臨大寶，八表湊才賢。", "經緯文天賦，剛柔德日宣。", "建邦隆柱石，造物運陶甄。", "共致升平業，綿長保億年。"]'),
('81732e27-d8e3-45b6-bc12-1f69031ec7d2','建隆乾德朝會樂章二十八首 又六變。 其六','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','神化妙無方，巍巍邁百王。',48,'全唐诗/poet.song.250000.json','["神化妙無方，巍巍邁百王。", "鶴書搜隠逸，龍陛策賢良。", "拱揖朝羣后，賓筵闢四方。", "洪圖基億載，淳曜德彌光。"]'),
('003b55b8-d46f-4bf7-a66b-fa461ffb42bf','建隆乾德朝會樂章二十八首 第二盞畢用《天下大定》。 其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','皇猷敷八表，武誼肅三邊。',48,'全唐诗/poet.song.250000.json','["皇猷敷八表，武誼肅三邊。", "蘭錡韜兵日，靈臺偃伯年。", "奉珍皆述職，削衽盡朝天。", "功德超前古，音徽播管弦。"]'),
('f64717b3-308f-4694-b334-043cf1547034','建隆乾德朝會樂章二十八首 第二盞畢用《天下大定》。 其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','伐叛天威震，恢疆帝業多。',48,'全唐诗/poet.song.250000.json','["伐叛天威震，恢疆帝業多。", "削平侔肅殺，涵煦極陽和。", "蹈厲觀周舞，風雲入漢歌。", "功成推大定，歸馬偃琱戈。"]'),
('1b61178b-4727-4fde-b74d-f7dd0c40f5ec','建隆乾德朝會樂章二十八首 又六變。 其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','惕厲日乾乾，潜蟠或躍淵。',48,'全唐诗/poet.song.250000.json','["惕厲日乾乾，潜蟠或躍淵。", "伐謀參上策，受鉞總中堅。", "田訟歸周日，民謠戴舜年。", "風雲自冥感，嘉會翼飛天。"]'),
('2a0921c0-0fae-4a08-a369-276e4763e3fd','建隆乾德朝會樂章二十八首 又六變。 其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','壺關方逆命，投袂起親征。',48,'全唐诗/poet.song.250000.json','["壺關方逆命，投袂起親征。", "虎旅聊攻伐，梟巢遽蕩平。", "天威清朔漠，仁澤被黎氓。", "按節皇輿復，洋洋載頌聲。"]'),
('4c248cd4-b9b8-41ff-851e-a16445faab62','建隆乾德朝會樂章二十八首 又六變。 其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','蠢茲淮海帥，保據毒黎苗。',48,'全唐诗/poet.song.250000.json','["蠢茲淮海帥，保據毒黎苗。", "不悟龍興漢，猶同犬吠堯。", "六師方雨施，孤壘自冰消。", "千載逢嘉運，華夷奉聖朝。"]'),
('ae2c0e96-7718-4672-a20e-8b06e81cc27f','建隆乾德朝會樂章二十八首 又六變。 其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','上游荆楚要，澤國洞庭深。',48,'全唐诗/poet.song.250000.json','["上游荆楚要，澤國洞庭深。", "自識同文世，皆迴拱極心。", "一戎聊杖鉞，九土盡輸金。", "大定功成後，薰風入舜琴。"]'),
('5913cda4-30e5-4d43-9234-367a0744180d','建隆乾德朝會樂章二十八首 又六變。 其五','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','席卷定巴邛，西遐盡率從。',48,'全唐诗/poet.song.250000.json','["席卷定巴邛，西遐盡率從。", "岷峨難負阻，江漢自朝宗。", "述職方舟集，驅車九折通。", "粲然書國史，冠古耀豐功。"]'),
('35e44ebd-0071-4465-ae2e-5f63706035a8','建隆乾德朝會樂章二十八首 又六變。 其六','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','銳旅慶回旋，邊防盡晏然。',48,'全唐诗/poet.song.250000.json','["銳旅慶回旋，邊防盡晏然。", "鍵櫜方偃武，飛將亦韜弦。", "震曜資平壘，文明協麗天。", "洸洸成大業，赫奕在青編。"]'),
('e198dde7-ff25-4f4d-8a56-dade85fdd92f','淳化中朝會二十三首 上壽用《和安》。 其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','四序伊始，三陽肇開。',40,'全唐诗/poet.song.250000.json','["四序伊始，三陽肇開。", "條風入律，玉琯飛灰。", "望雲肅謁，鳴佩斯來。", "稱觴獻壽，瞻拱星迴。"]'),
('74928c3d-b061-49fd-b303-81ed081b27d5','淳化中朝會二十三首 上壽用《和安》。 其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','一陽應候，萬國同文。',40,'全唐诗/poet.song.250000.json','["一陽應候，萬國同文。", "天正紀節，太史書雲。", "凝旒在御，列敘爰分。", "壽觴斯薦，祝慶明君。"]'),
('f3694f41-7370-4494-a863-ee0a4085d0be','淳化中朝會二十三首 皇帝初舉酒用《祥麟》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','聖皇御宇，仁獸誕彰。',40,'全唐诗/poet.song.250000.json','["聖皇御宇，仁獸誕彰。", "在郊旅貢，游畤呈祥。", "星辰是稟，草木無傷。", "紀異信史，登歌太常。"]'),
('1c1cc199-e4de-4ff8-a645-5c3abd34fb69','淳化中朝會二十三首 再舉酒用《丹鳳》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','九苞薦瑞，戴德膺仁。',40,'全唐诗/poet.song.250000.json','["九苞薦瑞，戴德膺仁。", "藻翰爰奮，靈音載振。", "非時不見，有道則臻。", "降岐匪匹，儀舜爲鄰。"]'),
('64838c2f-bbe8-4ee3-aad7-4f1c4b83e43f','淳化中朝會二十三首 三舉酒用《河清》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','沔彼涇瀆，澄明鑑如。',40,'全唐诗/poet.song.250000.json','["沔彼涇瀆，澄明鑑如。", "清應寶運，光涵帝居。", "洞分沈璧，徹見游魚。", "聖祚無極，神休偉與。"]'),
('1b528df8-4666-4069-8125-5bd761b0262a','淳化中朝會二十三首 四舉酒用《白龜》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','稽彼靈物，允昭聖皇。',40,'全唐诗/poet.song.250000.json','["稽彼靈物，允昭聖皇。", "浮石可躡，巢蓮益光。", "金方正色，介族殊祥。", "信書永耀，帝德無疆。"]'),
('0797dd4c-34d9-4f18-83fa-c7f8650f6c2e','淳化中朝會二十三首 五舉酒用《瑞麥》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','芃芃嘉麥，擢秀分岐。',40,'全唐诗/poet.song.250000.json','["芃芃嘉麥，擢秀分岐。", "甘露夕洒，惠風晨吹。", "良農告瑞，循吏稱奇。", "歸美英主，折而貢之。"]'),
('6f8313e4-87d1-4599-b825-16da0e57b8d9','淳化中朝會二十三首 羣臣初舉酒畢作《化成天下》。 其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','軒昊方同德，成康粗比肩。',48,'全唐诗/poet.song.250000.json','["軒昊方同德，成康粗比肩。", "素風惟普暢，皇道本無偏。", "陰魄重輪滿，陽精五色圓。", "要荒咸率服，卓越聖功全。"]'),
('03b709e9-2e5f-4545-a8cc-50d8939a36db','淳化中朝會二十三首 羣臣初舉酒畢作《化成天下》。 其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','聖德比陶唐，千年祚運昌。',48,'全唐诗/poet.song.250000.json','["聖德比陶唐，千年祚運昌。", "茂功雖不宰，鴻業自無疆。", "極塞成清謐，齊民益阜康。", "文明同日月，遐邇仰輝光。"]'),
('ac96757d-821c-4573-a702-7bd7d4e7daf9','淳化中朝會二十三首 又六變。 其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','蕩蕩無私世，巍巍至聖君。',48,'全唐诗/poet.song.250000.json','["蕩蕩無私世，巍巍至聖君。", "山河分國寶，日月耀人文。", "厭浥凝甘露，輪囷吐慶雲。", "正聲兼大雅，洋溢應南薰。"]'),
('bac91c15-41ff-4600-b92c-e5010af1bc85','淳化中朝會二十三首 又六變。 其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','鴻範合彝倫，調元四序均。',48,'全唐诗/poet.song.250000.json','["鴻範合彝倫，調元四序均。", "歲功天吏正，御苑物華新。", "底貢陳方物，來賓列遠人。", "奉常呈九奏，嘉貺動穹旻。"]'),
('c3cde3bf-2223-4573-99df-b445d75024d7','淳化中朝會二十三首 又六變。 其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','大君隆至化，興運契千齡。',48,'全唐诗/poet.song.250000.json','["大君隆至化，興運契千齡。", "覲禮俄班瑞，夷賨盡實庭。", "成文調露樂，奉聖拱辰星。", "舞佾方更進，朝陽上楚萍。"]'),
('c26b3c5c-3cb4-4807-9ac6-6320143a40d2','淳化中朝會二十三首 又六變。 其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','禮樂昭王業，寰區致太平。',48,'全唐诗/poet.song.250000.json','["禮樂昭王業，寰區致太平。", "革車停北狩，雲稼屢西成。", "國有詳延詔，鄉聞講誦聲。", "日華融五色，遐邇仰文明。"]'),
('40243620-eb75-4127-b893-0aff6c64bb13','淳化中朝會二十三首 又六變。 其五','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','亭障戢干戈，人心浹太和。',48,'全唐诗/poet.song.250000.json','["亭障戢干戈，人心浹太和。", "務農登寶穀，獵俊設雲羅。", "儀鳳書良史，祥麟載雅歌。", "嘉辰資宴喜，星拱弁峨峨。"]'),
('f2549022-04e2-43aa-abc6-ce9e9cb1c538','淳化中朝會二十三首 又六變。 其六','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','冠古耀鴻徽，深仁及隠微。',48,'全唐诗/poet.song.250000.json','["冠古耀鴻徽，深仁及隠微。", "二南江漢詠，九奏鳳凰飛。", "設虡羅鐘律，盈庭列舞衣。", "文明資厚德，怡懌兆民歸。"]'),
('5f715750-f22e-41a5-8bf2-11cda9f480c0','淳化中朝會二十三首 再舉酒畢用《威加海內》。 其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','革輅征汾晉，隳城比燎毛。',48,'全唐诗/poet.song.250000.json','["革輅征汾晉，隳城比燎毛。", "桓桓勗軍旅，將將御英豪。", "神武誠無敵，天威詎可逃。", "王師宣利澤，霈若沃春膏。"]'),
('499e1d43-0185-41f2-bd76-04c15ee658a6','淳化中朝會二十三首 再舉酒畢用《威加海內》。 其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','振萬方明德，疾徐咸可觀。',48,'全唐诗/poet.song.250000.json','["振萬方明德，疾徐咸可觀。", "鏗鏘動金奏，蹈厲總朱干。", "夾進昭威武，申嚴警宴安。", "守方推猛士，當用鶡爲冠。"]'),
('f40f8f93-95ca-4ebc-a28e-bcc3c7bdd492','淳化中朝會二十三首 又六變。 其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','宣榭始觀兵，桓桓稱鼓行。',48,'全唐诗/poet.song.250000.json','["宣榭始觀兵，桓桓稱鼓行。", "一戎期大定，載纘議徂征。", "善政從師律，神功冀武成。", "勗哉勤誓衆，王業自經營。"]'),
('e4e590af-45d1-45f7-ba96-324d92e14980','淳化中朝會二十三首 又六變。 其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','聲教方柔遠，甌閩禮可招。',48,'全唐诗/poet.song.250000.json','["聲教方柔遠，甌閩禮可招。", "獻圖連日際，歸國象江潮。", "撫運重熙盛，提封萬里遥。", "還同有虞氏，文德格三苗。"]'),
('08f4f3a1-89fd-4c99-85f6-b5fe9280987c','淳化中朝會二十三首 又六變。 其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','南暨宣皇化，東吳奉乃神。',48,'全唐诗/poet.song.250000.json','["南暨宣皇化，東吳奉乃神。", "舞干方耀德，執玉自來賓。", "巢伯朝丹陛，韓侯覲紫宸。", "古今歸一揆，懷遠道彌新。"]'),
('8898b3b1-d24c-4ef4-8d97-b4f9fa1225ab','淳化中朝會二十三首 又六變。 其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','遺俗續陶唐，來蘇徯聖皇。',48,'全唐诗/poet.song.250000.json','["遺俗續陶唐，來蘇徯聖皇。", "布昭湯弔伐，恢復漢封疆。", "金鉞申戡剪，朱干示發揚。", "宜哉七德頌，千載播洋洋。"]'),
('49850d06-45b9-47cf-89aa-15317570dd8c','淳化中朝會二十三首 又六變。 其五','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','乃眷嘗西顧，偏師暫首征。',48,'全唐诗/poet.song.250000.json','["乃眷嘗西顧，偏師暫首征。", "靈旗方直指，獷俗自亡精。", "禹敘終馴致，堯封漸化成。", "不須嚴尉候，於廓海彌清。"]'),
('14114164-d380-4c42-9a58-738ac731894a','淳化中朝會二十三首 又六變。 其六','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','干戚有司傳，威容著凱旋。',48,'全唐诗/poet.song.250000.json','["干戚有司傳，威容著凱旋。", "象成王業盛，役輟武功全。", "兵寢西郊閲，書惟北闕縣。", "聖神膺景命，卜世萬斯年。"]'),
('e18c898d-f4b1-4d1e-b48d-b7f82439c607','景德中朝會十四首 皇帝升坐用《隆安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','金奏在庭，羣后在位。',40,'全唐诗/poet.song.250000.json','["金奏在庭，羣后在位。", "天威煌煌，嚮明負扆。", "高拱穆清，弁冕端委。", "盛德日新，禮容有煒。"]'),
('a3c0b237-6a43-4943-883a-f07f75bd54b4','景德中朝會十四首 公卿入門用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','萬邦來同，九賓在位。',40,'全唐诗/poet.song.250000.json','["萬邦來同，九賓在位。", "奉璋薦紳，陟降庭止。", "文思安安，威儀棣棣。", "臣哉鄰哉，介爾蕃祉。"]'),
('ef874d91-7f6e-4b8f-8253-ff058f0616d9','景德中朝會十四首 上壽用《和安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','天威煌煌，山龍采章。',40,'全唐诗/poet.song.250000.json','["天威煌煌，山龍采章。", "庭實旅百，上公奉觴。", "拱揖羣后，端委垂裳。", "永錫難老，萬壽無疆。"]'),
('275722a4-4903-4d2b-86e4-20b59602a983','景德中朝會十四首 皇帝初舉酒用《祥麟》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','帝圖會昌，二獸效祥。',40,'全唐诗/poet.song.250000.json','["帝圖會昌，二獸效祥。", "雙角共觝，示武不傷。", "四靈爲畜，玄枵耀芒。", "公族信厚，元元阜康。"]'),
('3fc06485-e8e0-4b02-ab5f-cf7a9f4efa46','景德中朝會十四首 再舉酒用《丹鳳》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','矯矯長離，振羽來儀。',40,'全唐诗/poet.song.250000.json','["矯矯長離，振羽來儀。", "和音中律，藻翰揚輝。", "珍符沓至，品物攸宜。", "至德玄感，受天之祺。"]'),
('d203ba9f-6ea2-4bb9-bf29-0c83854b4b2c','景德中朝會十四首 三舉酒用《河清》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','德水湯湯，發源靈長。',40,'全唐诗/poet.song.250000.json','["德水湯湯，發源靈長。", "皎鑒澄徹，千年效祥。", "積厚流濕，資生阜昌。", "朝宗潤下，善利無疆。"]'),
('c36bc7ab-6377-48c7-8942-9217a16ec63f','景德中朝會十四首 羣臣舉酒用《正安》。 其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','思皇多士，靖恭著位。',40,'全唐诗/poet.song.250000.json','["思皇多士，靖恭著位。", "鳴玉飛緌，鏘鏘濟濟。", "宴有折俎，以示慈惠。", "罔敢不祗，福祿來暨。"]'),
('a60fe2a6-5c65-4772-81ea-cbd31bb2eff2','景德中朝會十四首 羣臣舉酒用《正安》。 其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','金奏在庭，有酒斯旨。',40,'全唐诗/poet.song.250000.json','["金奏在庭，有酒斯旨。", "顒顒卬卬，嚮明負扆。", "湛湛露斯，式宴以喜。", "佩玉蘂兮，罔不由禮。"]'),
('1a1b1bbd-a097-43d8-a1e3-1c0acc37590b','景德中朝會十四首 羣臣舉酒用《正安》。 其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','酒以成禮，樂以侑食。',40,'全唐诗/poet.song.250000.json','["酒以成禮，樂以侑食。", "露湛朝陽，星環紫極。", "淑慎爾容，既飽以德。", "進退周旋，威儀抑抑。"]'),
('da2ebe1d-1f79-4544-af16-b3e8258caf2b','景德中朝會十四首 初舉酒畢用《盛德升聞》。 其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','八佾具呈，萬舞有奕。',40,'全唐诗/poet.song.250000.json','["八佾具呈，萬舞有奕。", "既以象功，又以觀德。", "進旅退旅，執籥秉翟。", "至化懷柔，遠人來格。"]'),
('65c0392a-8846-4fea-b8ea-6b252bdbfcd9','景德中朝會十四首 初舉酒畢用《盛德升聞》。 其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','閶闔天開，羣后在位。',40,'全唐诗/poet.song.250000.json','["閶闔天開，羣后在位。", "設業設虡，庭燎晰晰。", "斧扆當陽，虎賁夾陛。", "舞之蹈之，四隩來暨。"]'),
('40265bf5-9f60-400f-92d3-1c147615997e','景德中朝會十四首 再舉酒畢用《天下大定》。 其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','武功既成，綴兆有翼。',40,'全唐诗/poet.song.250000.json','["武功既成，綴兆有翼。", "以節八音，以象七德。", "俁俁蹲蹲，朱干玉戚。", "發揚蹈厲，其儀不忒。"]'),
('e483e518-2a8b-4b6d-8524-57208bef0971','景德中朝會十四首 再舉酒畢用《天下大定》。 其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','偃伯靈臺，功成作樂。',40,'全唐诗/poet.song.250000.json','["偃伯靈臺，功成作樂。", "以昭德容，以清戎索。", "萬邦會同，邪慝銷鑠。", "盡善盡美，侔彼韶箾。"]'),
('b60f5709-ad65-4b09-ab11-9827c0b79633','景德中朝會十四首 降坐用《隆安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','被衮當陽，穆穆皇皇。',40,'全唐诗/poet.song.250000.json','["被衮當陽，穆穆皇皇。", "擊石拊石，頌聲揚揚。", "和樂優洽，終然允臧。", "禮成而退，荷天百祥。"]'),
('ea2cf47e-373e-48dc-ae6f-3bd86a3a017e','大中祥符朝會五首 皇帝舉酒用《醴泉》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','觱沸檻泉，寒流清泚。',40,'全唐诗/poet.song.250000.json','["觱沸檻泉，寒流清泚。", "地不愛寶，其旨如醴。", "上善至柔，靈休所啟。", "利澤無疆，允資岱禮。"]'),
('599c7995-7e39-46bf-b6d0-0830fc1eec0e','大中祥符朝會五首 再舉酒用《神芝》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','彼茁者芝，茂英煌煌。',40,'全唐诗/poet.song.250000.json','["彼茁者芝，茂英煌煌。", "敷秀喬嶽，寔繁其房。", "適符修貢，封巒允臧。", "永言登薦，抑惟舊章。"]'),
('3683f4d9-a989-403e-ab78-1303fd291292','大中祥符朝會五首 三舉酒用《慶雲》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','惟帝佑德，卿雲發祥。',40,'全唐诗/poet.song.250000.json','["惟帝佑德，卿雲發祥。", "紛紛郁郁，五色成章。", "奉日逾麗，回風載翔。", "歌薦郊廟，播厥無疆。"]'),
('1f6ddd73-45c2-4b07-943f-2369c3113401','大中祥符朝會五首 四舉酒用《靈鶴》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','玄文申錫，嘉祥紹至。',40,'全唐诗/poet.song.250000.json','["玄文申錫，嘉祥紹至。", "偉茲胎禽，羽族之異。", "翻翰來儀，徘徊嘹唳。", "祚聖儲休，聿昭天意。"]'),
('2f27a223-0d86-47a7-b735-5a8bf8e27b05','大中祥符朝會五首 五舉酒用《瑞木》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','天生五材，木曰曲直。',40,'全唐诗/poet.song.250000.json','["天生五材，木曰曲直。", "維帝順天，厚其生植。", "連理效祥，成文表德。", "總萃坤珍，永光祕刻。"]'),
('6a23f2d8-0005-4987-bb3c-69020c2cabf8','熙寧中朝會三首 皇帝初舉酒用《慶雲》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','乾坤順夷，皇有嘉德。',40,'全唐诗/poet.song.250000.json','["乾坤順夷，皇有嘉德。", "爰施慶雲，承日五色。", "輪囷下乘，萬物皆飾。", "惟天祚休，長彼無極。"]'),
('ffed059d-8558-4bc7-bb3c-a374230691d4','熙寧中朝會三首 再舉酒用《嘉禾》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','彼美嘉禾，一莖九穗。',40,'全唐诗/poet.song.250000.json','["彼美嘉禾，一莖九穗。", "農疇告祥，史牒書瑞。", "擊壤歡歌，如京委積。", "留獻春種，昭錫善類。"]'),
('a4d6bbd2-a230-4aa9-9739-8dc7c49a942d','熙寧中朝會三首 三舉酒用《靈芝》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','皇仁溥博，品物蕃滋。',40,'全唐诗/poet.song.250000.json','["皇仁溥博，品物蕃滋。", "慶祥回復，秀發神芝。", "靈華雙舉，連葉四施。", "披圖按牒，永享純禧。"]'),
('8b84a541-d577-44bd-9bfd-4ab450f4b360','元符大朝會三首 皇帝初舉酒用《靈芝》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','嘉瑞降臨，應我皇德。',40,'全唐诗/poet.song.250000.json','["嘉瑞降臨，應我皇德。", "燁燁神芝，不根而植。", "春秋三秀，晝夜一色。", "物播詩歌，聲被金石。"]'),
('68307c05-11b5-46b0-8256-4959e8b654ca','元符大朝會三首 再舉酒用《壽星》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','倬彼星象，於昭于天。',40,'全唐诗/poet.song.250000.json','["倬彼星象，於昭于天。", "維南有極，離丙之躔。", "既明且大，應聖乘乾。", "誕受景福，億萬斯年。"]'),
('eca5d9fe-b092-44b7-9b86-8efb7c2e5cf3','元符大朝會三首 三舉酒用《甘露》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','泫泫零露，雲英醴溢。',40,'全唐诗/poet.song.250000.json','["泫泫零露，雲英醴溢。", "和氣凝津，流甘委白。", "飴泛泮林，珠聯竹柏。", "天不愛道，聖功允格。"]'),
('7b2db395-7fb0-44c8-91bf-0d0a71f37304','哲宗傳受國寶三首','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於穆我王，繼序不忘。',40,'全唐诗/poet.song.250000.json','["於穆我王，繼序不忘。", "明昭上帝，上帝是皇。", "長發其祥，惠我無疆。", "受命于天，既壽永昌。"]'),
('c188b005-8d1d-4111-8c13-c8238291a666','哲宗傳受國寶三首 《神光》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','惟皇上德，伊嘏我王。',40,'全唐诗/poet.song.250000.json','["惟皇上德，伊嘏我王。", "將受厥明，載錫之光。", "於昭于天，曄曄煌煌。", "緝熙欽止，其永無疆。"]'),
('4a94cfb5-682d-498f-90c9-2f24391f251a','哲宗傳受國寶三首 《翔鶴》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','彼鳴在陰，亦白其羽。',40,'全唐诗/poet.song.250000.json','["彼鳴在陰，亦白其羽。", "聲聞于天，來集斯所。", "勉勉我王，咸遂厥宇。", "播于異物，受天多祜。"]'),
('0b2dd085-3268-4769-8726-2bafd9dbf363','紹興朝會十三首 皇帝升坐用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','鈎陳肅列，金奏充庭。',40,'全唐诗/poet.song.250000.json','["鈎陳肅列，金奏充庭。", "顒卬南面，如日之昇。", "垂衣拱手，治無能名。", "順履獻歲，大安大榮。"]'),
('cc3fa081-6544-49d2-84c6-7ec875f16e09','紹興朝會十三首 公卿入門用《正安》。升降同。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','天子當陽，臣工率職。',40,'全唐诗/poet.song.250000.json','["天子當陽，臣工率職。", "流水朝宗，衆星拱極。", "環佩鏘鏘，威儀抑抑。", "上下交欣，同心同德。"]'),
('5f1d1e15-b897-4928-9e2f-42a008c80b81','紹興朝會十三首 上公上壽用《和安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','八音克諧，萬舞有奕。',40,'全唐诗/poet.song.250000.json','["八音克諧，萬舞有奕。", "上公奉觴，率茲百辟。", "聲效呼嵩，祝聖人壽。", "億載萬年，天長地久。"]'),
('97f5581d-b6ea-43c9-8cec-21ab9fe79055','紹興朝會十三首 皇帝初舉酒用《瑞木成文》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','厚地效珍，嘉木紀瑞。',40,'全唐诗/poet.song.250000.json','["厚地效珍，嘉木紀瑞。", "匪刻匪雕，具文見意。", "三登太平，允協聖治。", "詩雅詠歌，有光既醉。"]'),
('22f5c8fa-d229-46ff-a0a2-83249312ad3b','紹興朝會十三首 再舉酒用《滄海澄清》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','百谷王，符聖治。',32,'全唐诗/poet.song.250000.json','["百谷王，符聖治。", "不揚波，效殊祉。", "德淪淵，滄海清。", "應千秋，敘五行。"]'),
('b6b6f74b-a231-4ffe-bf53-7ea50a95979f','紹興朝會十三首 三舉酒用《瑞粟呈祥》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','至治發聞惟馨香，播厥百穀臻穰穰。',64,'全唐诗/poet.song.250000.json','["至治發聞惟馨香，播厥百穀臻穰穰。", "農夫之慶歲其有，禾易長畝盈倉箱。", "時和物阜粟滋茂，嘉生駢穗來呈祥。", "自今以始大豐美，行旅不用齎餱糧。"]'),
('366c605e-3cab-43c2-85cf-669b214225eb','紹興朝會十三首 羣臣酒行用《正安》。 其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','羣公卿士，咸造在庭。',40,'全唐诗/poet.song.250000.json','["羣公卿士，咸造在庭。", "式燕以衎，思均露零。", "穆穆明明，於斯爲盛。", "歸美報上，一人有慶。"]'),
('575cffe7-617f-48fb-9885-e8daa81a4c08','紹興朝會十三首 羣臣酒行用《正安》。 其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','明明天子，萬福來同。',40,'全唐诗/poet.song.250000.json','["明明天子，萬福來同。", "嘉賓式燕，曷不肅雍。", "燕以示慈，式禮莫愆。", "樂胥君子，容止可觀。"]'),
('f32078d4-84aa-4e67-9711-32f06e755ce1','紹興朝會十三首 酒一行用文舞。 其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','帝德誕敷，銷爍羣慝。',40,'全唐诗/poet.song.250000.json','["帝德誕敷，銷爍羣慝。", "近悅遠來，惟聖時克。", "玉振金聲，治功興起。", "韶箾象之，盡善盡美。"]'),
('0a78ea34-e2ef-47af-8f9f-5e1ec2923a7f','紹興朝會十三首 酒一行用文舞。 其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','文物以紀，藻色以明。',40,'全唐诗/poet.song.250000.json','["文物以紀，藻色以明。", "禮備樂舉，遹觀厥成。", "睿知有臨，誕敷文德。", "教雨化風，洽此四國。"]'),
('932c1790-958f-460d-95e7-a6d65ebb3100','紹興朝會十三首 酒載行用武舞。 其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','用戒不虞，誰能去兵。',40,'全唐诗/poet.song.250000.json','["用戒不虞，誰能去兵。", "師出以律，動必有名。", "折彼遐衝，布昭聖武。", "和衆安民，時惟多助。"]'),
('1b563ce3-fe23-4d15-99fd-15bc1660dd88','紹興朝會十三首 酒載行用武舞。 其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','止戈曰武，惟聖爲能。',40,'全唐诗/poet.song.250000.json','["止戈曰武，惟聖爲能。", "御得其道，無敢不庭。", "整我六師，稽諸七德。", "不吳不揚，有嚴有翼。"]'),
('ff55ebb8-b9b4-4762-b766-c36729ea7610','紹興朝會十三首 皇帝降坐用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','帝坐熒煌，廷紳肅穆。',40,'全唐诗/poet.song.250000.json','["帝坐熒煌，廷紳肅穆。", "對揚天休，各恭爾服。", "頌聲洋洋，彌文郁郁。", "禮備樂成，永膺多福。"]'),
('0758c3c2-56a8-42a1-bf57-e53a8db9d5b1','建隆御樓三首《宋史·樂志》一：乾德六年，和峴言：按《開元禮》，郊祀，車駕還宮，入嘉德門奏《采茨之樂》，入太極門奏《太和之樂》。今郊祀禮畢，登樓肆赦然後還宮，宮縣但用《隆安》，不用《采茨》，其《隆安》樂章本是御殿之辭。伏詳《禮》意，《隆安之樂》自內而出，《采茨之樂》自外而入，若不並用，有失舊典。羣從之。 南郊回仗駕至樓前用《采茨》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','高煙升太一，明祀達乾坤。',48,'全唐诗/poet.song.250000.json','["高煙升太一，明祀達乾坤。", "天仗回嶢闕，皇輿入應門。", "簪裳如霧集，車騎若雲屯。", "兆庶皆翹首，巍巍萬乘尊。"]'),
('49fba076-d5a3-4289-b53f-6ce2e872c94b','建隆御樓三首《宋史·樂志》一：乾德六年，和峴言：按《開元禮》，郊祀，車駕還宮，入嘉德門奏《采茨之樂》，入太極門奏《太和之樂》。今郊祀禮畢，登樓肆赦然後還宮，宮縣但用《隆安》，不用《采茨》，其《隆安》樂章本是御殿之辭。伏詳《禮》意，《隆安之樂》自內而出，《采茨之樂》自外而入，若不並用，有失舊典。羣從之。 升坐用《隆安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','禋祀畢圓丘，嘉辰慶澤流。',48,'全唐诗/poet.song.250000.json','["禋祀畢圓丘，嘉辰慶澤流。", "天儀臨觀魏，盛禮藹風猷。", "洋溢歡聲動，氛氳瑞氣浮。", "上穹垂眷佑，邦國擁鴻休。"]'),
('bb785a69-081b-4eb1-bb52-43019242ac87','建隆御樓三首《宋史·樂志》一：乾德六年，和峴言：按《開元禮》，郊祀，車駕還宮，入嘉德門奏《采茨之樂》，入太極門奏《太和之樂》。今郊祀禮畢，登樓肆赦然後還宮，宮縣但用《隆安》，不用《采茨》，其《隆安》樂章本是御殿之辭。伏詳《禮》意，《隆安之樂》自內而出，《采茨之樂》自外而入，若不並用，有失舊典。羣從之。 降坐用《隆安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','華纓就列，左衽來王。',40,'全唐诗/poet.song.251000.json','["華纓就列，左衽來王。", "帝儀炳煥，大樂鏗鏘。", "禮成嶢闕，言旋未央。", "一人有慶，萬壽無疆。"]'),
('5f6b294e-779c-4482-9a16-98e4b4169a4c','咸平御樓四首 《采茨》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','禮成于郊，迎日之至。',40,'全唐诗/poet.song.251000.json','["禮成于郊，迎日之至。", "時乘六龍，天旋象魏。", "端門九重，虎賁萬騎。", "四夷來王，羣后輯瑞。"]'),
('279d5685-4570-4917-beb2-e9802df6b31a','咸平御樓四首 索扇用《隆安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','應門有翼，羽衛斯陳。',40,'全唐诗/poet.song.251000.json','["應門有翼，羽衛斯陳。", "山龍衮冕，律度聲身。", "峨峨奉璋，肅肅九賓。", "清明在躬，志氣如神。"]'),
('64733d58-7c6f-443a-ac65-a1b5f2717e9b','咸平御樓四首 升坐用《隆安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','圜丘類上帝，六變降天神。',48,'全唐诗/poet.song.251000.json','["圜丘類上帝，六變降天神。", "禋燔禮云畢，仗衛肅以陳。", "天顔瞻咫尺，王澤熙陽春。", "玉帛臻禹會，動植霑堯仁。"]'),
('8828b839-2f1d-4a74-8782-3971b9dc261f','咸平御樓四首 降坐用《隆安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','肆眚云畢，淳熙溥將。',40,'全唐诗/poet.song.251000.json','["肆眚云畢，淳熙溥將。", "雷雨麗澤，雲物效祥。", "禮容濟濟，天威皇皇。", "大賚四海，富壽無疆。"]'),
('6d2dda0a-bff4-4319-a5c2-e63fb7b6794c','咸平藉田回仗御樓二首 《采茨》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','農皇既祀，禮畢躬耕。',40,'全唐诗/poet.song.251000.json','["農皇既祀，禮畢躬耕。", "商輅旋軫，周頌騰聲。", "觀魏將陟，服御爰更。", "輿人瞻仰，如日之明。"]'),
('ab5645da-d514-4d64-88de-b3f253f59b9a','咸平藉田回仗御樓二首 升坐用《隆安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','應門斯御，雉扇爰開。',40,'全唐诗/poet.song.251000.json','["應門斯御，雉扇爰開。", "人瞻日月，澤動雲雷。", "同風三代，均禧九垓。", "歡心允洽，時詠康哉。"]'),
('4608ce27-008f-400f-bf83-3e8353a280f2','乾興御樓二首 升坐用《隆安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','夾鐘紀月，初吉在辰。',40,'全唐诗/poet.song.251000.json','["夾鐘紀月，初吉在辰。", "眚災流慶，布德推仁。", "采章震耀，典禮具陳。", "茂昭丕貺，永庇斯民。"]'),
('06dcde92-2892-459e-ae6b-c88669fd3b5d','乾興御樓二首 降坐用《隆安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','皇衢赫敞，黼坐穹崇。',40,'全唐诗/poet.song.251000.json','["皇衢赫敞，黼坐穹崇。", "華纓在列，嚴令發中。", "王制鉅麗，寶瑞豐融。", "均禧綿宇，萬壽無窮。"]'),
('749c8afc-9b61-416e-a41a-137e06fad17d','紹興登門肆赦二首 升坐用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','拜况于郊，皇哉唐哉。',40,'全唐诗/poet.song.251000.json','["拜况于郊，皇哉唐哉。", "熙事休成，六騑鼎來。", "天閫以决，地垠以開。", "隤祉發祥，如登春臺。"]'),
('0b203717-8dc1-4472-acb0-a08d6cfd888f','紹興登門肆赦二首 降坐用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','鴻霈普洽，言歸端門。',40,'全唐诗/poet.song.251000.json','["鴻霈普洽，言歸端門。", "蕩蕩巍巍，旋乾轉坤。", "穆然宣室，儲思垂恩。", "於萬斯年，敷錫羣元。"]'),
('5d27c40e-f575-44e6-8777-8a9794d72266','寧宗登門肆赦二首 升坐用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','帝饗于郊，荷天之休。',40,'全唐诗/poet.song.251000.json','["帝饗于郊，荷天之休。", "五福敷錫，皇明燭幽。", "雲行雨施，仁翔德游。", "聖人多男，歌頌九州。"]'),
('b57f179b-f889-4148-a6ab-483c57fc2432','寧宗登門肆赦二首 降坐用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','天日清晏，朝野靖安。',40,'全唐诗/poet.song.251000.json','["天日清晏，朝野靖安。", "三靈答祉，萬國騰懽。", "帝命不違，王業艱難。", "天子萬年，永迪監觀。"]'),
('60ffd877-e206-44e7-ae89-b54ccdf72b51','皇帝上尊號一首 冊寶入門用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於穆元后，天臨紫宸。',40,'全唐诗/poet.song.251000.json','["於穆元后，天臨紫宸。", "飛緌星拱，建羽林芬。", "徽冊是奉，鴻名愈新。", "荷茲介祉，永永無垠。"]'),
('9658e51a-dd51-4273-be24-0c1422cbd349','明道元年章獻明肅皇太后朝會十五首《宋史·樂志》一：明道初，章獻皇太后御前殿見群臣，作《玉芝》《壽星》《奇木連理》之曲，《厚德無疆》《四海會同》之舞。 皇太后升坐用《聖安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','聖母有子，重光類禋。',40,'全唐诗/poet.song.251000.json','["聖母有子，重光類禋。", "聖皇事母，感極天人。", "百辟在庭，九儀具陳。", "禮容之盛，萬國咸賓。"]'),
('3413d047-8ed9-4dbb-b0b6-a5a7bf1e51dc','明道元年章獻明肅皇太后朝會十五首《宋史·樂志》一：明道初，章獻皇太后御前殿見群臣，作《玉芝》《壽星》《奇木連理》之曲，《厚德無疆》《四海會同》之舞。 公卿入門用《禮安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','帝率四海，承顔盡恭。',40,'全唐诗/poet.song.251000.json','["帝率四海，承顔盡恭。", "端闈肅設，羣后來同。", "玉佩鏘鳴，衣冠有容。", "英韶節步，磬管雍雍。"]'),
('1c21d8f1-0651-4de2-a3ad-08c1d1c5417e','明道元年章獻明肅皇太后朝會十五首《宋史·樂志》一：明道初，章獻皇太后御前殿見群臣，作《玉芝》《壽星》《奇木連理》之曲，《厚德無疆》《四海會同》之舞。 皇帝上壽酒用《崇安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','天子之德，形于四方。',40,'全唐诗/poet.song.251000.json','["天子之德，形于四方。", "尊親立愛，化洽風揚。", "聖母褘衣，明君黼裳。", "因時獻壽，克盛朝章。"]'),
('34b0ea6f-8f2e-49e2-a1a3-4584e348c38b','明道元年章獻明肅皇太后朝會十五首《宋史·樂志》一：明道初，章獻皇太后御前殿見群臣，作《玉芝》《壽星》《奇木連理》之曲，《厚德無疆》《四海會同》之舞。 上壽用《福安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','盛禮煌煌，六衣有光。',40,'全唐诗/poet.song.251000.json','["盛禮煌煌，六衣有光。", "千官在位，百福稱觴。", "坤德慈仁，邦斯淑祥。", "如山之壽，佑聖無疆。"]'),
('a0deb8b6-cfac-43a4-a54f-e15a07462442','明道元年章獻明肅皇太后朝會十五首《宋史·樂志》一：明道初，章獻皇太后御前殿見群臣，作《玉芝》《壽星》《奇木連理》之曲，《厚德無疆》《四海會同》之舞。 皇太后初舉酒用《玉芝》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','燁燁靈芝，生于殿闈。',40,'全唐诗/poet.song.251000.json','["燁燁靈芝，生于殿闈。", "照映華拱，紛敷玉蕤。", "感召元和，光符聖期。", "祥篇協吉，百福咸宜。"]'),
('e5f9d56c-6277-40f2-9450-fcc7564c2551','明道元年章獻明肅皇太后朝會十五首《宋史·樂志》一：明道初，章獻皇太后御前殿見群臣，作《玉芝》《壽星》《奇木連理》之曲，《厚德無疆》《四海會同》之舞。 再舉酒用《壽星》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','現彼南極，昭然瑞文。',40,'全唐诗/poet.song.251000.json','["現彼南極，昭然瑞文。", "騰光丙位，薦壽中宸。", "太史駢奏，升歌有聞。", "軒宮就養，億萬斯春。"]'),
('6f003f9f-b99b-4ae0-846c-3ca3465f0ff7','明道元年章獻明肅皇太后朝會十五首《宋史·樂志》一：明道初，章獻皇太后御前殿見群臣，作《玉芝》《壽星》《奇木連理》之曲，《厚德無疆》《四海會同》之舞。 三舉酒用《奇木連理》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','王化無外，坤珍效靈。',40,'全唐诗/poet.song.251000.json','["王化無外，坤珍效靈。", "旁枝內附，直幹來并。", "羣分非一，祺祥紹登。", "至誠攸感，海縣斯寧。"]'),
('1df5fe1c-0d18-447d-b7c2-ae4541066ece','明道元年章獻明肅皇太后朝會十五首《宋史·樂志》一：明道初，章獻皇太后御前殿見群臣，作《玉芝》《壽星》《奇木連理》之曲，《厚德無疆》《四海會同》之舞。 羣臣酒行用《禮安》。 其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','肅肅臨下，有威有容。',40,'全唐诗/poet.song.251000.json','["肅肅臨下，有威有容。", "循循事上，惟信惟忠。", "盛禮興樂，示慈訓恭。", "君臣協吉，惟道之從。"]'),
('e9256748-30c2-4ee0-8de8-0bea6448a8b9','明道元年章獻明肅皇太后朝會十五首《宋史·樂志》一：明道初，章獻皇太后御前殿見群臣，作《玉芝》《壽星》《奇木連理》之曲，《厚德無疆》《四海會同》之舞。 羣臣酒行用《禮安》。 其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','湛湛零露，晞于載陽。',40,'全唐诗/poet.song.251000.json','["湛湛零露，晞于載陽。", "我有旨酒，羣臣樂康。", "既飲以德，亦圖爾良。", "永言修輔，用協天常。"]'),
('43a73877-1f81-4c2f-8f08-4bfcf8d87a6d','明道元年章獻明肅皇太后朝會十五首《宋史·樂志》一：明道初，章獻皇太后御前殿見群臣，作《玉芝》《壽星》《奇木連理》之曲，《厚德無疆》《四海會同》之舞。 羣臣酒行用《禮安》。 其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','禮均孝慈，樂合韶武。',40,'全唐诗/poet.song.251000.json','["禮均孝慈，樂合韶武。", "至德光矣，鴻恩亦溥。", "上下和濟，華夷樂湑。", "醆斝三行，盛儀斯舉。"]'),
('7666837c-e916-4c16-b001-bdf31d0228ba','明道元年章獻明肅皇太后朝會十五首《宋史·樂志》一：明道初，章獻皇太后御前殿見群臣，作《玉芝》《壽星》《奇木連理》之曲，《厚德無疆》《四海會同》之舞。 酒一行畢作《厚德無疆之舞》。 其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','堯母之聖，放勛爲子。',40,'全唐诗/poet.song.251000.json','["堯母之聖，放勛爲子。", "同心協謀，柔遠能邇。", "以德康俗，以文興治。", "斯焉象功，罔不昭濟。"]'),
('b8ec02b6-9b57-43d0-9559-02e7c89c3986','明道元年章獻明肅皇太后朝會十五首《宋史·樂志》一：明道初，章獻皇太后御前殿見群臣，作《玉芝》《壽星》《奇木連理》之曲，《厚德無疆》《四海會同》之舞。 酒一行畢作《厚德無疆之舞》。 其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','至矣坤元，道符惟聖。',40,'全唐诗/poet.song.251000.json','["至矣坤元，道符惟聖。", "就養宸極，助隆善政。", "翟籥紛舉，笙鏞協應。", "翱翔有容，表德之盛。"]'),
('a4174009-9ed2-44d9-9c8e-f384cb778abd','明道元年章獻明肅皇太后朝會十五首《宋史·樂志》一：明道初，章獻皇太后御前殿見群臣，作《玉芝》《壽星》《奇木連理》之曲，《厚德無疆》《四海會同》之舞。 酒再行作《四海會同之舞》。 其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','七德之舞，四朝用康。',40,'全唐诗/poet.song.251000.json','["七德之舞，四朝用康。", "有如姬姒，助集周邦。", "威克厥愛，居安不忘。", "風旋山立，濟濟皇皇。"]'),
('0981a168-dbb3-49f3-82ff-5c7c3a192d6f','明道元年章獻明肅皇太后朝會十五首《宋史·樂志》一：明道初，章獻皇太后御前殿見群臣，作《玉芝》《壽星》《奇木連理》之曲，《厚德無疆》《四海會同》之舞。 酒再行作《四海會同之舞》。 其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','左秉朱干，右揮玉戚。',40,'全唐诗/poet.song.251000.json','["左秉朱干，右揮玉戚。", "以象武綴，以明皇德。", "天子榮養，羣臣述職。", "四夷賓附，罔不承式。"]'),
('c5aaae65-54e6-4114-aadd-aca259b2831a','明道元年章獻明肅皇太后朝會十五首《宋史·樂志》一：明道初，章獻皇太后御前殿見群臣，作《玉芝》《壽星》《奇木連理》之曲，《厚德無疆》《四海會同》之舞。 降坐用《聖安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','長樂居尊，盛容有煒。',40,'全唐诗/poet.song.251000.json','["長樂居尊，盛容有煒。", "文王事親，萬國歸美。", "朝會之則，邦家之紀。", "受福于天，克昭隆禮。"]'),
('4fa5b130-379e-4b10-b572-1d47cc70c9ca','治平皇太后皇后冊寶三首 皇帝升坐用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','王化之始，治繇內孚。',40,'全唐诗/poet.song.251000.json','["王化之始，治繇內孚。", "時庸作命，玉簡金書。", "磬筦在庭，其縱繹如。", "天臨法扆，禮與誠俱。"]'),
('c0696434-1dcc-4554-9e16-2f323534b5f1','治平皇太后皇后冊寶三首 太尉等奉冊寶入門用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','晬儀臨拱，丕命明敭。',40,'全唐诗/poet.song.251000.json','["晬儀臨拱，丕命明敭。", "鸞回寶勢，鴻貫瑶光。", "禮成樂備，德裕名芳。", "肇基王化，永懋天祥。"]'),
('0e3d1f78-aa80-45c8-95a8-614196fd34e9','治平皇太后皇后冊寶三首 皇帝降坐用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','衮衣繡裳，嚴威肅莊。',40,'全唐诗/poet.song.251000.json','["衮衣繡裳，嚴威肅莊。", "八音具張，簨虡龍驤。", "玉簡瑶章，金書煌煌。", "壽千萬年，與天比長。"]'),
('29123b98-0e8b-45df-b7d4-33d84990b108','熙寧皇太后冊寶三首 出入用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','煌煌鳳字，玉氣宛延。',40,'全唐诗/poet.song.251000.json','["煌煌鳳字，玉氣宛延。", "天門崛岉，飛驂後先。", "龍簨四合，奏鼓淵淵。", "母儀天下，何千萬年。"]'),
('b709ea8e-b7c7-4d2e-8366-9d92bbbcc933','熙寧皇太后冊寶三首 升坐用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','峨峨繡扆，旋佩以登。',40,'全唐诗/poet.song.251000.json','["峨峨繡扆，旋佩以登。", "如彼杲日，凌天而升。", "玉色下照，亹亹繩繩。", "猗歟大孝，四海其承。"]'),
('d11d9b54-0627-4868-9a45-8cdabd56179b','熙寧皇太后冊寶三首 降坐用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','皇帝降席，流雲四開。',40,'全唐诗/poet.song.251000.json','["皇帝降席，流雲四開。", "堯趨舜步，下躡天階。", "恭授寶冊，翠旄裴回。", "明明純孝，鴻釐大來。"]'),
('4d6eb535-d8cf-4619-acfc-33fe7ce44c6e','哲宗上太皇太后冊寶五首 皇帝升坐用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','大矣孝熙，帥民以躬。',40,'全唐诗/poet.song.251000.json','["大矣孝熙，帥民以躬。", "奉承寶冊，欽明兩宮。", "萬樂具舉，一人肅雍。", "化繇上始，四海來同。"]'),
('3a681653-bebf-4316-b7e2-acda711355f0','哲宗上太皇太后冊寶五首 降坐用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','皇帝仁孝，總臨萬方。',40,'全唐诗/poet.song.251000.json','["皇帝仁孝，總臨萬方。", "褒顯其親，日嚴以莊。", "龍衮翼翼，玉書煌煌。", "傳之億世，休有烈光。"]'),
('75c63174-d974-438f-b8fe-5c5b6a45228d','哲宗上太皇太后冊寶五首 太皇太后升坐用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','總裁庶政，擁佑嗣皇。',40,'全唐诗/poet.song.251000.json','["總裁庶政，擁佑嗣皇。", "金書玉簡，爛其文章。", "衆歌警作，筦磬將將。", "保安四極，降福無疆。"]'),
('7b5a7e95-53d0-45c3-a4e6-12bc6c7cb1bb','哲宗上太皇太后冊寶五首 降坐用《乾安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','塗山之德，渭涘之祥。',40,'全唐诗/poet.song.251000.json','["塗山之德，渭涘之祥。", "圖徽寶冊，玉色金相。", "管弦燁煜，鐘鼓喤喤。", "天之所啟，既壽而昌。"]'),
('e5cc5b2c-2dc6-4ed8-a918-94f5632bf5d6','哲宗上太皇太后冊寶五首 太尉等奉冊寶出入門用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','玉車臨御，鳳蓋棽麗。',40,'全唐诗/poet.song.251000.json','["玉車臨御，鳳蓋棽麗。", "奉承寶冊，彌文盛儀。", "抗聲極律，助我孝熙。", "天之所佑，萬壽無期。"]'),
('f8107a50-a7d3-40b2-b5e0-c45c7c586c66','紹興十年發皇太后冊寶八首 皇帝隨冊寶降殿用《聖安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','景祚有開，符天媲昊。',40,'全唐诗/poet.song.251000.json','["景祚有開，符天媲昊。", "誕毓聖神，是崇位號。", "星拱天隨，祗嚴冊寶。", "還御慈寧，增光舜道。"]'),
('d521a7fd-78b7-47e4-9e15-deca0ea5a44e','紹興十年發皇太后冊寶八首 中書令奉冊詣皇帝褥位用《禮安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','聲樂備陳，禮容罔忒。',40,'全唐诗/poet.song.251000.json','["聲樂備陳，禮容罔忒。", "相維辟公，虔奉玉冊。", "皇則受之，慕形於色。", "既壽且康，與天無極。"]'),
('4084de81-f0b8-4323-b333-023558eaf0ac','紹興十年發皇太后冊寶八首 侍中奉寶詣皇帝褥位用《禮安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','祖啟瑶光，誕生明聖。',40,'全唐诗/poet.song.251000.json','["祖啟瑶光，誕生明聖。", "尊極母儀，帝庸作命。", "寶章煌煌，導以笙磬。", "還燕慈寧，邦家徯慶。"]'),
('385b0d19-aaf6-4e83-ab3a-dd5dbbd1eaff','紹興十年發皇太后冊寶八首 太傅奉冊寶出門用《聖安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','肅肅東朝，帝隆孝治。',40,'全唐诗/poet.song.251000.json','["肅肅東朝，帝隆孝治。", "猗歟丕稱，寶冊斯備。", "皇扉四闢，導迎慶瑞。", "德邁太任，有周卜世。"]'),
('7dced264-2896-4f53-a30a-3c0070317f54','紹興十年發皇太后冊寶八首 太傅奉冊寶入門用《聖安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','靜順坤儀，聖神是育。',40,'全唐诗/poet.song.251000.json','["靜順坤儀，聖神是育。", "懿鑠昭陳，鏤文華玉。", "樂奏既備，禮儀不瀆。", "導迎善祥，翟車歸毣。"]'),
('333ef8d9-b6e1-43f6-b1af-24f91ac3ea80','紹興十年發皇太后冊寶八首 太傅奉冊授提點官用《禮安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','孝奉天儀，信維休德。',40,'全唐诗/poet.song.251000.json','["孝奉天儀，信維休德。", "發越徽音，禮文靡忒。", "永保嘉祥，時萬時億。", "歸于東朝，含飴燕息。"]'),
('cc94ff79-d9de-4dea-8ffc-6635ee1162d0','紹興十年發皇太后冊寶八首 太傅奉冊授提點官用《禮安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','肅雍長樂，克篤其慶。',40,'全唐诗/poet.song.251000.json','["肅雍長樂，克篤其慶。", "河洲茂德，沙麓啟聖。", "是生睿哲，蚤隆丕運。", "欽稱鴻寶，永膺天命。"]'),
('b17a7092-7720-43fc-8f1c-f125ece5273e','紹興十年發皇太后冊寶八首 冊寶升慈寧殿幄用《聖安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','禮行東朝，樂奏大呂。',40,'全唐诗/poet.song.251000.json','["禮行東朝，樂奏大呂。", "羽衛森陳，簪紳式序。", "雲幄邃嚴，宏典是舉。", "天子萬年，母儀寰宇。"]'),
('cbb96e6b-c98c-4ecf-a8c1-d08de346ffd6','乾道七年恭上太上皇帝太上皇后尊號十一首 冊寶降殿用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','元祀介福，孰綏孰將。',40,'全唐诗/poet.song.251000.json','["元祀介福，孰綏孰將。", "歸于尊親，孝哉君王。", "載鏤斯牒，載琢斯章。", "得名得壽，如虞如唐。"]'),
('8ff91b56-2f70-4607-b376-f0b944a36b1c','乾道七年恭上太上皇帝太上皇后尊號十一首 中書令、侍中奉冊寶詣殿下用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','宗郊斯成，交舉典冊。',40,'全唐诗/poet.song.251000.json','["宗郊斯成，交舉典冊。", "汝輔汝弼，威儀是力。", "陳于廣庭，迨此上日。", "巍巍煌煌，烏臯在昔。"]'),
('5341c6d9-57d9-4c10-af86-68dceea97f52','乾道七年恭上太上皇帝太上皇后尊號十一首 皇帝奉太上皇帝冊寶授太傅用《禮安》。奉太上皇后同。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','儀物陳矣，禮樂明矣。',40,'全唐诗/poet.song.251000.json','["儀物陳矣，禮樂明矣。", "天子戾止，詒爾臣矣。", "陟降維則，恭且勤矣。", "茫茫四海，德教形矣。"]'),
('b94a9ded-0d04-45ce-a921-a344477cc713','乾道七年恭上太上皇帝太上皇后尊號十一首 冊寶出門用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','天門九重，蕩蕩開徹。',40,'全唐诗/poet.song.251000.json','["天門九重，蕩蕩開徹。", "金支秀華，垂紳佩玦。", "或導或陪，率履不越。", "注民耳目，四表胥悅。"]'),
('5dcf4510-faa0-4568-af9a-e00285efa140','乾道七年恭上太上皇帝太上皇后尊號十一首 冊寶入德壽門用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','禮神頌祇，福祿來下。',40,'全唐诗/poet.song.251000.json','["禮神頌祇，福祿來下。", "不有榮名，孰緝伊嘏。", "千乘萬騎，魚魚雅雅。", "皇扉洞開，鞠躬如也。"]'),
('03e00768-7b31-4a35-b2c2-67cd33684c9f','乾道七年恭上太上皇帝太上皇后尊號十一首 太上皇帝升御坐。降同。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','穆穆聖顔，安安天步。',40,'全唐诗/poet.song.251000.json','["穆穆聖顔，安安天步。", "有縟者儀，以莫不舉。", "天人和同，恩澤洋普。", "億載萬年，爲衆父父。"]'),
('8842114e-fc02-41a1-9a3e-52725eb7c1db','乾道七年恭上太上皇帝太上皇后尊號十一首 太傅奉太上皇帝冊寶升殿用《聖安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','大哉堯乎，南嚮垂裳。',40,'全唐诗/poet.song.251000.json','["大哉堯乎，南嚮垂裳。", "君哉舜也，拜而奉觴。", "繅藉光華，鼓鐘鏗鏘。", "三事稽首，宋德無疆。"]'),
('5144d648-9c11-4a8b-93f5-684fda254105','乾道七年恭上太上皇帝太上皇后尊號十一首 太傅奉太上皇后冊寶升殿用《聖安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','乾元資始，坤元資生。',40,'全唐诗/poet.song.251000.json','["乾元資始，坤元資生。", "允也聖德，同實異名。", "春王三朝，典冊並行。", "咨爾上公，相儀以登。"]'),
('d49883b2-13ea-4132-b756-98a79a5d732d','乾道七年恭上太上皇帝太上皇后尊號十一首 皇帝從太上皇后冊寶詣宮中用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','維冊伊何，鏤玉垂鴻。',40,'全唐诗/poet.song.251000.json','["維冊伊何，鏤玉垂鴻。", "維寶伊何，範金鈕龍。", "翊以𣊓御，間以笙鏞。", "誰敢不恭，天子寔從。"]'),
('9a601849-bdeb-4e09-9505-b1c44c408ef2','乾道七年恭上太上皇帝太上皇后尊號十一首 太上皇后出閣升御坐用《坤安》。降同。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','帝膺永福，功靡專有。',40,'全唐诗/poet.song.251000.json','["帝膺永福，功靡專有。", "既尊聖父，亦燕壽母。", "怡怡在宮，大典時受。", "彤管紀之，天長地久。"]'),
('6a39a2c1-82d4-496d-b4af-c26f9d28086a','乾道七年恭上太上皇帝太上皇后尊號十一首 內侍官舉太上皇后冊寶詣讀冊位用《聖安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','斂福于郊，逢時之泰。',40,'全唐诗/poet.song.251000.json','["斂福于郊，逢時之泰。", "揭名日月，侔德覆載。", "自我作古，域中有大。", "永言保之，眉壽無害。"]'),
('80b9ad40-6456-41a3-a20d-f5c9b00b5330','淳熙二年發太上皇帝太上皇后冊寶十一首 冊寶降殿用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','高明者乾，博厚者坤。',40,'全唐诗/poet.song.251000.json','["高明者乾，博厚者坤。", "以清以寧，資始資生。", "壽胡可度，德胡可評。", "願言從欲，誕受强名。"]'),
('be97345d-8977-438c-aa14-a042a94a591c','淳熙二年發太上皇帝太上皇后冊寶十一首 中書令、侍中奉冊寶詣殿下用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','受命既長，福祿既康。',40,'全唐诗/poet.song.251000.json','["受命既長，福祿既康。", "如日之升，如月之常。", "追琢其章，金玉其相。", "君子萬年，保其家邦。"]'),
('cc6ed955-4a74-454b-9a9a-74ad78ba93ee','淳熙二年發太上皇帝太上皇后冊寶十一首 皇帝奉太上皇帝冊寶授太傅用《禮安》。奉太上皇后同。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','翠華之旗，靈鼉之鼓。',40,'全唐诗/poet.song.251000.json','["翠華之旗，靈鼉之鼓。", "陳于廣宇，相我盛舉。", "來汝公傅，肅乃儀矩。", "毋愆于素，以篤多祜。"]'),
('e3988407-5390-42d9-8137-5f179e65957f','淳熙二年發太上皇帝太上皇后冊寶十一首 冊寶出門用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','蚴蟉青龍，婉嬗象輿。',40,'全唐诗/poet.song.251000.json','["蚴蟉青龍，婉嬗象輿。", "其載伊何，煌煌金書。", "乃由端門，乃行康衢。", "于以榮親，振古所無。"]'),
('796a5f43-133f-4e85-a7ec-02dbf0c6fd0d','淳熙二年發太上皇帝太上皇后冊寶十一首 冊寶入德壽宮門用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','惟天爲大，其德曰誠。',40,'全唐诗/poet.song.251000.json','["惟天爲大，其德曰誠。", "惟堯則之，其性曰仁。", "迺文迺武，得壽得名。", "於萬斯年，以莫不增。"]'),
('78ee5fd9-3363-4910-b5bb-dfe4fda02096','淳熙二年發太上皇帝太上皇后冊寶十一首 太上皇帝升御坐用《乾安》。降同。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','天行惟健，天步惟安。',40,'全唐诗/poet.song.251000.json','["天行惟健，天步惟安。", "聖子中立，臣工四環。", "民無能名，威不違顔。", "宋德宜頌，漢儀可刪。"]'),
('a04a9ab9-e11a-4efa-a62c-e8089573f802','淳熙二年發太上皇帝太上皇后冊寶十一首 太傅奉太上皇帝冊升殿用《聖安》。奉寶同。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','天畀遐福，允彰父慈。',40,'全唐诗/poet.song.251000.json','["天畀遐福，允彰父慈。", "維昔曠典，我能舉之。", "徐爾陟降，敬爾威儀。", "申錫無疆，永言保之。"]'),
('ce6d7f51-c8df-412d-ad77-7fdfeb808273','淳熙二年發太上皇帝太上皇后冊寶十一首 太傅奉太上皇后冊寶升殿用《聖安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','乾健坤從，陽剛陰相。',40,'全唐诗/poet.song.251000.json','["乾健坤從，陽剛陰相。", "迨茲受祉，允也並况。", "虡業在下，儀物在上。", "咨時三公，執事無曠。"]'),
('10e3f49b-7e4f-42c1-af90-3bdf65e905ee','淳熙二年發太上皇帝太上皇后冊寶十一首 皇帝從太上皇后冊寶詣宮中用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','丕顯文王，之德之純。',40,'全唐诗/poet.song.251000.json','["丕顯文王，之德之純。", "亦有太姒，式揚徽音。", "維冊維寶，迺玉迺金。", "伊誰從之，一人事親。"]'),
('d0c59f48-d6c5-4be7-bea5-8e82d423c4e7','淳熙二年發太上皇帝太上皇后冊寶十一首 太上皇后出閣升御坐用《坤安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','重翟出房，褘衣被躬。',40,'全唐诗/poet.song.251000.json','["重翟出房，褘衣被躬。", "委委佗佗，河潤山容。", "聖皇臨軒，聖母在宮。", "並受鴻名，與天無窮。"]'),
('0adfeca3-9663-4793-bcd0-2b53113251b8','淳熙二年發太上皇帝太上皇后冊寶十一首 內侍官舉太上皇后冊詣讀冊位用《聖安》。舉寶同。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','珉玉玢豳，褭蹄精良。',40,'全唐诗/poet.song.251000.json','["珉玉玢豳，褭蹄精良。", "既刻厥文，亦鑄之章。", "象德維何，至靜而方。", "輔我光堯，萬壽無疆。"]'),
('bb4b6653-45fd-4d0b-bfa5-0cfbada76ea1','淳熙十二年加上太上皇帝太上皇后尊號十一首 大慶殿發冊寶降殿用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','維天蓋高，維地克承。',40,'全唐诗/poet.song.251000.json','["維天蓋高，維地克承。", "父尊母親，天地難名。", "疆名廣大，建號安榮。", "衍登壽嘏，闡繹皇明。"]'),
('df56163f-ff84-4dd9-8727-edd73415e307','淳熙十二年加上太上皇帝太上皇后尊號十一首 中書令、侍中奉太上皇帝、太上皇后冊寶詣殿下用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','二儀同尊，兩耀齊光。',40,'全唐诗/poet.song.251000.json','["二儀同尊，兩耀齊光。", "巍巍煌煌，不顯亦彰。", "實茂號榮，玉振金相。", "於萬斯年，既壽且昌。"]'),
('bb0836e5-2f2c-4a35-827a-97c28878199d','淳熙十二年加上太上皇帝太上皇后尊號十一首 皇帝奉太上皇帝冊寶授太傅。太上皇后冊寶同。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','我尊我親，承天之祉。',40,'全唐诗/poet.song.251000.json','["我尊我親，承天之祉。", "壽名兼美，家國咸喜。", "公傅秉禮，寶冊有煒。", "惟千萬祀，令聞不已。"]'),
('08875e3a-ebe3-4eb2-a993-cb8c31436f8c','淳熙十二年加上太上皇帝太上皇后尊號十一首 冊寶出門用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','羽衛有嚴，寶書有輝。',40,'全唐诗/poet.song.251000.json','["羽衛有嚴，寶書有輝。", "昭衍尊名，鋪張上儀。", "出其端闈，由于康逵。", "比屋延瞻，歌之舞之。"]'),
('bdf86f0b-5d5d-408c-8c67-36af5d05a58b','淳熙十二年加上太上皇帝太上皇后尊號十一首 德壽宮冊寶入殿門用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','南山之鞏，皇壽無窮。',40,'全唐诗/poet.song.251000.json','["南山之鞏，皇壽無窮。", "太極之尊，皇名是崇。", "奉茲寶冊，于皇之宮。", "皇則受之，於昭盛容。"]'),
('b36a3e19-32ca-4de4-9048-f7e486e070c1','淳熙十二年加上太上皇帝太上皇后尊號十一首 太上皇帝出宮升御坐用《乾安》。降坐同。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','聖明太上，天子有尊。',40,'全唐诗/poet.song.251000.json','["聖明太上，天子有尊。", "玉坐高拱，慈顔睟溫。", "震禁嘉承，朝弁昈分。", "盛禮縟典，邃古未聞。"]'),
('8460d1ef-2272-489f-8f55-dbcd284c7730','淳熙十二年加上太上皇帝太上皇后尊號十一首 太傅、中書令、侍中奉太上皇帝冊寶升殿用《聖安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','天錫伊嘏，地效其珍。',40,'全唐诗/poet.song.251000.json','["天錫伊嘏，地效其珍。", "誕作寶典，奉于尊親。", "爾公爾相，爾恭爾寅。", "協舉令儀，遹臻厥成。"]'),
('3cdea1b7-5bf3-4a46-9c9a-f2232bda067a','淳熙十二年加上太上皇帝太上皇后尊號十一首 太傅、中書令、侍中奉太上皇后冊寶升殿用《聖安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','坤載有元，乾行是順。',40,'全唐诗/poet.song.251000.json','["坤載有元，乾行是順。", "施生萬彙，厥德彌盛。", "翼翼母道，贊我皇訓。", "相維羣公，奉典斯敬。"]'),
('fb33e291-c416-466e-862b-8cb7c5a08dc6','淳熙十二年加上太上皇帝太上皇后尊號十一首 皇帝從太上皇后冊寶詣宮中用《正安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','大矣母慈，德備且純。',40,'全唐诗/poet.song.251000.json','["大矣母慈，德備且純。", "思古齊敬，佐我皇文。", "明章茂典，金玉其音。", "帝親奉之，以翼以欽。"]'),
('f7c546c9-a127-4dc6-a344-7dcd052a7ed8','淳熙十二年加上太上皇帝太上皇后尊號十一首 太上皇后出閤升御坐用《坤安》。降坐同。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','天相慈皇，慶臻壺闈。',40,'全唐诗/poet.song.251000.json','["天相慈皇，慶臻壺闈。", "徽柔內修，壽與天齊。", "既承皇歡，載覿母儀。", "懿典鴻名，永綏多祺。"]'),
('ac46b7e8-e685-4dc8-8fb6-b126201e31f0','淳熙十二年加上太上皇帝太上皇后尊號十一首 內侍舉太上皇后冊寶詣讀冊寶位用《聖安》。','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','有美英瑶，於昭祥金。',40,'全唐诗/poet.song.251000.json','["有美英瑶，於昭祥金。", "爲策爲章，並著徽音。", "德聖而尊，備舉彌文。", "億載萬年，永輔堯勛。"]'),
('ee86c726-5d37-4c5d-a683-fd672da487ea','紹熙元年恭上壽聖皇太后至尊壽皇聖帝壽成皇后尊號冊寶十四首  其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','帝受內禪，紀元紹熙。',40,'全唐诗/poet.song.251000.json','["帝受內禪，紀元紹熙。", "欽崇慈親，孝心肅祗。", "迺建顯號，迺蕆丕儀。", "發冊廣庭，聲歌侑之。"]'),
('ac665a15-9ffc-451c-9bc5-4e5e206525a5','紹熙元年恭上壽聖皇太后至尊壽皇聖帝壽成皇后尊號冊寶十四首  其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','鐘鼓交作，文物咸備。',40,'全唐诗/poet.song.251000.json','["鐘鼓交作，文物咸備。", "彤庭玉階，天子是蒞。", "咨爾輔臣，展采錯事。", "輔臣稽首，敢不率禮。"]'),
('d832717f-ba2f-4abf-82bf-8314f7aa6e6a','紹熙元年恭上壽聖皇太后至尊壽皇聖帝壽成皇后尊號冊寶十四首  其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','巍巍天宮，洞開閶闔。',40,'全唐诗/poet.song.251000.json','["巍巍天宮，洞開閶闔。", "旗常葳蕤，劍佩雜沓。", "寶冊啟行，法駕繼發。", "鑠哉盛典，快臯胥悅。"]'),
('d01e162c-9577-4d8c-8684-6462d0f6aadf','紹熙元年恭上壽聖皇太后至尊壽皇聖帝壽成皇后尊號冊寶十四首  其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','仰止皇居，九門載闢。',40,'全唐诗/poet.song.251000.json','["仰止皇居，九門載闢。", "麗日重光，非煙五色。", "雷動萬乘，雲從百辟。", "咫尺重霄，鞠躬屏息。"]'),
('1e745ce8-6c58-49df-94e1-cea89babf0cb','紹熙元年恭上壽聖皇太后至尊壽皇聖帝壽成皇后尊號冊寶十四首  其五','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','玉璽瑶編，禮容畢具。',40,'全唐诗/poet.song.251000.json','["玉璽瑶編，禮容畢具。", "穆穆至尊，華殿是御。", "德配有虞，紹唐授禹。", "於萬斯年，受天之祜。"]'),
('bc493bfe-e58f-4743-a595-8e5023e395d1','紹熙元年恭上壽聖皇太后至尊壽皇聖帝壽成皇后尊號冊寶十四首  其六','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','慈皇天臨，睟表怡怡。',40,'全唐诗/poet.song.251000.json','["慈皇天臨，睟表怡怡。", "欽哉聖子，親奉玉巵。", "鼇抃嵩呼，歡浹華夷。", "邇臣捧冊，是恪是祗。"]'),
('67675064-46ec-435e-a147-b0b479951357','紹熙元年恭上壽聖皇太后至尊壽皇聖帝壽成皇后尊號冊寶十四首  其七','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','瑟彼華玉，篆魚鈕龍。',40,'全唐诗/poet.song.251000.json','["瑟彼華玉，篆魚鈕龍。", "與冊並登，咨爾上公。", "詠以歌詩，協之鼓鐘。", "是陟是降，靡有弗恭。"]'),
('5b4b2a59-e09d-41c5-8c24-05d4fded0860','紹熙元年恭上壽聖皇太后至尊壽皇聖帝壽成皇后尊號冊寶十四首  其八','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','天祐皇家，慶集重闈。',40,'全唐诗/poet.song.251000.json','["天祐皇家，慶集重闈。", "寶兮揚名，冊兮流徽。", "金支秀華，盛容祲威。", "詔我近弼，相禮不違。"]'),
('8157fcca-e454-4922-89cf-2e20a719e2e3','紹熙元年恭上壽聖皇太后至尊壽皇聖帝壽成皇后尊號冊寶十四首  其九','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','大哉乾元，既極形容。',40,'全唐诗/poet.song.251000.json','["大哉乾元，既極形容。", "坤元德至，實與比隆。", "寶冊並登，勒崇垂鴻。", "相我縟儀，肅肅雍雍。"]'),
('dd27a5d8-5176-4930-8e34-48a2e81d8b54','紹熙元年恭上壽聖皇太后至尊壽皇聖帝壽成皇后尊號冊寶十四首  其一○','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','涓辰協吉，時維春元。',40,'全唐诗/poet.song.251000.json','["涓辰協吉，時維春元。", "上冊三殿，曠古無前。", "思齊重闈，積慶有源。", "是尊是崇，帝心載虔。"]'),
('5552d522-d222-4110-87a7-01e59b2c40d0','紹熙元年恭上壽聖皇太后至尊壽皇聖帝壽成皇后尊號冊寶十四首  其一一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','丕赫有宋，三聖授受。',40,'全唐诗/poet.song.251000.json','["丕赫有宋，三聖授受。", "誰其助之，繄我太母。", "東朝受冊，飲此春酒。", "聖子神孫，密侍左右。"]'),
('1b0a5488-2f2f-443e-a1ab-83dfcacdb899','紹熙元年恭上壽聖皇太后至尊壽皇聖帝壽成皇后尊號冊寶十四首  其一二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','坤德益崇，天壽平格。',40,'全唐诗/poet.song.251000.json','["坤德益崇，天壽平格。", "慶流萬世，子孫千億。", "刻玉範金，鋪張赫奕。", "惟昔姜任，則莫我匹。"]'),
('92456c6b-ee21-46ec-8c91-b94a468a2d61','紹熙元年恭上壽聖皇太后至尊壽皇聖帝壽成皇后尊號冊寶十四首  其一三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','鞠育保護，母道備矣。',40,'全唐诗/poet.song.251000.json','["鞠育保護，母道備矣。", "密贊親傳，德其至矣。", "綵服來朝，慈容有喜。", "既受鴻名，又多受祉。"]'),
('cd5ade53-3f4a-40f4-a94a-4df4f72fce1c','紹熙元年恭上壽聖皇太后至尊壽皇聖帝壽成皇后尊號冊寶十四首  其一四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','仰瞻慈闈，登進寶冊。',40,'全唐诗/poet.song.251000.json','["仰瞻慈闈，登進寶冊。", "惟時𣊓御，祗率厥職。", "曰壽曰名，母兮兼得。", "儷我尊父，億載無極。"]'),
('7dc37adc-4c6d-4080-9118-838ae3287f05','紹熙四年加上壽聖皇太后尊號八首  其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','德厚重闈，沖澹粹穆。',40,'全唐诗/poet.song.251000.json','["德厚重闈，沖澹粹穆。", "何以名之，惟慈惟福。", "寶鏤精鏐，冊鎸華玉。", "物盛禮崇，丕昭群目。"]'),
('20c0e7e2-7a9e-4835-87e8-dd711803b0c3','紹熙四年加上壽聖皇太后尊號八首  其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於皇帝室，休運貽孫。',40,'全唐诗/poet.song.251000.json','["於皇帝室，休運貽孫。", "重熙疊慶，祗進號榮。", "爰授茲冊，必躬必親。", "天子聖孝，萬邦儀刑。"]'),
('e0a7fbe8-42a8-4001-8790-6f38ec1ba4ad','紹熙四年加上壽聖皇太后尊號八首  其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','煌煌冊寶，天子受之。',40,'全唐诗/poet.song.251000.json','["煌煌冊寶，天子受之。", "言徐其行，肅展迺儀。", "其儀維何，劍佩黄麾。", "鸞駕清蹕，聳瞻九逵。"]'),
('c7fc9ead-248d-4491-a085-0b94c566cfac','紹熙四年加上壽聖皇太后尊號八首  其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','熙辰禮備，濟濟雍雍。',40,'全唐诗/poet.song.251000.json','["熙辰禮備，濟濟雍雍。", "言奉斯冊，重親之宮。", "宮帷既敞，協氣感通。", "皇儀親展，壽祉無窮。"]'),
('49e918fe-72f2-474a-8274-0e926c0b8e7a','紹熙四年加上壽聖皇太后尊號八首  其五','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','既肅琨庭，載升金戺。',40,'全唐诗/poet.song.251000.json','["既肅琨庭，載升金戺。", "迺導迺陪，威儀濟濟。", "天步繼臨，孝誠備矣。", "聲容孔昭，中外悅喜。"]'),
('081750e3-1beb-4435-92b1-1d7cc0d88b73','紹熙四年加上壽聖皇太后尊號八首  其六','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','琱輿彩仗，祗詣慈宮。',40,'全唐诗/poet.song.251000.json','["琱輿彩仗，祗詣慈宮。", "寶冊前奉，龍挾雲從。", "言備茲禮，于宮之中。", "惟天子孝，於昭祲容。"]'),
('18121af0-3262-4eca-a140-4080e08511cb','紹熙四年加上壽聖皇太后尊號八首  其七','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','懿典大冊，陳儀邃深。',40,'全唐诗/poet.song.251000.json','["懿典大冊，陳儀邃深。", "怡怡愉愉，寶坐是臨。", "重綵儼侍，罙展肅心。", "三宮協慶，永播徽音。"]'),
('127214fe-1ca3-4e92-8b6f-fb3fe21d09d7','紹熙四年加上壽聖皇太后尊號八首  其八','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','寶冊既奉，祗誦迺言。',40,'全唐诗/poet.song.251000.json','["寶冊既奉，祗誦迺言。", "仁深慶衍，益顯益尊。", "和聲協氣，充溢乾坤。", "並受伊嘏，聖子神孫。"]'),
('79ff69a9-03f2-4f89-b341-977a4bb32701','慶元二年恭上太皇太后皇太后太上皇帝太上皇后尊號二十四首  其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','天擁帝家，澤流子孫。',40,'全唐诗/poet.song.251000.json','["天擁帝家，澤流子孫。", "三宮燕胥，四海崇尊。", "聲諧韶濩，輝燭瑶琨。", "維皇緝熙，耀德乾坤。"]'),
('5a15993d-e04c-4c57-9198-f423c4ece40b','慶元二年恭上太皇太后皇太后太上皇帝太上皇后尊號二十四首  其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','祖后重壽，親闈並崇。',40,'全唐诗/poet.song.251000.json','["祖后重壽，親闈並崇。", "駢慶聯休，申景鋪鴻。", "疊璧交輝，多儀煥叢。", "億萬斯年，福祿攸同。"]'),
('320d59f0-ba2c-4212-a5fa-f20bd4956f62','慶元二年恭上太皇太后皇太后太上皇帝太上皇后尊號二十四首  其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','太任媚姜，塗山翼禹。',40,'全唐诗/poet.song.251000.json','["太任媚姜，塗山翼禹。", "慈祥曼衍，鴻儀迭舉。", "寶章奕奕，祲宮俁俁。", "帝用將之，于彼宮所。"]'),
('4349a9a5-4676-4695-abe3-16644369acb5','慶元二年恭上太皇太后皇太后太上皇帝太上皇后尊號二十四首  其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','東朝層邃，端闈靖深。',40,'全唐诗/poet.song.251000.json','["東朝層邃，端闈靖深。", "列仗節鑾，鏤玉繩金。", "來奉來崇，載祗載欽。", "曾孫之慶，世世徽音。"]'),
('5ee9e376-ee1a-4a29-9019-cc190d62dad5','慶元二年恭上太皇太后皇太后太上皇帝太上皇后尊號二十四首  其五','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','純佑我宋，母儀四朝。',40,'全唐诗/poet.song.251000.json','["純佑我宋，母儀四朝。", "擁翼孫謀，如虞承堯。", "仁覃函夏，喜浮慶霄。", "福祿萬年，金玉孔昭。"]'),
('08251ab9-6192-4f12-a2eb-84d636a8641a','慶元二年恭上太皇太后皇太后太上皇帝太上皇后尊號二十四首  其六','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','神人和懌，天日淑清。',40,'全唐诗/poet.song.251000.json','["神人和懌，天日淑清。", "王母來燕，必壽而名。", "琨庭璈音，五雲佩聲。", "勉勉我皇，遹昭厥成。"]'),
('53a92546-9735-403b-8b36-dbfef4f53bbb','慶元二年恭上太皇太后皇太后太上皇帝太上皇后尊號二十四首  其七','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','曾孫致養，五福駢臻。',40,'全唐诗/poet.song.251000.json','["曾孫致養，五福駢臻。", "太極所運，兩儀三辰。", "輝光日新，啟佑後人。", "永翼瑶圖，億萬堯春。"]'),
('7825174e-e2c0-4d74-a2a9-c3b855bffca7','慶元二年恭上太皇太后皇太后太上皇帝太上皇后尊號二十四首  其八','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','徽光宣華，仁聲流文。',40,'全唐诗/poet.song.251000.json','["徽光宣華，仁聲流文。", "曠儀合沓，泰和絪緼。", "慈顔有喜，祚我聖君。", "珠宮含飴，坐閲來雲。"]'),
('27673351-ba6c-49ba-9139-f1f473d6d999','慶元二年恭上太皇太后皇太后太上皇帝太上皇后尊號二十四首  其九','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','縟儀既登，寶冊既膺。',40,'全唐诗/poet.song.251000.json','["縟儀既登，寶冊既膺。", "喜洽祥流，雲烝川增。", "天子萬年，鳴玉慈庭。", "惠我無疆，詵詵繩繩。"]'),
('a2ad87a2-1d26-40f6-bd8a-cad20d40a3a1','慶元二年恭上太皇太后皇太后太上皇帝太上皇后尊號二十四首  其一○','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','新庭靖安，祖后燕怡。',40,'全唐诗/poet.song.251000.json','["新庭靖安，祖后燕怡。", "有開聖謀，累崇天基。", "典章文明，聲容葳蕤。", "御于邦家，曰壽曰慈。"]'),
('6abc78f8-26c6-4533-8fdf-ce1f238b7081','慶元二年恭上太皇太后皇太后太上皇帝太上皇后尊號二十四首  其一一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','三禮崇容，八鑾警衛。',40,'全唐诗/poet.song.251000.json','["三禮崇容，八鑾警衛。", "有來辰儀，闡徽媯汭。", "璇宮肅雍，藻景澄霽。", "文子文孫，本支百世。"]'),
('d81ad001-b0a3-44c3-9f80-dc5e98f7bf03','慶元二年恭上太皇太后皇太后太上皇帝太上皇后尊號二十四首  其一二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','堯門疊瑞，姒幄齊輝。',40,'全唐诗/poet.song.251000.json','["堯門疊瑞，姒幄齊輝。", "重坤靖夷，麗冊華徽。", "天子仁聖，禮文弗違。", "福壽康寧，同燕層闈。"]'),
('f1de8fb2-0f9a-4866-a663-2ef9031dd12e','慶元二年恭上太皇太后皇太后太上皇帝太上皇后尊號二十四首  其一三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','文母曼壽，載錫之光。',40,'全唐诗/poet.song.251000.json','["文母曼壽，載錫之光。", "總集瑞命，宜君宜王。", "惠以仁顯，慈以德彰。", "保佑子孫，受福無疆。"]'),
('f872226d-2be9-4eba-a594-a2337f589f88','慶元二年恭上太皇太后皇太后太上皇帝太上皇后尊號二十四首  其一四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','華鸞編玉，文螭液金。',40,'全唐诗/poet.song.251000.json','["華鸞編玉，文螭液金。", "頌德摛英，揚徽嗣音。", "紫幄天開，翠華日臨。", "歲歲年年，如周太任。"]'),
('7d32790b-69c3-46cc-a788-51fe3ee3b3be','慶元二年恭上太皇太后皇太后太上皇帝太上皇后尊號二十四首  其一五','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','宋有明德，天保佑之。',40,'全唐诗/poet.song.251000.json','["宋有明德，天保佑之。", "以壽繼壽，以慈廣慈。", "聲文宣昭，福祉茂綏。", "神孫之休，燕及華夷。"]'),
('d02bfe8d-fcb0-44d7-a1b6-75282f113d51','慶元二年恭上太皇太后皇太后太上皇帝太上皇后尊號二十四首  其一六','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','大安耽耽，興慶崇崇。',40,'全唐诗/poet.song.251000.json','["大安耽耽，興慶崇崇。", "維皇之尊，與天比隆。", "非心閒燕，文命延鴻。", "欲報之恩，禮縟儀豐。"]'),
('db7fe36c-9328-4bdd-aab4-fae0a0a19e35','慶元二年恭上太皇太后皇太后太上皇帝太上皇后尊號二十四首  其一七','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','上帝有赫，百靈效祥。',40,'全唐诗/poet.song.251000.json','["上帝有赫，百靈效祥。", "儲祉垂恩，錫年降康。", "皇儀睟溫，帝躬肅莊。", "三宮齊懽，地久天長。"]'),
('fc279407-166e-455a-a986-c46e55d49c77','慶元二年恭上太皇太后皇太后太上皇帝太上皇后尊號二十四首  其一八','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','夏典稽瑞，禹玉含淳。',40,'全唐诗/poet.song.251000.json','["夏典稽瑞，禹玉含淳。", "追琢有章，溫潤孔純。", "聖底于安，壽綿於仁。", "太上立德，自天其申。"]'),
('9629c582-5829-40bc-863e-9b139c53ca88','慶元二年恭上太皇太后皇太后太上皇帝太上皇后尊號二十四首  其一九','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','父尊母親，天涵地育。',40,'全唐诗/poet.song.251000.json','["父尊母親，天涵地育。", "燕我翼子，景命有僕。", "得名得壽，如金如玉。", "子孫千億，成其厚福。"]'),
('ab01b47f-d58c-43b4-9e02-9bf6319e9b18','慶元二年恭上太皇太后皇太后太上皇帝太上皇后尊號二十四首  其二○','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','天地清寧，日月華光。',40,'全唐诗/poet.song.251000.json','["天地清寧，日月華光。", "歸尊慈極，嵩呼未央。", "慶函百嘉，壽躋八荒。", "上皇萬歲，俾熾俾昌。"]'),
('d399a50f-e59b-4227-a5a1-e0b54e929eae','慶元二年恭上太皇太后皇太后太上皇帝太上皇后尊號二十四首  其二一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','晨趨慈幄，佳氣鬰蔥。',40,'全唐诗/poet.song.251000.json','["晨趨慈幄，佳氣鬰蔥。", "受帝之祉，配天其崇。", "璧華金精，禮敷樂充。", "天子是若，懽聲融融。"]'),
('43338e6f-9db3-4e4a-ba87-1e0553e3cf93','慶元二年恭上太皇太后皇太后太上皇帝太上皇后尊號二十四首  其二二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','文物流彩，鑾輅靖陳。',40,'全唐诗/poet.song.251000.json','["文物流彩，鑾輅靖陳。", "龜瑞薦祉，坤儀效珍。", "比皇之壽，翼帝以仁。", "和氣致祥，與物爲春。"]'),
('ae5665e2-3f08-444a-8e7f-dbff2ba5991e','慶元二年恭上太皇太后皇太后太上皇帝太上皇后尊號二十四首  其二三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','黼黻其文，金玉其相。',40,'全唐诗/poet.song.251000.json','["黼黻其文，金玉其相。", "永壽於萬，合德無疆。", "福緒祥源，厥後克昌。", "天維格斯，祚我聖皇。"]'),
('99fa5fbc-fa8a-428f-9ee6-c0d56a25ebe4','慶元二年恭上太皇太后皇太后太上皇帝太上皇后尊號二十四首  其二四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','榮懷之慶，莫盛於斯。',40,'全唐诗/poet.song.251000.json','["榮懷之慶，莫盛於斯。", "三宮四冊，五葉一時。", "德阜而豐，福大而滋。", "子子孫孫，于時保之。"]'),
('e92f3c20-e35a-44a9-8e35-b390c1fb72c8','嘉泰二年恭上太皇太后尊號八首  其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','思齊太任，嬪于周京。',40,'全唐诗/poet.song.251000.json','["思齊太任，嬪于周京。", "至哉坤元，萬物資生。", "不可儀測，矧可强名。", "鏤玉繩金，昭哉號榮。"]'),
('0e5ec799-3650-4756-af73-42ea0de011e8','嘉泰二年恭上太皇太后尊號八首  其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','鼓鐘喤喤，儀物載陳。',40,'全唐诗/poet.song.251000.json','["鼓鐘喤喤，儀物載陳。", "儀物陳矣，爛其瑶琨。", "咨爾上公，相予文孫。", "勿亟勿徐，奉我重親。"]'),
('a5e9e98e-e3e7-477a-95da-3a97966fa2f6','嘉泰二年恭上太皇太后尊號八首  其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','蕩蕩天門，金鋪玉戶。',40,'全唐诗/poet.song.251000.json','["蕩蕩天門，金鋪玉戶。", "采旄翠旌，流蘇葆羽。", "千官影從，迺導迺輔。", "都人縱觀，填道呼舞。"]'),
('392162bf-3004-4777-b96c-9520793125de','嘉泰二年恭上太皇太后尊號八首  其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','煌煌寶書，玉篆金縷。',40,'全唐诗/poet.song.251000.json','["煌煌寶書，玉篆金縷。", "曷爲來哉，自天子所。", "自天子所，以燕文母。", "婉嬗祥雲，日正當午。"]'),
('5f8cf94f-7c4d-4419-bfe9-e74683ec5156','嘉泰二年恭上太皇太后尊號八首  其五','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','文物備矣，三事其承。',40,'全唐诗/poet.song.251000.json','["文物備矣，三事其承。", "崇牙高張，樂充宮庭。", "耽耽廣殿，左墄右平。", "敬爾威儀，攝齊以登。"]'),
('313e03da-2b75-4a9d-8549-f8d3ff9a3d7c','嘉泰二年恭上太皇太后尊號八首  其六','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','維壽伊何，聖德日新。',40,'全唐诗/poet.song.251000.json','["維壽伊何，聖德日新。", "維慈伊何，祐于後人。", "迺范斯金，迺鏤斯珉。", "皇舉玉趾，從于堯門。"]'),
('af8445ec-b02b-4119-8452-4baa16ff6086','嘉泰二年恭上太皇太后尊號八首  其七','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','侍中版奏，辦外嚴中。',40,'全唐诗/poet.song.251000.json','["侍中版奏，辦外嚴中。", "出自玉房，褘褕被躬。", "我龍受之，祲威盛容。", "皇帝聖孝，其樂融融。"]'),
('ac292bec-ad7b-4200-b322-48345151b69c','嘉泰二年恭上太皇太后尊號八首  其八','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','麟趾褭蹄，我寶斯刻。',40,'全唐诗/poet.song.251000.json','["麟趾褭蹄，我寶斯刻。", "碝磩采緻，載備斯冊。", "眉壽萬年，詒謀燕翼。", "於赫湯孫，克綿永福。"]'),
('3436c9db-7c34-4197-b45e-5187ba186839','紹定三年壽明仁福慈睿皇太后冊寶九首  其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','思齊聖母，媲于周任。',40,'全唐诗/poet.song.251000.json','["思齊聖母，媲于周任。", "體乾履坤，博厚洪深。", "七袠既啟，萬壽自今。", "昕庭發號，式昭德音。"]'),
('12a94af8-d00a-417a-a178-aa83e82f9f4f','紹定三年壽明仁福慈睿皇太后冊寶九首  其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','煌煌儀物，繹繹鼓鐘。',40,'全唐诗/poet.song.251000.json','["煌煌儀物，繹繹鼓鐘。", "奉茲寶冊，至于階東。", "上公相儀，列辟盡恭。", "拜手慈宸，福如華嵩。"]'),
('a02e8fc4-f205-4cbe-9744-cbf54450941b','紹定三年壽明仁福慈睿皇太后冊寶九首  其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','帝闕肅開，天階坦履。',40,'全唐诗/poet.song.251000.json','["帝闕肅開，天階坦履。", "霓旌羽蓋，導儀護衛。", "匪誇雕瑑，匪矜繁麗。", "茲謂盛儀，億載千歲。"]'),
('9573e336-8981-4a7f-8e29-cf31003bd7f4','紹定三年壽明仁福慈睿皇太后冊寶九首  其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','金堅玉純，文郁禮縟。',40,'全唐诗/poet.song.251000.json','["金堅玉純，文郁禮縟。", "來從帝所，作瑞王國。", "天開地闢，日熙春燠。", "茲謂盛事，永燕茀祿。"]'),
('88d63a43-abc8-4544-a100-a41fa1cfefd1','紹定三年壽明仁福慈睿皇太后冊寶九首  其五','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','皇儀有煒，綵舁次升。',40,'全唐诗/poet.song.251000.json','["皇儀有煒，綵舁次升。", "沈沈邃殿，穆穆天廷。", "坤德罙隆，皇圖永寧。", "咨爾廷臣，攝齊以登。"]'),
('24bf4f4b-94ce-4d1f-b24f-b38c08203938','紹定三年壽明仁福慈睿皇太后冊寶九首  其六','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','壽爲福先，明燭物表。',40,'全唐诗/poet.song.251000.json','["壽爲福先，明燭物表。", "仁沾動植，福齊穹昊。", "曰慈與睿，並崇丕號。", "演而申之，萬世永保。"]'),
('3a224878-dcd9-4fe2-a1ea-8d35997da89e','紹定三年壽明仁福慈睿皇太后冊寶九首  其七','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','邇臣跪奏，嚴辦必恭。',40,'全唐诗/poet.song.251000.json','["邇臣跪奏，嚴辦必恭。", "乃御褘褕，升于殿中。", "慈顔雍穆，和氣沖融。", "芳流清史，傳之無窮。"]'),
('20e3ea72-1b7b-4dc8-8d84-7fae587bff05','紹定三年壽明仁福慈睿皇太后冊寶九首  其八','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','徽音孔昭，寶傳斯刻。',40,'全唐诗/poet.song.251000.json','["徽音孔昭，寶傳斯刻。", "金昭玉粹，有燁斯冊。", "載祈載祝，以燕以翼。", "寶之萬年，與宋無極。"]'),
('dd5768b5-e55a-4e7d-9d02-0801166dd6a0','紹定三年壽明仁福慈睿皇太后冊寶九首  其九','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','皇文既舉，慶禮告虔。',40,'全唐诗/poet.song.251000.json','["皇文既舉，慶禮告虔。", "肇自宮闈，格于幅員。", "子稱母壽，母謂子賢。", "陟降在茲，隆名際天。"]'),
('1ed0f7af-2856-4c32-94ce-7f44ed965c2b','哲宗發皇后冊寶三首  其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','既登乃依，如日之升。',40,'全唐诗/poet.song.251000.json','["既登乃依，如日之升。", "有嚴有翼，丕顯丕承。", "天作之合，家邦其興。", "朱芾斯皇，子孫繩繩。"]'),
('455b982b-0bad-4a7c-ad3f-9e3ec5b5f367','哲宗發皇后冊寶三首  其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','我禮嘉成，我駕言旋。',40,'全唐诗/poet.song.251000.json','["我禮嘉成，我駕言旋。", "降坐而蹕，奏鼓淵淵。", "景命有僕，保佑自天。", "永錫祚嗣，何千萬年。"]'),
('d2487063-a5eb-4503-911b-449789630b42','哲宗發皇后冊寶三首  其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','宣哲維公，就位肅莊。',40,'全唐诗/poet.song.251000.json','["宣哲維公，就位肅莊。", "冊寶具舉，丕顯其光。", "出于宸闈，鼓鐘喤喤。", "母儀天下，萬壽無疆。"]'),
('444ec2d1-5133-443e-b0d9-14bc4c24c6a0','紹興十三年發皇后冊寶十三首  其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','天地奠位，乾坤以分。',40,'全唐诗/poet.song.251000.json','["天地奠位，乾坤以分。", "夫婦有別，父子相親。", "聖王之治，禮重婚姻。", "端冕從事，是正大倫。"]'),
('5fff17b0-e0a9-484c-8d62-486ca0092bcc','紹興十三年發皇后冊寶十三首  其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','天子當陽，群工就列。',40,'全唐诗/poet.song.251000.json','["天子當陽，群工就列。", "冊寶既陳，鐘鼓備設。", "上公奉事，容莊心協。", "克相盛禮，光昭玉牒。"]'),
('c4e03613-0056-4b94-b29f-20990f099a3d','紹興十三年發皇后冊寶十三首  其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','穆穆睟容，如天之臨。',40,'全唐诗/poet.song.251000.json','["穆穆睟容，如天之臨。", "赫赫明命，如玉之音。", "虔恭出門，禮容兢兢。", "塗山生啟，夏道以興。"]'),
('7cfccf57-57fc-44c6-bab2-70e3b3b5a05e','紹興十三年發皇后冊寶十三首  其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','朝陽已升，薰風習至。',40,'全唐诗/poet.song.251000.json','["朝陽已升，薰風習至。", "樂奏既成，禮容亦備。", "玉佩鏘鳴，帝徐舉趾。", "壺政穆宣，以聽內治。"]'),
('c41c4aab-6a54-48f1-bfb5-d279cd46c694','紹興十三年發皇后冊寶十三首  其五','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','猗歟賢后，德本性成。',40,'全唐诗/poet.song.251000.json','["猗歟賢后，德本性成。", "承天致順，遡日爲明。", "作配儷極，王化以行。", "萬有千歲，奉祀宗祊。"]'),
('657e97d8-f1f7-4010-bd28-8198296a253e','紹興十三年發皇后冊寶十三首  其六','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','款承祗事，時惟肅雍。',40,'全唐诗/poet.song.251000.json','["款承祗事，時惟肅雍。", "跪奉冊寶，陳于法宮。", "以俯以仰，有儀有容。", "明神介之，福祿來崇。"]'),
('fc818cfd-8ca3-4495-b72f-8074ac439ebc','紹興十三年發皇后冊寶十三首  其七','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','溫惠之德，褘翟之衣。',40,'全唐诗/poet.song.251000.json','["溫惠之德，褘翟之衣。", "行中采薺，禮無或違。", "降于丹陛，有容有儀。", "委委蛇蛇，誰其似之。"]'),
('f8a608d2-81b6-42e3-bbe6-3ea22db9de0a','紹興十三年發皇后冊寶十三首  其八','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','鏤蒼玉兮，盛德載揚。',40,'全唐诗/poet.song.251000.json','["鏤蒼玉兮，盛德載揚。", "鑄南金兮，作鎮椒房。", "虔受賜兮，有燁有光。", "宜室家兮，朱芾斯皇。"]'),
('ea5c565e-cc39-4b7e-a4e9-d220c62b9a04','紹興十三年發皇后冊寶十三首  其九','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','禮既行兮，厥位孔安。',40,'全唐诗/poet.song.251000.json','["禮既行兮，厥位孔安。", "母儀正兮，容止可觀。", "奉東朝兮，常得其歡。", "求淑女兮，豈樂多般。"]'),
('8f59d7fe-d127-4135-b1b2-39315c15808b','紹興十三年發皇后冊寶十三首  其一○','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','素月澄輝，衆星顯列。',40,'全唐诗/poet.song.251000.json','["素月澄輝，衆星顯列。", "炳爲天文，各有攸別。", "椒房既正，陰教斯設。", "關雎麟趾，應如響捷。"]'),
('21fc3df1-848d-49d4-b5f2-4cfeb8efe8b8','紹興十三年發皇后冊寶十三首  其一一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','窈窕其容，淑嫕其姿。',40,'全唐诗/poet.song.251000.json','["窈窕其容，淑嫕其姿。", "爛其如雲，瞻我母儀。", "曰天之妹，作合惟宜。", "粲然舞抃，疇不肅祗。"]'),
('6f14ab37-4623-47e2-a708-5a34d3f31554','紹興十三年發皇后冊寶十三首  其一二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','寶字煌煌，冊書粲粲。',40,'全唐诗/poet.song.251000.json','["寶字煌煌，冊書粲粲。", "副笄加飾，褘褕有爛。", "祗若帝休，委蛇樂衎。", "億萬斯年，永膺宸翰。"]'),
('e6f13129-27fb-4205-abee-c6b24ea6e851','紹興十三年發皇后冊寶十三首  其一三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','太任徽音，太姒是嗣。',40,'全唐诗/poet.song.251000.json','["太任徽音，太姒是嗣。", "則百斯男，周室以熾。", "天子萬年，受茲女士。", "如姒事任，從以孫子。"]'),
('4f1dfe21-9c2f-49d1-a5ab-3f85a71e3125','淳熙三年發皇后冊寶十三首  其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','赫赫惟皇，如日之光。',40,'全唐诗/poet.song.251000.json','["赫赫惟皇，如日之光。", "肅肅惟后，如月之常。", "禮行一時，明照無疆。", "天子蒞止，疇敢不莊。"]'),
('b841ef95-ec9a-4d1d-8771-aa4ed1887b1f','淳熙三年發皇后冊寶十三首  其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','卜月惟良，練辰斯臧。',40,'全唐诗/poet.song.251000.json','["卜月惟良，練辰斯臧。", "臣工在庭，劍佩瑲瑲。", "來汝疑丞，明命是將。", "有淑其儀，無或怠遑。"]'),
('c2aeca59-a41a-45b4-b2e0-235289aba5e2','淳熙三年發皇后冊寶十三首  其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','刻簡以珉，鑄寶以金。',40,'全唐诗/poet.song.251000.json','["刻簡以珉，鑄寶以金。", "持節伊誰，時惟四鄰。", "自我文德，達之穆清。", "委蛇委蛇，往迄于成。"]'),
('6d0f420c-da0b-44f1-9658-35b4ca1b128d','淳熙三年發皇后冊寶十三首  其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','冊行何曏，于門東偏。',40,'全唐诗/poet.song.251000.json','["冊行何曏，于門東偏。", "禮備樂成，合扇鳴鞭。", "皇舉玉趾，如天之旋。", "燕及家邦，億萬斯年。"]'),
('3592caa6-6dec-4c9c-bd2e-e20d16253888','淳熙三年發皇后冊寶十三首  其五','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','椒塗蘭馭，河潤山容。',40,'全唐诗/poet.song.251000.json','["椒塗蘭馭，河潤山容。", "副笄在首，褘衣被躬。", "靜女其姝，實翼實從。", "自彼西閤，聿來殿中。"]'),
('477a2efa-daa2-4bd1-95f3-96bc2ae7ec90','淳熙三年發皇后冊寶十三首  其六','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','德隆位尊，禮厚文縟。',40,'全唐诗/poet.song.251000.json','["德隆位尊，禮厚文縟。", "乃篆斯金，乃鏤斯玉。", "群公盈門，執事有肅。", "願言保之，永鎮坤軸。"]'),
('d07093ef-45e8-469e-8198-c90debce92f0','淳熙三年發皇后冊寶十三首  其七','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','規殿沉沉，叶氣旼旼。',40,'全唐诗/poet.song.251000.json','["規殿沉沉，叶氣旼旼。", "明章婦順，表正人倫。", "躡是左墄，暨于中庭。", "尚宮顯相，罔有弗欽。"]'),
('082bc221-b67f-4fa9-97e6-5c537600e611','淳熙三年發皇后冊寶十三首  其八','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','備物典冊，樂之鼓鐘。',40,'全唐诗/poet.song.251000.json','["備物典冊，樂之鼓鐘。", "拜而受之，極其肅雍。", "司言司寶，各以職從。", "行地有慶，與天無窮。"]'),
('9bdd1e8a-52f7-4990-9a8b-0439dd065c4a','淳熙三年發皇后冊寶十三首  其九','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','容典既膺，壺儀既正。',40,'全唐诗/poet.song.251000.json','["容典既膺，壺儀既正。", "羽衛外列，揚顔中映。", "如帝如天，以莊以靚。", "六宮承式，二南流詠。"]'),
('63b00f44-cc59-4b10-a5ee-5fde0cb9559b','淳熙三年發皇后冊寶十三首  其一○','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','葛覃節用，樛木逮下。',40,'全唐诗/poet.song.251000.json','["葛覃節用，樛木逮下。", "形爲嬪則，夙已心化。", "茲臨長秋，遂正諸夏。", "以慶以祈，百祥來迓。"]'),
('d1057c03-444e-4cef-b10d-3628e24f6024','淳熙三年發皇后冊寶十三首  其一一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','碩人其頎，公侯之妻。',40,'全唐诗/poet.song.251000.json','["碩人其頎，公侯之妻。", "翟茀以朝，象服是宜。", "如星之共，遡月之輝。", "母儀既瞻，群心則夷。"]'),
('c56e40d9-a300-49f9-a32c-21dff7f6741d','淳熙三年發皇后冊寶十三首  其一二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','窈窕淑女，備六服兮。',40,'全唐诗/poet.song.251000.json','["窈窕淑女，備六服兮。", "陟降多儀，聳群目兮。", "內治允備，陰教肅兮。", "宜君宜王，綏有福兮。"]'),
('3540039f-cb79-4774-a05b-86e292363901','淳熙三年發皇后冊寶十三首  其一三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','天監有周，是生太任。',40,'全唐诗/poet.song.251000.json','["天監有周，是生太任。", "亦有太姒，嗣其徽音。", "孰如兩宮，慈愛相承。", "思齊之盛，復見于今。"]'),
('00489df4-e531-48ba-8bfd-882c476ad2ef','淳熙十六年皇后冊寶十三首  其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','乾位既正，坤斯順承。',40,'全唐诗/poet.song.251000.json','["乾位既正，坤斯順承。", "日麗于天，月斯遡明。", "惟帝受命，惟帝並登。", "黼扆尊臨，典冊是行。"]'),
('cf7e021b-5659-4fec-a6e8-7573613c32b7','淳熙十六年皇后冊寶十三首  其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','迺協良辰，維春之宜。',40,'全唐诗/poet.song.251000.json','["迺協良辰，維春之宜。", "迺詔近弼，來汝相儀。", "九門洞開，文物華輝。", "聲詩載歌，于以侑之。"]'),
('83bebb5c-4cb7-4f55-ace1-a513bb752cdf','淳熙十六年皇后冊寶十三首  其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','有璽範金，有冊鏤瓊。',40,'全唐诗/poet.song.251000.json','["有璽範金，有冊鏤瓊。", "汝使汝介，持節以行。", "禮始文德，達于穆清。", "是恪是虔，依我和聲。"]'),
('196ba0df-45d0-4211-9cd8-2e6f57f3bc65','淳熙十六年皇后冊寶十三首  其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','鼓鐘喤喤，磬筦鏘鏘。',40,'全唐诗/poet.song.251000.json','["鼓鐘喤喤，磬筦鏘鏘。", "劍佩充庭，濟濟洋洋。", "禮典告備，皇心樂康。", "於萬斯年，受福無疆。"]'),
('84642880-2bf0-485c-9018-8c9dbc551a39','淳熙十六年皇后冊寶十三首  其五','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','懿範柔容，如月斯輝。',40,'全唐诗/poet.song.251000.json','["懿範柔容，如月斯輝。", "駕厥翟輅，被以褘衣。", "九御從之，如雲祁祁。", "典冊是承，心焉肅祗。"]'),
('199c3be2-16f3-4896-bbdd-f5c703420d00','淳熙十六年皇后冊寶十三首  其六','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','華榱璧璫，有馨椒殿。',40,'全唐诗/poet.song.251000.json','["華榱璧璫，有馨椒殿。", "備物來陳，多儀式煥。", "曰冊曰寶，是刻是瑑。", "並舉以行，皇矣懿典。"]'),
('5920204e-4486-40c7-8875-e3cbb15c8ebe','淳熙十六年皇后冊寶十三首  其七','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','褘褕盛服，有恪其容。',40,'全唐诗/poet.song.251000.json','["褘褕盛服，有恪其容。", "是陟是降，相以尚宮。", "金殿玉階，聿來于中。", "展詩應律，載詠肅雍。"]'),
('c48b3638-9fbb-4b1d-96f6-2c98ffc1946a','淳熙十六年皇后冊寶十三首  其八','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','帝有顯命，稟于親慈。',40,'全唐诗/poet.song.251000.json','["帝有顯命，稟于親慈。", "后德克承，拜而受之。", "人倫既正，王化是基。", "億載萬年，永祚坤儀。"]'),
('d4080921-70ad-4df0-affb-3764c536a336','淳熙十六年皇后冊寶十三首  其九','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','帝慶三宮，膺受寶冊。',40,'全唐诗/poet.song.251000.json','["帝慶三宮，膺受寶冊。", "御于中闈，載欣載惕。", "迺孚陰教，迺明內則。", "翼翼魚貫，罔不承式。"]'),
('123d4d6a-57cb-4352-8013-e3d3caa69a7c','淳熙十六年皇后冊寶十三首  其一○','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','掖庭頒官，于位有四。',40,'全唐诗/poet.song.251000.json','["掖庭頒官，于位有四。", "嘒彼小星，撫以德惠。", "熙焉如春，育焉如地。", "慶禮聿成，靡弗咸喜。"]'),
('791bfc87-fdf4-47c9-b96d-7db9c4845e1f','淳熙十六年皇后冊寶十三首  其一一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','魚軒鼎來，象服是宜。',40,'全唐诗/poet.song.251000.json','["魚軒鼎來，象服是宜。", "班于內庭，率禮惟祗。", "化以婦道，時惟母儀。", "是慶是類，于胥樂兮。"]'),
('f94b6e2a-2229-4453-8b26-5e910808e71c','淳熙十六年皇后冊寶十三首  其一二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','正位長秋，容典備矣。',40,'全唐诗/poet.song.251000.json','["正位長秋，容典備矣。", "王假有家，人倫至矣。", "儷極俔天，多受祉矣。", "蟄蟄螽斯，宜孫子矣。"]'),
('fe01b0c3-3f9b-424b-bf3a-8bd3531f0ffb','淳熙十六年皇后冊寶十三首  其一三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','維天佑宋，盛事相仍。',40,'全唐诗/poet.song.251000.json','["維天佑宋，盛事相仍。", "崇號三宮，甫茲浹辰。", "肇正中闈，縟禮載陳。", "邦家之慶，曠古無倫。"]'),
('7119abcf-5f46-4083-b846-ace478ed495a','慶元二年皇后冊寶十三首  其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','乾健坤順，群生首資。',40,'全唐诗/poet.song.251000.json','["乾健坤順，群生首資。", "日常月升，四時叶熙。", "帝嗣天歷，后崇母儀。", "黼黻承暉，王化是基。"]'),
('de9db4fe-7651-4ac9-bdae-47e2540d2117','慶元二年皇后冊寶十三首  其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','熛闕蟺蜎，璧門雲龍。',40,'全唐诗/poet.song.251000.json','["熛闕蟺蜎，璧門雲龍。", "烈文維輔，翊奉有容。", "典章煇明，彝度肅雍。", "蕆時縟儀，登于璿宮。"]'),
('cd70e35c-52b7-4eb0-9c5b-9b2ec19cc19a','慶元二年皇后冊寶十三首  其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','金晶麗輝，璧葉含春。',40,'全唐诗/poet.song.251000.json','["金晶麗輝，璧葉含春。", "贊夏之翼，繹虞之嬪。", "樂序韶亮，禮文藻新。", "辟公相成，物采彬彬。"]'),
('508abc41-6173-4bb5-9d0d-cd5eab976e41','慶元二年皇后冊寶十三首  其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','帟旒雲舒，金秀充庭。',40,'全唐诗/poet.song.251000.json','["帟旒雲舒，金秀充庭。", "璇衛鑾華，蒨佩垂𦀚。", "皇容熙備，柔儀順承。", "三宮齊懽，萬福昭膺。"]'),
('9640f267-4dd6-4f60-88f5-cd095be7949a','慶元二年皇后冊寶十三首  其五','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','驂翟崇容，褘鞠陳衣。',40,'全唐诗/poet.song.251000.json','["驂翟崇容，褘鞠陳衣。", "戾止蘭殿，夙興椒闈。", "淑正宣華，粹明騰煇。", "欽若有承，嗣音之徽。"]'),
('fd169c27-937b-472f-ad77-e4da6648b96d','慶元二年皇后冊寶十三首  其六','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','褘帟流光，沙祥增衍。',40,'全唐诗/poet.song.251000.json','["褘帟流光，沙祥增衍。", "編玉鏤德，螭金溢篆。", "粹猷藻黻，徽文華顯。", "二南聲詩，于時昭闡。"]'),
('def8ba69-1ba5-42fe-8919-c4e7ff413b2d','慶元二年皇后冊寶十三首  其七','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','翬珩煥采，趨節風韶。',40,'全唐诗/poet.song.251000.json','["翬珩煥采，趨節風韶。", "陟降墄陛，奉將英瑶。", "辟道承薰，嬪儀揚翹。", "是敬是祗，德音孔昭。"]'),
('616e4633-a0fd-4a86-9c2e-ad53962d18e9','慶元二年皇后冊寶十三首  其八','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','帝奉太室，后儀成之。',40,'全唐诗/poet.song.251000.json','["帝奉太室，后儀成之。", "帝養三宮，后志承之。", "德如關雎，盛如螽斯。", "宜君宜王，百世本支。"]'),
('e78ef546-c479-45e8-a574-8177effa2e2a','慶元二年皇后冊寶十三首  其九','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','肅肅壺彝，雍雍陰教。',40,'全唐诗/poet.song.251000.json','["肅肅壺彝，雍雍陰教。", "險詖自防，警戒是傚。", "中闈端委，列御胥告。", "其思輔順，永翼帝孝。"]'),
('f431b38b-4cff-46dc-809e-0f5939382857','慶元二年皇后冊寶十三首  其一○','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','天子九嬪，王宮六寢。',40,'全唐诗/poet.song.251000.json','["天子九嬪，王宮六寢。", "有燁令儀，載秩華品。", "福履綏將，節用躬儉。", "矢其德音，于以來諗。"]'),
('d45b5ebd-975d-45c3-a42b-540bfdd044c8','慶元二年皇后冊寶十三首  其一一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','象服之文，鵲巢之風。',40,'全唐诗/poet.song.251000.json','["象服之文，鵲巢之風。", "化以婦道，覲于內宮。", "采蘋澗濱，采藻澗中。", "夙夜在公，贊彼累功。"]'),
('47d96a67-bf77-45c8-b0f6-2c9d3b3db098','慶元二年皇后冊寶十三首  其一二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','光佑晏寧，惠慈燕喜。',40,'全唐诗/poet.song.251000.json','["光佑晏寧，惠慈燕喜。", "壽仁並崇，家邦均祉。", "懿文交舉，壺冊嗣美。", "維億萬年，愛敬惟似。"]'),
('5cf9158b-7bc9-43b5-9e0b-da028a663188','慶元二年皇后冊寶十三首  其一三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','天心仁佑，坤德世昭。',40,'全唐诗/poet.song.251000.json','["天心仁佑，坤德世昭。", "灼有慈範，著于累朝。", "儉以贊虞，勤以承堯。", "是用則傚，共勵夙宵。"]'),
('b5ac996b-5b4a-46d4-96fe-8e201329be40','嘉泰三年皇后冊寶十三首  其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','茂建坤極，容典聿新。',40,'全唐诗/poet.song.251000.json','["茂建坤極，容典聿新。", "天命所贊，慈訓是遵。", "肅涓穀旦，躬御紫宸。", "鴻禧累福，駢賚翕臻。"]'),
('075c8e47-c3e6-411e-b9fe-1753755d85d1','嘉泰三年皇后冊寶十三首  其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','端門曉闢，瑞氣雲凝。',40,'全唐诗/poet.song.251000.json','["端門曉闢，瑞氣雲凝。", "有儼良輔，踵武造廷。", "肅肅王命，是將是承。", "登冊穆清，萬歲永膺。"]'),
('92f852b4-08f8-4b66-9d52-bfbc622c6b34','嘉泰三年皇后冊寶十三首  其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','瑶冊玉寶，爛然瑞輝。',40,'全唐诗/poet.song.251000.json','["瑶冊玉寶，爛然瑞輝。", "旁翼絳節，上承紫微。", "璆鳴朝佩，徐出獸扉。", "登進坤極，益彰典徽。"]'),
('cf2a86f5-2857-4839-999d-65106dbcceab','嘉泰三年皇后冊寶十三首  其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','天臨黼扆，雲集弁纓。',40,'全唐诗/poet.song.251000.json','["天臨黼扆，雲集弁纓。", "金石遞奏，典禮備成。", "玉趾緩步，龍駕翼行。", "言旋北極，永燕西清。"]'),
('9eece73e-030b-40cf-8bf6-db2f4b877ec1','嘉泰三年皇后冊寶十三首  其五','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','日薰椒屋，雲靄璧門。',40,'全唐诗/poet.song.251000.json','["日薰椒屋，雲靄璧門。", "有華瑞節，來自帝閽。", "統天惟乾，合德者坤。", "我龍受之，福祿永繁。"]'),
('532c3c1e-207a-4bcb-b2dc-e63523f9356e','嘉泰三年皇后冊寶十三首  其六','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','虹輝燦爛，雲篆綢繆。',40,'全唐诗/poet.song.251000.json','["虹輝燦爛，雲篆綢繆。", "絳節前導，瑞光上浮。", "瑶階玉扉，既集長秋。", "欽承天寵，永荷帝休。"]'),
('a63f8190-a589-4af8-9b7c-850ed2cf2ffa','嘉泰三年皇后冊寶十三首  其七','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','瑶殿清閟，玉墄坦夷。',40,'全唐诗/poet.song.251000.json','["瑶殿清閟，玉墄坦夷。", "褘衣副珈，陟降不遲。", "寶冊聿至，載肅載祗。", "禮儀昭備，福履永綏。"]'),
('f1d57775-aa91-40de-974b-c879dce4245c','嘉泰三年皇后冊寶十三首  其八','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','日月臨燭，乾坤覆持。',40,'全唐诗/poet.song.251000.json','["日月臨燭，乾坤覆持。", "明並二曜，德合兩儀。", "光媲宸極，共恢化基。", "膺受茂典，億載永宜。"]'),
('f412b318-bf25-4b9e-a2e5-3452a03df9e6','嘉泰三年皇后冊寶十三首  其九','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','寶璽瑶冊，既祗既承。',40,'全唐诗/poet.song.251000.json','["寶璽瑶冊，既祗既承。", "繡裀藻席，載躋載升。", "柔儀肅穆，瑞命端凝。", "永膺多福，如川方增。"]'),
('17767653-fd98-415a-8bf9-6f846446c134','嘉泰三年皇后冊寶十三首  其一○','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','服煥盛儀，班分華緻。',40,'全唐诗/poet.song.251000.json','["服煥盛儀，班分華緻。", "九嬪婦職，六寢內治。", "參差荇菜，求勤寤寐。", "烝然來思，相禮贊祭。"]'),
('24da07d7-26aa-4ce3-9d40-92c31c6b3c5a','嘉泰三年皇后冊寶十三首  其一一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','婦榮於室，通籍禁中。',40,'全唐诗/poet.song.251000.json','["婦榮於室，通籍禁中。", "班列有次，車服有容。", "佐我關雎，鵲巢之風。", "被之僮僮，曷不肅雍。"]'),
('1bbb42bc-5ee0-496c-a6ee-1289aac41773','嘉泰三年皇后冊寶十三首  其一二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','金石具舉，典禮茂明。',40,'全唐诗/poet.song.251000.json','["金石具舉，典禮茂明。", "淑慎其止，遹觀厥成。", "瓊琚微動，鳳輦翼行。", "儀光媲極，德邁嬪京。"]'),
('723ca4b6-116d-4323-a35a-30b1e46897f0','嘉泰三年皇后冊寶十三首  其一三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','寶坐既興，鳳輿戒行。',40,'全唐诗/poet.song.251000.json','["寶坐既興，鳳輿戒行。", "奏解嚴辦，歸燕邃清。", "問安壽慈，奉齎宗祊。", "彌千萬年，內助聖明。"]'),
('a4d83f79-b7f1-45a6-a354-886dffd56cd7','嘉定十五年皇帝受恭膺天命之寶三首  其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','我祖受命，恭膺于天。',40,'全唐诗/poet.song.251000.json','["我祖受命，恭膺于天。", "爰作玉寶，載祗載虔。", "申錫無疆，神聖有傳。", "昭茲興運，於萬斯年。"]'),
('f3a76927-f2da-4a62-806f-55df5d92a004','嘉定十五年皇帝受恭膺天命之寶三首  其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於穆我皇，之德之純。',40,'全唐诗/poet.song.251000.json','["於穆我皇，之德之純。", "涵濡群生，矧我遺民。", "連齊跨晉，輸貢效珍。", "土宇日闢，一視同仁。"]'),
('39aff256-417c-4b75-b0e7-b3538588379c','嘉定十五年皇帝受恭膺天命之寶三首  其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','我祖我宗，德厚澤深。',40,'全唐诗/poet.song.251000.json','["我祖我宗，德厚澤深。", "於皇繼序，益單厥心。", "天人協扶，一統有臨。", "乾坤清夷，振古斯今。"]'),
('75e36f81-2ab7-4064-920c-4765ba1ab4e0','至道元年冊皇太子二首  其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','主鬯之重，允屬賢明。',40,'全唐诗/poet.song.251000.json','["主鬯之重，允屬賢明。", "承華肇啟，上嗣騰英。", "禮修樂舉，育德開榮。", "一人元良，萬邦以寧。"]'),
('e0b55663-eeba-4bca-aa64-d96ba206a510','至道元年冊皇太子二首  其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','皇儲既建，聖祚無疆。',40,'全唐诗/poet.song.251000.json','["皇儲既建，聖祚無疆。", "鸞旌列敘，雞戟分行。", "前星有爛，瑞日重光。", "際天接聖，溫文允臧。"]'),
('e9e20287-1247-4c8b-933a-b980f9de4a7d','天禧三年冊皇太子一首','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','明離之象，少陽之位。',40,'全唐诗/poet.song.251000.json','["明離之象，少陽之位。", "固邦爲本，體天作貳。", "儀範克溫，禮章斯備。", "丕宣令猷，恭守宗器。"]'),
('c6ecc881-b298-45ad-96c1-42d921a5a6b2','乾道元年冊皇太子四首  其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','宋受天命，聖緒無疆。',40,'全唐诗/poet.song.251000.json','["宋受天命，聖緒無疆。", "惟懷永圖，乃登元良。", "涓選休辰，冊書是將。", "黼坐天臨，穆穆皇皇。"]'),
('d2bff98a-2cde-4ece-ab2d-d54346f20afc','乾道元年冊皇太子四首  其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於維皇儲，玉潤金聲。',40,'全唐诗/poet.song.251000.json','["於維皇儲，玉潤金聲。", "體震之洊，重離之明。", "冊寶具舉，環佩鏘鳴。", "守器承祧，惟邦之榮。"]'),
('35cbec88-9405-4ccf-89e2-3206f6c450a7','乾道元年冊皇太子四首  其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','樂備既奏，和聲沖融。',40,'全唐诗/poet.song.251000.json','["樂備既奏，和聲沖融。", "玉簡金書，翔鸞戲鴻。", "下拜登受，旋于青宮。", "儀辰作貳，垂休無窮。"]'),
('b28b6248-1f54-48d2-b509-fe07932d161e','乾道元年冊皇太子四首  其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','我禮備成，我駕言旋。',40,'全唐诗/poet.song.251000.json','["我禮備成，我駕言旋。", "降坐而蹕，奏鼓淵淵。", "國本既定，保佑自天。", "克昌厥後，何千萬年。"]'),
('f9be806f-d51b-43f6-ba74-2bbc4aef1c8b','乾道七年冊皇太子四首  其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','建儲以賢，闢宮于東。',40,'全唐诗/poet.song.251000.json','["建儲以賢，闢宮于東。", "典冊既備，筮占既從。", "濟濟卿士，鏘鏘鼓鐘。", "天子戾止，盛哉禮容。"]'),
('3ba1cb52-bcb8-46c1-8fce-0a95884c9853','乾道七年冊皇太子四首  其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','琱珉瑳瑳，篆金煌煌。',40,'全唐诗/poet.song.251000.json','["琱珉瑳瑳，篆金煌煌。", "對揚于庭，是承是將。", "星重其暉，日重其光。", "觀瞻以懌，國有元良。"]'),
('ef517e91-5f30-43b4-b703-62c1c9b13d56','乾道七年冊皇太子四首  其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','淵中象德，玉裕凝姿。',40,'全唐诗/poet.song.251000.json','["淵中象德，玉裕凝姿。", "進退周旋，有肅其儀。", "既定國本，益隆慶基。", "燕及兩宮，福祿如茨。"]'),
('da7082f6-2e4b-4d02-87e8-a830786922a4','乾道七年冊皇太子四首  其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','儲副豫定，器之公兮。',40,'全唐诗/poet.song.251000.json','["儲副豫定，器之公兮。", "冊授孔時，禮之隆兮。", "天步遲遲，旋九重兮。", "壽祉萬年，德無窮兮。"]'),
('4365fd90-e7d8-4f2b-b8a8-25b190687777','嘉定二年冊皇太子四首  其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於皇我宋，受命于天。',40,'全唐诗/poet.song.251000.json','["於皇我宋，受命于天。", "升儲主鬯，衍慶卜年。", "典冊告備，庭工載虔。", "萬乘蒞止，端冕邃延。"]'),
('26333fff-ebe8-4aa3-b2e8-9e0ae9c863f9','嘉定二年冊皇太子四首  其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','太極端御，少陽肅祗。',40,'全唐诗/poet.song.251000.json','["太極端御，少陽肅祗。", "珉簡斯鏤，衮服孔宜。", "式奏備樂，迺陳盛儀。", "下拜登受，永言保之。"]'),
('76c24666-c35d-4d3a-bfbd-f1f4d633baee','嘉定二年冊皇太子四首  其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','明兩承曜，作貳宣猷。',40,'全唐诗/poet.song.251000.json','["明兩承曜，作貳宣猷。", "茂德金昭，令譽川流。", "豫定厥本，永貽迺謀。", "三朝致養，問寢龍樓。"]'),
('963fde3c-5eed-4fea-81ea-b87df92ece38','嘉定二年冊皇太子四首  其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','震洊體象，我儲明兮。',40,'全唐诗/poet.song.251000.json','["震洊體象，我儲明兮。", "渙揚顯冊，我禮成兮。", "大駕言旋，警蹕鳴兮。", "燕祉無疆，邦之榮兮。"]'),
('b759e635-95cd-4e5b-b0f9-2211b863785f','寶祐二年皇子冠二十首  其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於皇帝德，乃聖乃神。',40,'全唐诗/poet.song.251000.json','["於皇帝德，乃聖乃神。", "本支百世，立愛惟親。", "敬共冠事，以明人倫。", "承天右序，休命用申。"]'),
('5cac32fa-8177-4cd7-92d2-521b2ab850cc','寶祐二年皇子冠二十首  其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','豐芑詒謀，建爾元子。',40,'全唐诗/poet.song.251000.json','["豐芑詒謀，建爾元子。", "揆禮儀年，筮賓敬事。", "八音克諧，嘉賓至止。", "于以冠之，成其福履。"]'),
('a81f9436-5bc3-431f-b726-d5aabca3ba0c','寶祐二年皇子冠二十首  其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','禮國之本，冠禮之始。',40,'全唐诗/poet.song.251000.json','["禮國之本，冠禮之始。", "賓升自西，維賓之位。", "于著於阼，維子之義。", "厥惟欽哉，敬以從事。"]'),
('35ea2fe3-65ab-4ea9-b480-3d153bbcca4e','寶祐二年皇子冠二十首  其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','路寢闢門，黼坐恭己。',40,'全唐诗/poet.song.251000.json','["路寢闢門，黼坐恭己。", "群公在庭，所重維禮。", "正心齊家，以燕翼子。", "於萬斯年，王心載喜。"]'),
('5843a362-d3b8-42a1-aec9-d26d761a0ce0','寶祐二年皇子冠二十首  其五','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','有來振振，月重輪兮。',40,'全唐诗/poet.song.251000.json','["有來振振，月重輪兮。", "瑜玉在佩，綦組明兮。", "左徵右羽，德結旌兮。", "步中采薺，矩彠循兮。"]'),
('f513481a-907e-4d4b-95d0-357bea0c2a7a','寶祐二年皇子冠二十首  其六','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','我有嘉賓，直大以方。',40,'全唐诗/poet.song.251000.json','["我有嘉賓，直大以方。", "亦既至止，厥德用光。", "冠而字之，厥義孔彰。", "表裏純備，黄耇無疆。"]'),
('dbe62900-ef97-4065-971f-553b6e0882d3','寶祐二年皇子冠二十首  其七','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','吉圭休成，其日南至。',40,'全唐诗/poet.song.251000.json','["吉圭休成，其日南至。", "天子有詔，冠爾皇嗣。", "爲國之本，隆邦之禮。", "拜而受之，式共敬止。"]'),
('f450f44e-fc3c-4974-8493-8197cde34d0a','寶祐二年皇子冠二十首  其八','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','茲惟阼階，厥義有在。',40,'全唐诗/poet.song.251000.json','["茲惟阼階，厥義有在。", "歷階而升，敬謹將冠。", "經訓昭昭，邦儀粲粲。", "正纚賓筵，壽考未艾。"]'),
('ac3e3c19-36e8-4329-b0c2-753fa26f52d1','寶祐二年皇子冠二十首  其九','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','秩秩賓筵，籩豆孔嘉。',40,'全唐诗/poet.song.251000.json','["秩秩賓筵，籩豆孔嘉。", "帝子至止，衿纓振華。", "周旋陟降，禮行三加。", "成人有德，匪驕匪奢。"]'),
('38cf9736-4037-4085-8c96-3923061f8d3b','寶祐二年皇子冠二十首  其一○','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','帝子惟賢，懋昭厥德。',40,'全唐诗/poet.song.251000.json','["帝子惟賢，懋昭厥德。", "跪冠于房，玄冠有特。", "鼓鐘喤喤，威儀抑抑。", "百禮既洽，祚我王國。"]'),
('58798643-3177-44c8-83d2-6880a3423bc6','寶祐二年皇子冠二十首  其一一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','有賓在筵，有尊在戶。',40,'全唐诗/poet.song.251000.json','["有賓在筵，有尊在戶。", "磬管將將，醮禮時舉。", "跪觴祝辭，以永燕譽。", "寶祚萬年，磐石鞏固。"]'),
('384a6364-5e24-41e1-9f4a-ee32b3e5c477','寶祐二年皇子冠二十首  其一二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','復爻肇祥，震維標德。',40,'全唐诗/poet.song.251000.json','["復爻肇祥，震維標德。", "乃共皮弁，其儀不忒。", "體正色齊，維民之則。", "璇霄眷佑，國壽箕翼。"]'),
('d42a18a2-12f1-4110-904b-55bb1f268446','寶祐二年皇子冠二十首  其一三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','冠醮之義，匪酬匪酌。',40,'全唐诗/poet.song.251000.json','["冠醮之義，匪酬匪酌。", "于戶之西，敬共以恪。", "金石相宣，冠醮相錯。", "帝祉之受，施及家國。"]'),
('cbd77db3-dcb9-416d-af24-55ee8a05e499','寶祐二年皇子冠二十首  其一四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','善頌善禱，三加彌尊。',40,'全唐诗/poet.song.251000.json','["善頌善禱，三加彌尊。", "爵弁峨峨，介珪溫溫。", "陽德方長，成德允存。", "燕及君親，厥祉孔蕃。"]'),
('7a748ec4-cae9-40f5-92d1-fbb940279bcb','寶祐二年皇子冠二十首  其一五','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','席于賓階，禮義以興。',40,'全唐诗/poet.song.251000.json','["席于賓階，禮義以興。", "受爵執爵，多福以膺。", "匪惟服加，德加愈升。", "匪惟德加，壽加愈增。"]'),
('a3a13877-8f41-460a-b5c5-10a0fb47dd15','寶祐二年皇子冠二十首  其一六','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','命服煌煌，跬步中度。',40,'全唐诗/poet.song.251000.json','["命服煌煌，跬步中度。", "慶輯皇闈，化行海宇。", "禮具樂成，惕若戒懼。", "寶璐厥躬，有秩斯祜。"]'),
('1a350959-5311-420d-aa5a-0619ea666a6d','寶祐二年皇子冠二十首  其一七','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','皇王烝哉，令聞不已。',40,'全唐诗/poet.song.251000.json','["皇王烝哉，令聞不已。", "燕翼有謀，冠醮有禮。", "百僚在庭，遹相厥事。", "頌聲所同，嘉受帝祉。"]'),
('9a6488eb-7eb3-4937-b47b-6debaae7d0b8','寶祐二年皇子冠二十首  其一八','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','青社分封，前星啟燄。',40,'全唐诗/poet.song.251000.json','["青社分封，前星啟燄。", "繁弱綏章，厥光莫揜。", "容稱其德，蓄學之驗。", "芳譽敷華，大圭無玷。"]'),
('62b2cd36-4932-4f65-87ae-f032f418971f','寶祐二年皇子冠二十首  其一九','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','玄衮黼裳，垂徽永世。',40,'全唐诗/poet.song.251000.json','["玄衮黼裳，垂徽永世。", "勉勉成德，是在元子。", "胙土南賓，厥旨孔懿。", "充一忠字，作百無愧。"]'),
('df5afbb6-d74e-4aa8-a6ba-b283721718e5','寶祐二年皇子冠二十首  其二○','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','愛始於親，聖盡倫兮。',40,'全唐诗/poet.song.251000.json','["愛始於親，聖盡倫兮。", "元子冠字，邦禮成兮。", "天步舒徐，皇心寧兮。", "家人之吉，億萬春兮。"]'),
('917abe4c-0f9b-4361-bf89-f86195c2a03a','淳化鄉飲酒三十三章  其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','鹿鳴呦呦，命侶與儔。',40,'全唐诗/poet.song.251000.json','["鹿鳴呦呦，命侶與儔。", "宴樂嘉賓，既獻且醻。", "獻醻有序，休祉無疆。", "展矣君子，邦家之光。"]'),
('bf1ad2e9-d173-4cbb-aaf7-d5a77825cf5d','淳化鄉飲酒三十三章  其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','鹿鳴呦呦，在彼中林。',40,'全唐诗/poet.song.251000.json','["鹿鳴呦呦，在彼中林。", "宴樂嘉賓，式昭德音。", "德音愔愔，既樂且湛。", "允矣君子，實慰我心。"]'),
('19e11d9b-1bd5-42af-b6cb-d110b1c334fa','淳化鄉飲酒三十三章  其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','鹿鳴呦呦，在彼高岡。',40,'全唐诗/poet.song.251000.json','["鹿鳴呦呦，在彼高岡。", "宴樂嘉賓，吹笙鼓簧。", "幣帛戔戔，禮儀蹡蹡。", "樂只君子，利用賓王。"]'),
('75a8368b-e13c-41b1-a267-17cb1fc31045','淳化鄉飲酒三十三章  其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','鹿鳴相呼，聚澤之蒲。',40,'全唐诗/poet.song.251000.json','["鹿鳴相呼，聚澤之蒲。", "我樂嘉賓，鼓瑟吹竽。", "我命旨酒，以燕以娛。", "何以贈之，玄纁粲如。"]'),
('ae4ec08b-101c-419f-a50c-c7cb3c2a6395','淳化鄉飲酒三十三章  其五','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','鹿鳴相邀，聚場之苗。',40,'全唐诗/poet.song.251000.json','["鹿鳴相邀，聚場之苗。", "我美嘉賓，令名孔昭。", "我命旨酒，以歌以謠。", "何以置之，大君之朝。"]'),
('3d802fc5-c696-4ef1-8e5d-70c05fb5366f','淳化鄉飲酒三十三章  其六','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','鹿鳴相應，聚山之荆。',40,'全唐诗/poet.song.251000.json','["鹿鳴相應，聚山之荆。", "我燕嘉賓，鼓簧吹笙。", "我命旨酒，以逢以迎。", "何以薦之，揚于王庭。"]'),
('88004cd6-27d0-439a-97ab-e9030982f22d','淳化鄉飲酒三十三章  其七','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','瞻彼南陔，時物嘉良。',40,'全唐诗/poet.song.251000.json','["瞻彼南陔，時物嘉良。", "有泉清泚，有蘭馨香。", "晨飲是汲，夕膳是嘗。", "慈顔未悅，我心靡遑。"]'),
('9523605f-fc38-4527-818c-b77f5e35c0ac','淳化鄉飲酒三十三章  其八','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','嬉嬉南陔，眷眷慈顔。',40,'全唐诗/poet.song.251000.json','["嬉嬉南陔，眷眷慈顔。", "和氣怡色，奉甘與鮮。", "事親是宜，事君是思。", "虔勖忠孝，邦家之基。"]'),
('22651eef-9f04-40ef-99a8-a0fc2368cbc9','淳化鄉飲酒三十三章  其九','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','洋洋嘉魚，佇以美罛。',22,'全唐诗/poet.song.251000.json','["洋洋嘉魚，佇以美罛。", "君子有道，嘉賓式燕以娛。"]'),
('dfd540ae-3cb0-4bab-bf9c-12da823e5e01','淳化鄉飲酒三十三章  其一○','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','洋洋嘉魚，佇以芳罟。',22,'全唐诗/poet.song.251000.json','["洋洋嘉魚，佇以芳罟。", "君子有德，嘉賓式歌且舞。"]'),
('3217f302-ea8f-408f-a325-500a9cc177f7','淳化鄉飲酒三十三章  其一一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','我有宮沼，龜龍擾之。',22,'全唐诗/poet.song.251000.json','["我有宮沼，龜龍擾之。", "君子有禮，嘉賓式貴表之。"]'),
('44704459-05c3-4658-b9c3-a1a5b40cd0ee','淳化鄉飲酒三十三章  其一二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','我有宮藪，麟鳳來思。',22,'全唐诗/poet.song.251000.json','["我有宮藪，麟鳳來思。", "君子有樂，嘉賓式慰勤思。"]'),
('858e6e02-1940-471a-97d2-5f3f25582e4a','淳化鄉飲酒三十三章  其一三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','相彼嘉魚，爰縱之壑。',22,'全唐诗/poet.song.251000.json','["相彼嘉魚，爰縱之壑。", "我有旨酒，嘉賓式燕以樂。"]'),
('0f47ae1e-0ad6-4012-85de-6bb7cb3932a5','淳化鄉飲酒三十三章  其一四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','相彼嘉魚，在漢之梁。',22,'全唐诗/poet.song.251000.json','["相彼嘉魚，在漢之梁。", "我有旨酒，嘉賓式燕以康。"]'),
('116887f3-d40b-4f68-8313-c87e8db0ead1','淳化鄉飲酒三十三章  其一五','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','森森喬木，美蔓縈之。',22,'全唐诗/poet.song.251000.json','["森森喬木，美蔓縈之。", "我有旨酒，嘉賓式燕宜之。"]'),
('2d36dd29-6446-414d-9109-e9a1360de741','淳化鄉飲酒三十三章  其一六','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','喈喈黄鳥，載飛載止。',22,'全唐诗/poet.song.251000.json','["喈喈黄鳥，載飛載止。", "我有旨酒，嘉賓式燕且喜。"]'),
('914bfe40-4a78-47a6-b995-d0bb60e55c78','淳化鄉飲酒三十三章  其一七','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','崇丘峨峨，動植斯屬。',40,'全唐诗/poet.song.251000.json','["崇丘峨峨，動植斯屬。", "高既自遂，大亦自足。", "和風斯扇，膏雨斯沐。", "我仁如天，以亭以育。"]'),
('da82a3b6-e545-4d6d-9f3a-b8a5c9d400f0','淳化鄉飲酒三十三章  其一八','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','崇丘巍巍，動植其依。',40,'全唐诗/poet.song.251000.json','["崇丘巍巍，動植其依。", "高大之性，各極爾宜。", "王道坦坦，皇猷熙熙。", "仁壽之域，烝民允躋。"]'),
('80523a3b-82d2-40b5-84b0-d6387bf3ccbe','淳化鄉飲酒三十三章  其一九','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','關雎于飛，洲渚之湄。',20,'全唐诗/poet.song.251000.json','["關雎于飛，洲渚之湄。", "自家刑國，樂且有儀。"]'),
('37921d81-e1ec-4bcc-902b-a9024f762661','淳化鄉飲酒三十三章  其二○','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','郁郁芳蘭，幽人擷之。',20,'全唐诗/poet.song.251000.json','["郁郁芳蘭，幽人擷之。", "溫溫恭人，哲后求之。"]'),
('b3a2c2d8-9243-49e3-b0b7-5cca0cf864a6','淳化鄉飲酒三十三章  其二一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','求之無斁，寤寐所屬。',20,'全唐诗/poet.song.251000.json','["求之無斁，寤寐所屬。", "罄爾一心，受天百祿。"]'),
('bc93843b-12dc-4ced-8a60-b3c9033c224f','淳化鄉飲酒三十三章  其二二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','郁郁芳蘭，雨露滋之。',20,'全唐诗/poet.song.251000.json','["郁郁芳蘭，雨露滋之。", "溫溫恭人，圭組縻之。"]'),
('f839cb47-9fca-43c7-8085-920cb243bc36','淳化鄉飲酒三十三章  其二三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','郁郁芳蘭，佩服珍之。',20,'全唐诗/poet.song.251000.json','["郁郁芳蘭，佩服珍之。", "溫溫恭人，福履綏之。"]'),
('5b6a9221-2466-4ec6-9cbf-7128aab32e04','淳化鄉飲酒三十三章  其二四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','關雎蹌蹌，集水之央。',20,'全唐诗/poet.song.251000.json','["關雎蹌蹌，集水之央。", "好求賢輔，同揚德光。"]'),
('cb2b591e-60e4-4789-bd70-6365bb2224e4','淳化鄉飲酒三十三章  其二五','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','蘋蘩芳滋，同誰掇之。',20,'全唐诗/poet.song.251000.json','["蘋蘩芳滋，同誰掇之。", "願言賢德，靡日不思。"]'),
('d6610d3d-255d-4b86-b36d-9270e33adf1b','淳化鄉飲酒三十三章  其二六','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','偶其賢德，輔成己職。',20,'全唐诗/poet.song.251000.json','["偶其賢德，輔成己職。", "永配玉音，服之無斁。"]'),
('101a4965-8b3a-4448-9cf3-b0e091d6cbb2','淳化鄉飲酒三十三章  其二七','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','潔其粢盛，中心匪寧。',20,'全唐诗/poet.song.251000.json','["潔其粢盛，中心匪寧。", "薦於宗廟，助君德馨。"]'),
('aa5f4366-e4bf-4cd0-a130-d73aad2fa5e1','淳化鄉飲酒三十三章  其二八','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','賢淑來思，人之表儀。',20,'全唐诗/poet.song.251000.json','["賢淑來思，人之表儀。", "風化天下，何樂如之。"]'),
('beb8b5b1-4701-4ee6-8f33-b40c5de2843e','淳化鄉飲酒三十三章  其二九','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','彼鵲成巢，爾類攸處。',20,'全唐诗/poet.song.251000.json','["彼鵲成巢，爾類攸處。", "之子有歸，瓊瑶是祖。"]'),
('72355280-7d09-4187-a5bc-98548d030826','淳化鄉飲酒三十三章  其三○','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','彼鵲成巢，爾類攸匹。',20,'全唐诗/poet.song.251000.json','["彼鵲成巢，爾類攸匹。", "之子有行，錦繡是飾。"]'),
('b36876d3-209a-47b1-b5a1-8909018dd678','淳化鄉飲酒三十三章  其三一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','彼鵲成巢，爾類攸共。',20,'全唐诗/poet.song.251000.json','["彼鵲成巢，爾類攸共。", "之子有從，蘭蓀是奉。"]'),
('958cdd11-0bf1-48c2-9053-c9f4249f001b','淳化鄉飲酒三十三章  其三二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','伊鵲成巢，珍禽戾止。',20,'全唐诗/poet.song.251000.json','["伊鵲成巢，珍禽戾止。", "婉彼佳人，配于君子。"]'),
('7fd97b29-1b52-49e4-8501-fa8d82ba09b4','淳化鄉飲酒三十三章  其三三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','伊鵲營巢，珍禽攸處。',20,'全唐诗/poet.song.251000.json','["伊鵲營巢，珍禽攸處。", "內助賢侯，弼于明主。"]'),
('b96e258a-3c46-4059-b674-fdbec8a2fe47','淳化鄉飲酒三十三章  其三四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','伊鵲營巢，珍禽輯睦。',20,'全唐诗/poet.song.251000.json','["伊鵲營巢，珍禽輯睦。", "均養嘉雛，致于蕃育。"]'),
('9e806040-ec95-445d-8f58-3a8b0e855464','大觀聞喜宴六首  其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','多士濟濟，于彼西雍。',40,'全唐诗/poet.song.251000.json','["多士濟濟，于彼西雍。", "欽肅威儀，亦有斯容。", "烝然來思，自西自東。", "天畀爾祿，惟王其崇。"]'),
('5136cb5a-709b-4518-809a-6cfc66c8c5f7','大觀聞喜宴六首  其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','明明天子，率由舊章。',40,'全唐诗/poet.song.251000.json','["明明天子，率由舊章。", "思樂泮水，光于四方。", "薄采其芹，用賓于王。", "我有好爵，寘彼周行。"]'),
('0725d137-c90b-4579-82bd-52746e36ab55','大觀聞喜宴六首  其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','樂只君子，式燕又思。',40,'全唐诗/poet.song.251000.json','["樂只君子，式燕又思。", "服其命服，攝以威儀。", "鐘鼓既設，一朝醻之。", "德音是茂，邦家之基。"]'),
('627e76c6-420c-4db4-8eef-76a88ba7ee41','大觀聞喜宴六首  其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','聖謨洋洋，綱紀四方。',40,'全唐诗/poet.song.251000.json','["聖謨洋洋，綱紀四方。", "烝我髦士，觀國之光。", "遐不作人，而邦其昌。", "以燕天子，萬壽無疆。"]'),
('7eedb12f-95c2-4d40-add6-99e77daa12c9','大觀聞喜宴六首  其五','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','我求懿德，烝然來思。',40,'全唐诗/poet.song.251000.json','["我求懿德，烝然來思。", "籩豆靜嘉，式燕綏之。", "溫溫其恭，莫不令儀。", "追琢其章，髦士攸宜。"]'),
('53828554-4d07-4c17-a576-2898577b9cd2','大觀聞喜宴六首  其六','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','思皇多士，揚于王庭。',40,'全唐诗/poet.song.251000.json','["思皇多士，揚于王庭。", "鐘鼓樂之，肅雝和鳴。", "威儀抑抑，既安且寧。", "天子萬壽，永觀厥成。"]'),
('f7ab6057-a769-4cdb-a140-43f4bb0106e7','政和鹿鳴宴五首  其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','思樂泮水，承流辟雍。',40,'全唐诗/poet.song.251000.json','["思樂泮水，承流辟雍。", "思皇多士，賁然來從。", "雝雝濟濟，四方攸同。", "登于天府，維王是崇。"]'),
('a872ec04-8957-4fd9-b0e1-b2767c5f2132','政和鹿鳴宴五首  其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','鐘鼓皇皇，磬筦鏘鏘。',40,'全唐诗/poet.song.251000.json','["鐘鼓皇皇，磬筦鏘鏘。", "登降維時，利用賓王。", "髦士攸宜，邦家之光。", "媚于天子，事舉言揚。"]'),
('433f0928-6be4-4353-9841-361a4239d83d','政和鹿鳴宴五首  其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','鳴鹿呦呦，載弁俅俅。',40,'全唐诗/poet.song.251000.json','["鳴鹿呦呦，載弁俅俅。", "烝然來思，旨酒思柔。", "之子言邁，泮渙爾游。", "于彼西雍，對揚王休。"]'),
('89dbf112-9d25-4c3e-bcd6-057f49ea62b4','政和鹿鳴宴五首  其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','首善京師，灼于四方。',40,'全唐诗/poet.song.251000.json','["首善京師，灼于四方。", "烝我髦士，金玉其相。", "飲酒樂曲，吹笙鼓簧。", "勉戒徒御，觀國之光。"]'),
('cbef0d8c-d8ce-42f0-b587-df6f53e0959b','政和鹿鳴宴五首  其五','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','遐不作人，天下喜樂。',40,'全唐诗/poet.song.251000.json','["遐不作人，天下喜樂。", "何以況之，鳶飛魚躍。", "既勸之駕，獻酬交錯。", "利用賓王，縻以好爵。"]'),
('2fbe5424-0e2e-4585-8cf5-6faf1c8e378c','方丘樂歌  其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','至哉坤儀，萬彙資生。',40,'全唐诗/poet.song.251000.json','["至哉坤儀，萬彙資生。", "稱物平施，流謙變盈。", "禮修泰折，祭極精誠。", "皇皇靈睠，永奠寰瀛。"]'),
('ca7014b6-fed9-45ab-9ad4-98915f25ebbf','方丘樂歌  其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','禮有五經，無先祭禮。',40,'全唐诗/poet.song.251000.json','["禮有五經，無先祭禮。", "即時伸虔，惟時盥洗。", "品物吉蠲，威儀濟濟。", "錫之純嘏，來歆愷悌。"]'),
('f252ac01-fe26-40e8-bd2e-3153477bea3b','方丘樂歌  其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','無疆之德，至哉坤元。',40,'全唐诗/poet.song.251000.json','["無疆之德，至哉坤元。", "沉潜剛克，資生實蕃。", "方丘之儀，惟敬無文。", "神其來思，時歆薦殷。"]'),
('7b85ebd7-64b8-4bc9-9f1d-1d6c098e06bf','方丘樂歌  其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','禮行方澤，文物備舉。',40,'全唐诗/poet.song.251000.json','["禮行方澤，文物備舉。", "惟皇地祇，昭格來下。", "奠瘞玉帛，純誠內著。", "神保是享，陟降斯祐。"]'),
('3bf9e902-f9a5-47e1-a911-760b254b20fe','方丘樂歌  其五','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','四階秩儀，壇於方澤。',40,'全唐诗/poet.song.251000.json','["四階秩儀，壇於方澤。", "昭事皇祇，即陰以墌。", "潔肆於祊，孔嘉且碩。", "神其福之，如幾如式。"]'),
('8074f2a6-9af9-40e2-81fc-32ddead7fee8','方丘樂歌  其六','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','蕩蕩坤德，物無不載。',40,'全唐诗/poet.song.251000.json','["蕩蕩坤德，物無不載。", "柔順利貞，含弘光大。", "籩豆既陳，金石斯在。", "四海永寧，福祿攸介。"]'),
('0a7979f0-16e3-4202-86b7-43dc3cba3e10','方丘樂歌  其七','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','卓彼嘉壇，奠玉方澤。',30,'全唐诗/poet.song.251000.json','["卓彼嘉壇，奠玉方澤。", "百辟祗肅，八音純繹。", "祀事承明，柔祗感格。"]'),
('e1bc3162-b9b3-4e5f-a2a7-4b86620373ca','方丘樂歌  其八','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','修理方丘，吉蠲是宜。',40,'全唐诗/poet.song.251000.json','["修理方丘，吉蠲是宜。", "籩豆靜嘉，登於有司。", "芬芬馨香，來享來儀。", "郊儀將終，聲歌徹之。"]'),
('4a0e8c1b-f4e7-4460-8a33-b1703b722bbf','方丘樂歌  其九','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','因地方丘，濟濟多儀。',40,'全唐诗/poet.song.251000.json','["因地方丘，濟濟多儀。", "樂成八變，靈祇格思。", "薦餘徹豆，神貺昭垂。", "億萬斯年，永祐丕基。"]'),
('c6caa7fb-b64a-4348-864a-88855acf65af','五方帝  其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','帝宅震方，在德惟木。',40,'全唐诗/poet.song.251000.json','["帝宅震方，在德惟木。", "宣仁賦和，大生□育。", "祀法有虔，皇情允肅。", "神之格思，報以介福。"]'),
('9727a809-8e63-4f09-9541-c7eca39b9eb7','五方帝  其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','太微靈德，若首五精。',40,'全唐诗/poet.song.251000.json','["太微靈德，若首五精。", "本仁與益，降氣施生。", "純牲有碩，旨酒斯清。", "錫茲壽嘏，既壽洽平。"]'),
('9f408fbe-44cf-46bb-a3e5-043564343d97','五方帝  其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','惟帝乘離，恢台其德。',40,'全唐诗/poet.song.251000.json','["惟帝乘離，恢台其德。", "平秩南訛，百嘉允殖。", "感精啟運，祖我炎曆。", "璋幣迎郊，□□翼翼。"]'),
('fb8ac586-8135-4997-a15c-cd54a94dcae9','五方帝  其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','惟帝乘離，司厥生殖。',40,'全唐诗/poet.song.251000.json','["惟帝乘離，司厥生殖。", "感所自興，據我炎德。", "既度斯筵，乃馨斯稷。", "對越居歆，介祉無極。"]'),
('f254dbe5-fa38-43a9-af7d-4eefe77236da','五方帝  其五','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','聖考能饗，宗祀熙成。',40,'全唐诗/poet.song.251000.json','["聖考能饗，宗祀熙成。", "駿烈惟帝，於皇執衡。", "茂育元運，降祚丕平。", "載清斯酌，庸罄精誠。"]'),
('437628b4-2280-49a8-9083-e94a229652a7','五方帝  其六','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','四序均氣，五色奠方。',40,'全唐诗/poet.song.251000.json','["四序均氣，五色奠方。", "元標樞紐，位正中央。", "至誠馨潔，率土年康。", "神兮降止，鼎祚綿長。"]'),
('6caabae2-26f2-4ee1-a7e2-176d1fd2bc97','五方帝  其七','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','盛德居厚，含章有融。',40,'全唐诗/poet.song.251000.json','["盛德居厚，含章有融。", "惟思惟信，曰黄曰中。", "禮誠薦達，福祐嘉通。", "永延永阜，九穀咸豐。"]'),
('8c6c1924-05e2-4e78-923a-66f26dfd02f0','五方帝  其八','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','帝乘中央，沉載函蒙。',40,'全唐诗/poet.song.251000.json','["帝乘中央，沉載函蒙。", "經緯四方，物性滋豐。", "金石之薦，象德以宮。", "神錫嘉虞，介祉無窮。"]'),
('a9ea0885-423e-48d6-8294-09512f87cb12','五方帝  其九','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','玉琯均和，金風候氣。',40,'全唐诗/poet.song.251000.json','["玉琯均和，金風候氣。", "神其格思，豐粢潔幣。", "九穀順成，群物茂遂。", "降福無疆，德澤光被。"]'),
('ff4df47b-1811-449a-9e53-fcc24456fc17','五方帝  其一○','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','白煒方肅，合宮孔碩。',40,'全唐诗/poet.song.251000.json','["白煒方肅，合宮孔碩。", "琥以象象，神惟饗德。", "陞配有序，虔恭無斁。", "降福穰穰，永安邦國。"]'),
('caa2973b-7764-4e96-8327-e7e12218b282','五方帝  其一一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於赫路寢，肆筵有序。',40,'全唐诗/poet.song.251000.json','["於赫路寢，肆筵有序。", "粵若西顥，其神執矩。", "以薦幣玉，式陳簠簋。", "神其格思，受天之祐。"]'),
('04279654-3ba7-4701-bb04-86694423af6e','五方帝  其一二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','水官修職，星昴居方。',40,'全唐诗/poet.song.251000.json','["水官修職，星昴居方。", "執權含寶，萬物伏藏。", "大明昌祚，臨下皇皇。", "曰寒時若，神降之康。"]'),
('c927b06c-35c5-41ae-9d31-8607ff9fd17a','五方帝  其一三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','今月季秋，穀日辛亥。',43,'全唐诗/poet.song.251000.json','["今月季秋，穀日辛亥。", "路寢合宮，親修嚴配。", "北方之神，五室來會。", "馨烈是{目寽}，庬褫攸介。"]'),
('771f7e10-08c0-4527-961d-ec1006270c74','五方帝  其一四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','太宇清明，宣以方色。',40,'全唐诗/poet.song.251000.json','["太宇清明，宣以方色。", "沛哉靈游，昭示幽則。", "崇配尊親，惟茲孝德。", "神熙蕃丕，涵育四極。"]'),
('1ada6b4c-2988-41d2-8792-39578cdb75ab','五方帝  其一五','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','禮經之重，祀典惟明。',40,'全唐诗/poet.song.251000.json','["禮經之重，祀典惟明。", "命官攝事，陟降以誠。", "既升庶品，亦奉二精。", "錫茲福祉，迄用丕平。"]'),
('c53e2884-daaf-4ac0-b541-6a90b2f98155','太廟','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','大享合宮，於禮莫盛。',40,'全唐诗/poet.song.251000.json','["大享合宮，於禮莫盛。", "入太室祼，徧于列聖。", "陟降有儀，一主乎敬。", "祀事孔明，邦家之慶。"]'),
('f736a06a-cdc4-4532-a31e-bfd3db2ba3dc','祫饗太廟  其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','猗我僖祖，德潜而充。',40,'全唐诗/poet.song.251000.json','["猗我僖祖，德潜而充。", "慶之所基，日茂以崇。", "施及後嗣，天命有融。", "廟歌載之，播于無窮。"]'),
('71f7c19d-d3ba-4a90-936f-ee3e3772c6c7','祫饗太廟  其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','皇矣烈祖，次于僖宮。',40,'全唐诗/poet.song.251000.json','["皇矣烈祖，次于僖宮。", "燕貽憑厚，德遠而隆。", "尊昭綴穆，合食惟豐。", "孝孫奠爵，福嘏來同。"]'),
('3b49e7e9-3c42-4de0-8cf7-8c4e9a6c5e42','祫饗太廟  其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','清廟有嚴，觀德惟祖。',40,'全唐诗/poet.song.251000.json','["清廟有嚴，觀德惟祖。", "裕典時修，親尊並序。", "以祼以獻，禮交樂舉。", "靈其醉止，篤我純祐。"]'),
('033033a9-6215-4a4a-bb91-39089f735b35','祫饗太廟  其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','洪緒載德，盛際講儀。',40,'全唐诗/poet.song.251000.json','["洪緒載德，盛際講儀。", "精崇祫事，恭展孝思。", "肸蠁錫羨，齊莊受釐。", "猗歟馨烈，垂貺本支。"]'),
('001cd877-1245-4910-8f33-42a75252b3ff','祫饗太廟  其五','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','景炎啟旦，寶系開基。',40,'全唐诗/poet.song.251000.json','["景炎啟旦，寶系開基。", "登俎如在，縮鬯有儀。", "明靈昭格，孝饗肅祗。", "福茨綿瓞，罄宇均禧。"]'),
('82fcdd41-0f0b-4ce3-b485-7665cea9bbdd','祫饗太廟  其六','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','明明聖宗，大定區宇。',40,'全唐诗/poet.song.251000.json','["明明聖宗，大定區宇。", "永懷奉先，闕禮茲舉。", "惟德是馨，冀格我祖。", "萬嗣其昌，繄神之祐。"]'),
('76f83017-92f2-4a46-9639-83f6963a12c7','祫饗太廟  其七','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','皇皇在宥，品物由庚。',40,'全唐诗/poet.song.251000.json','["皇皇在宥，品物由庚。", "文教純被，武功告成。", "流頌樂府，擁休宗祊。", "帝奉祼瓚，欽哉孝誠。"]'),
('e6c11625-1498-4788-bd32-026932e419be','祫饗太廟  其八','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','赫赫閟宮，肇親合食。',40,'全唐诗/poet.song.251000.json','["赫赫閟宮，肇親合食。", "玉步徊翔，大姿嚴翼。", "洗奠交舉，堂除並飭。", "禮賓無違，神其昭格。"]'),
('84eabd9a-8672-4010-89f4-d37326f19ebb','祫饗太廟  其九','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','瑟彼良玉，薦于明靈。',40,'全唐诗/poet.song.251000.json','["瑟彼良玉，薦于明靈。", "宸襟蠲潔，鬰鬯芬馨。", "牲牢在俎，金石在庭。", "莫重者祼，慈嘏來寧。"]'),
('088d7443-b07a-4b20-bc08-85417a9f7bcf','祫饗太廟  其一○','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','嘉牲在俎，廣樂在庭。',40,'全唐诗/poet.song.251000.json','["嘉牲在俎，廣樂在庭。", "其所將者，曰躬曰誠。", "神兮來歆，以安以寧。", "以錫壽嘏，惟皇是膺。"]'),
('bc12bcfc-8eae-44b4-ad65-83a15df0ac2e','祫饗太廟  其一一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','鋪昭典禮，誕合神靈。',40,'全唐诗/poet.song.251000.json','["鋪昭典禮，誕合神靈。", "饗通純孝，治感至馨。", "鬰香既祼，聖酒來寧。", "膺茲福祿，萬壽益齡。"]'),
('a3abe054-edcd-46a7-88e4-b3140b0371f8','祫饗太廟  其一二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','禮備樂成，祖考來格。',40,'全唐诗/poet.song.251000.json','["禮備樂成，祖考來格。", "有嚴有翼，天子孝德。", "臣工在庭，罔不祗飭。", "玉爵之華，執如弗克。"]'),
('f6a456a4-f627-472e-8de4-81800523be9b','祫饗太廟  其一三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','樂統大安，舞昭盛德。',40,'全唐诗/poet.song.251000.json','["樂統大安，舞昭盛德。", "合奏允諧，孔容有翼。", "秉翟言竣，總干是力。", "簫勺之仁，參和萬國。"]'),
('7f59a36a-274c-4fbe-94b1-6f5cfcd5a5d6','祫饗太廟  其一四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','靈其顧思，降福來萃。',40,'全唐诗/poet.song.251000.json','["靈其顧思，降福來萃。", "天子受之，餕爾在位。", "神既享矣，福既均矣。", "豆斯徹矣，禮之成矣。"]'),
('725299ae-886f-4975-a019-493054d22d9b','祫饗太廟  其一五','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','帝還于次，佩玉其徐。',40,'全唐诗/poet.song.251000.json','["帝還于次，佩玉其徐。", "帝色不渝，罔解如初。", "凡百府司，各祗乃位。", "敢不肅恭，以訖爾事。"]'),
('dd2a2969-74be-4cfc-a02c-e51dbf457bc0','章獻明肅皇太后恭謝太廟  其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','於穆宋廟，肇允基扃。',40,'全唐诗/poet.song.251000.json','["於穆宋廟，肇允基扃。", "文母來獻，國祚咸寧。", "永言昭格，式薦惟馨。", "亦既降止，聿柄神靈。"]'),
('9ea68903-6901-4956-ab7d-90d6fae1d857','章獻明肅皇太后恭謝太廟  其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','九奏允諧，皇靈來暨。',40,'全唐诗/poet.song.251000.json','["九奏允諧，皇靈來暨。", "備物芬馨，昭違精意。", "升降有儀，群臣序位。", "享于克誠，萬福攸至。"]'),
('c60d02cd-6f8e-49fd-8b96-59ea4b51ed9e','章獻明肅皇太后恭謝太廟  其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','懿彼靈龜，在宮之池。',40,'全唐诗/poet.song.251000.json','["懿彼靈龜，在宮之池。", "芳蓮是託，千歲奇姿。", "祼將清廟，播于聲詩。", "神降之吉，永保壽祺。"]'),
('3b6e6834-1814-47ba-ac73-0eea07809049','章獻明肅皇太后恭謝太廟  其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','潔爾犧牲，既角且騂。',40,'全唐诗/poet.song.251000.json','["潔爾犧牲，既角且騂。", "玉俎奉將，式表純精。", "祖宗斯享，毖祀以成。", "福祿來降，邦祚隆平。"]'),
('13a3a280-764f-47b0-b75e-da9a818708d4','章獻明肅皇太后恭謝太廟  其五','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','太宮爾肅，烈祖巍巍。',40,'全唐诗/poet.song.251000.json','["太宮爾肅，烈祖巍巍。", "上炳淳耀，下流德暉。", "詒謀燕翼，奄宅邦畿。", "子孫千億，歷數同歸。"]'),
('df7cc3db-2e42-401a-919b-a6902135f5c5','章獻明肅皇太后恭謝太廟  其六','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','乃祖齊聖，綿瓞其昌。',40,'全唐诗/poet.song.251000.json','["乃祖齊聖，綿瓞其昌。", "源流濬邈，統祚悠長。", "如聞肅僾，有飶馨香。", "監觀垂祐，萬葉儲祥。"]'),
('ad37d9e1-7643-46a5-8c95-b8b3d8d1c1e7','章獻明肅皇太后恭謝太廟  其七','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','奕奕清廟，巍巍帝基。',40,'全唐诗/poet.song.251000.json','["奕奕清廟，巍巍帝基。", "詒謀積德，累洽熏熙。", "粢盛豐潔，禮容肅祗。", "俯歆明薦，永錫蕃禧。"]'),
('756ce18e-3933-4921-b8fc-0e9b530c0045','章獻明肅皇太后恭謝太廟  其八','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','赤符啟祚，長發其祥。',40,'全唐诗/poet.song.251000.json','["赤符啟祚，長發其祥。", "靈源自遠，帝運重光。", "載潔籩豆，恭薦令芳。", "致成翼翼，降福穰穰。"]'),
('ee007c36-c61a-44e7-bb35-0228338f03e5','章獻明肅皇太后恭謝太廟  其九','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','英英藝祖，出震承乾。',40,'全唐诗/poet.song.251000.json','["英英藝祖，出震承乾。", "握圖撫運，卜祚延年。", "衣冠在廟，威靈在天。", "永錫無疆，子孫保焉。"]'),
('a9fe90ca-1ab8-445d-a877-005c6e91c36d','章獻明肅皇太后恭謝太廟  其一○','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','赫赫皇祖，萬邦之君。',40,'全唐诗/poet.song.251000.json','["赫赫皇祖，萬邦之君。", "功崇偃革，德盛興文。", "聖謨宏達，至教氤氳。", "子孫百世，祗薦苾芬。"]'),
('c3d0c2a4-9ebd-4880-887e-9b1bc8117a1c','章獻明肅皇太后恭謝太廟  其一一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','巍巍新廟，穆穆真皇。',40,'全唐诗/poet.song.251000.json','["巍巍新廟，穆穆真皇。", "德符二聖，仁洽萬方。", "墜典咸秩，鴻儀用彰。", "威靈如在，時思不忘。"]'),
('f00c850a-0178-4d40-84a1-081fd6fa7dab','章獻明肅皇太后恭謝太廟  其一二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','苾芬既薦，溥碩咸陳。',40,'全唐诗/poet.song.251000.json','["苾芬既薦，溥碩咸陳。", "禮備樂舉，先後有倫。", "以奉七室，齊潔惟寅。", "皇靈斯享，福祥薦臻。"]'),
('c79b410c-1dc1-430e-b235-e14467aae407','章獻明肅皇太后恭謝太廟  其一三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','籥翟既備，干戚是陳。',20,'全唐诗/poet.song.251000.json','["籥翟既備，干戚是陳。", "德業昭著，用和神人。"]'),
('fa8ec537-3d7e-40a6-a9d5-701bd41c0b53','章獻明肅皇太后恭謝太廟  其一四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','牲牷腯肥，粢盛豐潔。',40,'全唐诗/poet.song.251000.json','["牲牷腯肥，粢盛豐潔。", "三獻用行，萬舞復列。", "禮儀克成，樂奏將闋。", "神保聿歸，玉豆斯徹。"]'),
('76ac8516-470e-4df1-b779-c6f1050f011f','章獻明肅皇太后恭謝太廟  其一五','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','九奏合兮僾然來，百禮成兮欻爾回。',32,'全唐诗/poet.song.251000.json','["九奏合兮僾然來，百禮成兮欻爾回。", "想霜馭兮望天闕，八音闋兮心悠哉。"]'),
('f50535fe-15bd-46f4-ba20-378ea27eb54d','朝會  其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','湛湛露斯，其甘如飴。',40,'全唐诗/poet.song.251000.json','["湛湛露斯，其甘如飴。", "清寧鑒德，和氣應之。", "神雲播液，冰玉凝姿。", "是爲仁瑞，萬壽維祺。"]'),
('a111e629-ef56-4025-bb21-393210f19d9e','朝會  其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','爰有嘉禾，含章自天。',41,'全唐诗/poet.song.251000.json','["爰有嘉禾，含章自天。", "宛城洛畫，粲若奎躔。", "珍符顯著，靈意昭宣。", "永告洪業，時萬萬斯年。"]'),
('ee0e4c88-f32c-4dd9-b473-91fd5e8b939b','朝會  其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','地效珍物，時維茲禾。',40,'全唐诗/poet.song.251000.json','["地效珍物，時維茲禾。", "秀標四穎，祥掩並柯。", "嘉生絕擬，善應爲多。", "光溢圖諜，宣用登歌。"]'),
('e18aedc5-e2eb-4dde-b3b4-748af3f8064e','御樓  其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','五輅鳴鸞，八神警蹕。',40,'全唐诗/poet.song.251000.json','["五輅鳴鸞，八神警蹕。", "天官景從，莫不祗栗。", "祲威盛容，昭哉祖述。", "祚我無疆，叶氣充溢。"]'),
('6fc3630f-e350-4b39-be8c-2aab754a2958','御樓  其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','青壇帝籍，在國之東。',40,'全唐诗/poet.song.251000.json','["青壇帝籍，在國之東。", "薦籩執耜，率禮和容。", "鳴鸞回蹕，瑞氣凝空。", "萬方瞻仰，百順來同。"]'),
('4823d938-5f1b-4413-b661-e8987ef637d2','御樓  其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','重城春滿，雙闕雲浮。',40,'全唐诗/poet.song.251000.json','["重城春滿，雙闕雲浮。", "將披雉扇，載儼珠旒。", "叶風應律，文德懷柔。", "溥天率土，惠澤咸周。"]'),
('b7839cac-ee88-4f85-87bf-43261395e614','御樓  其四','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','恩覃春煦，令布風馳。',40,'全唐诗/poet.song.251000.json','["恩覃春煦，令布風馳。", "聲名昭晰，文物葳蕤。", "重森寶扇，將降端闈。", "永光國典，翕受天祺。"]'),
('96845126-db9a-44a5-8d31-b27d6857f1b7','祫饗回升樓  其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','饗于宗祧，維聖之孝。',40,'全唐诗/poet.song.251000.json','["饗于宗祧，維聖之孝。", "驂騰素虬，還歸自廟。", "端闈百常，聳環七校。", "萬邦傾瞻，天若覆燾。"]'),
('ebf860ac-5eb8-4d86-8cb9-fc6a18918cca','祫饗回升樓  其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','端闈壯麗，羽衛驍騰。',40,'全唐诗/poet.song.251000.json','["端闈壯麗，羽衛驍騰。", "天儀畢曄，如日之昇。", "千官景從，萬宇仰承。", "輝光四充，介福其膺。"]'),
('ea481bb4-1723-4e0e-9188-0cd1273fe246','祫饗回升樓  其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','渙號爰發，皇敷至仁。',40,'全唐诗/poet.song.251000.json','["渙號爰發，皇敷至仁。", "幽隠盡達，洪德日新。", "國容肅穆，天宇晏溫。", "惠浹四遠，富壽無垠。"]'),
('2ead2814-105e-4cf1-b59f-59c941038f29','朝會  其一','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','華滋凝氣，靈粹發祥。',40,'全唐诗/poet.song.251000.json','["華滋凝氣，靈粹發祥。", "紫蓋輪囷，金跗煒煌。", "陽蓼三秀，甘泉九房。", "瑞圖休證，君王壽昌。"]'),
('8c81e7f3-cc4f-4739-a741-0311192947f9','朝會  其二','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','太平之符，昭發衆瑞。',40,'全唐诗/poet.song.251000.json','["太平之符，昭發衆瑞。", "爰有嘉禾，異壠合穗。", "大田如雲，既穫既刈。", "野人愉愉，不亦有歲。"]'),
('bf7bf3c5-f40b-4c2c-bcb6-32293863a389','朝會  其三','郊廟朝會歌辭','宋','宋诗','song-poetry','','[]','毓粹乾坤，儲休陰陽。',40,'全唐诗/poet.song.251000.json','["毓粹乾坤，儲休陰陽。", "氤氳馥郁，紛煒煌煌。", "融爲和氣，發爲祥光。", "瑞牒昭紀，萬壽無疆。"]'),
